import React, { useMemo } from 'react';
import {
    DashboardIcon,
    UsersIcon,
    PackageIcon,
    BoxIcon,
    CalendarIcon,
    BarChart2Icon,
    BookOpenIcon,
    SettingsIcon,
    CheckSquareIcon,
    ClipboardListIcon,
    FileSearchIcon,
    MegaphoneIcon,
    MessageSquareIcon,
    DollarSignIcon,
    ArchiveIcon
} from './icons/Icons.tsx';
import { Page } from '../types.ts';
import { useAuth } from '../hooks/useAuth.ts';
