const DealerSidebar: React.FC<{ activePage: DealerPage, setActivePage: (page: DealerPage, state?: any) => void }> = ({ activePage, setActivePage }) => {
    const { user } = useAuth();
    const { announcementRecipients, conversations, messages } = useData();

    const unreadAnnouncements = useMemo(() => {
        if (!user) return 0;
        return announcementRecipients.filter(r => r.userId === user._id && !r.isRead).length;
