import React, { useState, useRef, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth.ts';
import {
    BellIcon,
    UserIcon,
    LogOutIcon,
    SlidersIcon,
    DownloadIcon
} from './icons/Icons.tsx';
import NotificationsDropdown from './shared/NotificationsDropdown.tsx';
import ManageDevicesModal from './modals/ManageDevicesModal.tsx';
import SyncStatusIndicator from './shared/SyncStatusIndicator.tsx';
import Tooltip from './shared/Tooltip.tsx';
import { Page } from '../types.ts';

const Header: React.FC<{
    showToast: (message: string, type: 'success' | 'error' | 'info') => void;
    setActivePage?: (page: Page, state?: any) => void;
}> = ({ showToast, setActivePage }) => {
    const { user, logout } = useAuth();
    const [isMenuOpen, setMenuOpen] = useState(false);
    const [isNotificationsOpen, setNotificationsOpen] = useState(false);
    const [isDevicesOpen, setDevicesOpen] = useState(false);
    const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

    const menuRef = useRef<HTMLDivElement>(null);
    const notificationsRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setMenuOpen(false);
            }
            if (notificationsRef.current && !notificationsRef.current.contains(event.target as Node)) {
                setNotificationsOpen(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);

        // Listen for the beforeinstallprompt event
        const handleInstallPrompt = (e: Event) => {
            e.preventDefault();
            setDeferredPrompt(e);
        };
        window.addEventListener('beforeinstallprompt', handleInstallPrompt);

        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
            window.removeEventListener('beforeinstallprompt', handleInstallPrompt);
        };
    }, []);

    const handleInstallClick = () => {
        if (deferredPrompt) {
            deferredPrompt.prompt();
            deferredPrompt.userChoice.then((choiceResult: any) => {
                if (choiceResult.outcome === 'accepted') {
                    console.log('User accepted the install prompt');
                }
                setDeferredPrompt(null);
            });
        }
    };

    return (
        <header className="h-16 flex-shrink-0 flex items-center justify-end px-6 bg-white dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 z-10 no-print">
            <div className="flex items-center space-x-4">
                {deferredPrompt && (
                    <Tooltip content="Install App">
                        <button 
                            onClick={handleInstallClick} 
                            className="flex items-center space-x-2 px-3 py-1.5 bg-primary/10 text-primary rounded-md hover:bg-primary/20 text-sm font-medium transition-colors"
                        >
                            <DownloadIcon className="w-4 h-4" />
                            <span className="hidden md:inline">Install App</span>
                        </button>
                    </Tooltip>
                )}

                <SyncStatusIndicator showToast={showToast} />

                <div ref={notificationsRef} className="relative">
                    <Tooltip content="Notifications" position="bottom">
                        <button onClick={() => setNotificationsOpen(prev => !prev)} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-400">
                            <BellIcon />
                        </button>
                    </Tooltip>
                    {isNotificationsOpen && <NotificationsDropdown onClose={() => setNotificationsOpen(false)} setActivePage={setActivePage} />}
                </div>

                <div ref={menuRef} className="relative">
                    <Tooltip content="Profile & Settings" position="bottom">
                         <button onClick={() => setMenuOpen(prev => !prev)} className="flex items-center space-x-2 p-1 rounded-md hover:bg-slate-100 dark:hover:bg-slate-700">
                            <div className="w-10 h-10 rounded-full bg-primary text-white flex items-center justify-center font-bold">
                                {user?.name.charAt(0).toUpperCase()}
                            </div>
                            <div className="text-left hidden md:block">
                                <p className="font-semibold text-sm text-slate-800 dark:text-slate-200">{user?.name}</p>
                                <p className="text-xs text-slate-500 dark:text-slate-400">{user?.role}</p>
                            </div>
                        </button>
                    </Tooltip>
                    {isMenuOpen && (
                        <div className="absolute right-0 mt-2 w-56 bg-white dark:bg-slate-800 rounded-md shadow-lg z-20 border border-slate-200 dark:border-slate-700 animate-fade-in">
                            <ul className="py-1">
                                <li>
                                    <button onClick={() => { setActivePage?.('Profile'); setMenuOpen(false); }} className="w-full text-left flex items-center px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700">
                                        <UserIcon className="mr-3"/> Profile
                                    </button>
                                </li>
                                <li><button onClick={() => setDevicesOpen(true)} className="w-full text-left flex items-center px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700"><SlidersIcon className="mr-3"/> Manage Devices</button></li>
                                <li className="border-t border-slate-200 dark:border-slate-700 my-1"></li>
                                <li><button onClick={logout} className="w-full text-left flex items-center px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700"><LogOutIcon className="mr-3"/> Logout</button></li>
                            </ul>
                        </div>
                    )}
                </div>
            </div>
            <ManageDevicesModal isOpen={isDevicesOpen} onClose={() => setDevicesOpen(false)} />
        </header>
    );
};

export default Header;

import React, { useState, useMemo } from 'react';
import { useData } from '../../hooks/useData.ts';
import { Page, StockStatus, OrderStatus, BookingStatus, Product, ProductVariant, PaymentType, StockOrder } from '../../types.ts';
import { ArrowLeftIcon, BoxIcon, CalendarIcon, CheckSquareIcon, DollarSignIcon, StarIcon, PrintIcon, WhatsAppIcon, RefreshCwIcon, MessageSquareIcon } from '../icons/Icons.tsx';
import StatCard from '../shared/StatCard.tsx';
import usePagination from '../../hooks/usePagination.ts';
import Pagination from '../shared/Pagination.tsx';
import EmptyState from '../shared/EmptyState.tsx';
import SkeletonLoader from '../shared/SkeletonLoader.tsx';
import { printElementById, createWhatsAppLink } from '../../utils/print.ts';
import Tooltip from '../shared/Tooltip.tsx';
import DealerPaymentModal from '../modals/DealerPaymentModal.tsx';
import { usePermissions } from '../../hooks/usePermissions.ts';
import { useAppContext } from '../../hooks/useAppContext.ts';

type DetailTab = 'overview' | 'stock' | 'orders' | 'bookings' | 'financials';

const DealerDetail: React.FC<{ dealerId: string; setActivePage: (page: Page, state?: any) => void; showToast: (message: string, type: 'success' | 'error' | 'info') => void; }> = ({ dealerId, setActivePage, showToast }) => {
    const { dealers, stock, stockOrders, bookings, products, isLoading, dealerPayments, recalculateReputation } = useData();
    const { users } = useAppContext();
    const { canRecalculateReputation } = usePermissions();
    const [activeTab, setActiveTab] = useState<DetailTab>('overview');
    const [isPaymentModalOpen, setPaymentModalOpen] = useState(false);
    const [isRecalculating, setIsRecalculating] = useState(false);

    const dealer = useMemo(() => dealers.find(d => d._id === dealerId), [dealers, dealerId]);

    const dealerStock = useMemo(() => stock.filter(s => s.dealerId === dealerId), [stock, dealerId]);
    const dealerOrders = useMemo(() => stockOrders.filter(o => o.dealerId === dealerId), [stockOrders, dealerId]);
    const dealerBookings = useMemo(() => bookings.filter(b => b.dealerId === dealerId), [bookings, dealerId]);
    const paymentsForDealer = useMemo(() => dealerPayments.filter(p => p.dealerId === dealerId), [dealerPayments, dealerId]);

    const findProductInfo = (variantId: string): { product: Product | null, variant: ProductVariant | null } => {
        for (const product of products) {
            const variant = product.variants.find(v => v._id === variantId);
            if (variant) return { product, variant };
        }
        return { product: null, variant: null };
    };

    const stats = useMemo(() => {
        const totalStockValue = dealerStock.reduce((sum, item) => {
            const { variant } = findProductInfo(item.variantId);
            return sum + (variant?.price || 0);
        }, 0);
        const pendingOrders = dealerOrders.filter(o => o.status === OrderStatus.Pending).length;
        const deliveredBookings = dealerBookings.filter(b => b.status === BookingStatus.Delivered);
        const totalRevenue = deliveredBookings.reduce((sum, booking) => {
            const { variant } = findProductInfo(booking.variantId);
            return sum + (variant?.price || 0);
        }, 0);

        return {
            totalStockValue,
            pendingOrders,
            totalRevenue,
            totalBookings: dealerBookings.length,
        };
    }, [dealerStock, dealerOrders, dealerBookings, products]);

    const getStatusChip = (status: StockStatus | OrderStatus | BookingStatus) => {
        let colorClasses = '';
        switch (status) {
            case StockStatus.Available:
            case OrderStatus.Approved:
            case BookingStatus.Delivered:
            case OrderStatus.Delivered:
                colorClasses = 'bg-green-100 text-green-800'; break;
            case StockStatus.Reserved:
            case OrderStatus.Pending:
            case BookingStatus.Pending:
                colorClasses = 'bg-yellow-100 text-yellow-800'; break;
            case StockStatus.Sold:
            case OrderStatus.Rejected:
            case BookingStatus.Cancelled:
                colorClasses = 'bg-red-100 text-red-800'; break;
            case OrderStatus.PartiallyApproved:
            case BookingStatus.Allocated:
                colorClasses = 'bg-blue-100 text-blue-800'; break;
            case OrderStatus.Dispatched:
            case OrderStatus.InTransit:
                colorClasses = 'bg-indigo-100 text-indigo-800'; break;
            default: colorClasses = 'bg-slate-100 text-slate-800';
        }
        return <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${colorClasses}`}>{status}</span>;
    };

    const handleRecalculate = async () => {
        if (!dealerId) return;
        setIsRecalculating(true);
        await recalculateReputation(dealerId);
        setIsRecalculating(false);
    }

    const getReputationScoreUI = (score: number) => {
        let colorClasses = '';
        if (score >= 8.0) colorClasses = 'text-green-600';
        else if (score >= 5.0) colorClasses = 'text-yellow-600';
        else colorClasses = 'text-red-600';
        return <div className={`flex items-center text-xl font-bold ${colorClasses}`}><StarIcon className="w-5 h-5 mr-1.5 fill-current" /><span>{score.toFixed(1)}</span></div>;
    };

    const handleSendMessage = () => {
        if (!dealer) return;
        const dealerUser = users.find(u => u.dealerId === dealer._id);
        if (dealerUser) {
            setActivePage('Messages', { recipientId: dealerUser._id });
        } else {
            showToast('Could not find a user associated with this dealer.', 'error');
        }
    };

    const renderContent = () => {
        switch(activeTab) {
            case 'overview':
                return (
                    <div className="bg-white dark:bg-slate-800 p-6 rounded-lg shadow-sm space-y-8">
                        <div>
                            <h3 className="font-semibold text-slate-800 dark:text-slate-100 mb-4 text-lg">Dealer Information</h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div><strong>Owner:</strong> {dealer?.ownerName}</div>
                                <div><strong>Email:</strong> {dealer?.email}</div>
                                <div className="flex items-center">
                                    <strong className="mr-2">Phone:</strong>
                                    <a
                                        href={createWhatsAppLink(dealer?.phone || '')}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="flex items-center hover:text-green-600 dark:hover:text-green-400 transition-colors"
                                        aria-label="Chat on WhatsApp"
                                    >
                                        <span className="hover:underline">{dealer?.phone}</span>
                                        <Tooltip content="Chat on WhatsApp">
                                            <WhatsAppIcon className="w-5 h-5 ml-2 text-green-600 dark:text-green-400" />
                                        </Tooltip>
                                    </a>
                                </div>
                                <div><strong>City:</strong> {dealer?.city}</div>
                                <div><strong>Status:</strong> {dealer?.registrationApproved ? getStatusChip('Approved' as any) : getStatusChip('Pending' as any)}</div>
                                <div className="flex items-center gap-4">
                                    <strong>Reputation:</strong>
                                    {getReputationScoreUI(dealer?.reputationScore ?? 0)}
                                    {canRecalculateReputation &&
                                        <Tooltip content="Recalculate score based on recent performance">
                                            <button onClick={handleRecalculate} disabled={isRecalculating} className="p-1.5 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 hover:text-primary disabled:opacity-50 no-print">
                                                <RefreshCwIcon className={`w-4 h-4 ${isRecalculating ? 'animate-spin' : ''}`} />
                                            </button>
                                        </Tooltip>
                                    }
                                </div>
                            </div>
                        </div>

                        <div>
                            <h3 className="font-semibold text-slate-800 dark:text-slate-100 mb-4 text-lg border-t border-slate-200 dark:border-slate-700 pt-6">Key Performance Metrics</h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-4 gap-y-6 text-sm">
                                <div className="p-4 bg-slate-50 dark:bg-slate-700/50 rounded-lg">
                                    <p className="font-medium text-slate-500 dark:text-slate-400">Total Sales Revenue</p>
                                    <p className="text-2xl font-bold text-slate-800 dark:text-slate-100 mt-1">Rs. {stats.totalRevenue.toLocaleString()}</p>
                                </div>
                                 <div className="p-4 bg-slate-50 dark:bg-slate-700/50 rounded-lg">
                                    <p className="font-medium text-slate-500 dark:text-slate-400">Total Bookings (All Time)</p>
                                    <p className="text-2xl font-bold text-slate-800 dark:text-slate-100 mt-1">{stats.totalBookings}</p>
                                </div>
                                 <div className="p-4 bg-slate-50 dark:bg-slate-700/50 rounded-lg">
                                    <p className="font-medium text-slate-500 dark:text-slate-400">Current Stock Value</p>
                                    <p className="text-2xl font-bold text-slate-800 dark:text-slate-100 mt-1">Rs. {stats.totalStockValue.toLocaleString()}</p>
                                </div>
                                 <div className="p-4 bg-slate-50 dark:bg-slate-700/50 rounded-lg">
                                    <p className="font-medium text-slate-500 dark:text-slate-400">Pending Stock Orders</p>
                                    <p className="text-2xl font-bold text-slate-800 dark:text-slate-100 mt-1">{stats.pendingOrders}</p>
                                </div>
                            </div>
                        </div>
                    </div>
                );
            case 'stock': return <PaginatedTable columns={['VIN', 'Product', 'Status', 'Assigned']} data={dealerStock} renderRow={(item) => {
                const {product, variant} = findProductInfo(item.variantId);
                return (<>
                    <td className="px-6 py-4 whitespace-nowrap font-mono">{item.vin}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{product?.modelName} ({variant?.name})</td>
                    <td className="px-6 py-4 whitespace-nowrap">{getStatusChip(item.status)}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{new Date(item.assignedAt).toLocaleDateString()}</td>
                </>);
            }} />;
            case 'orders': return <PaginatedTable columns={['Date', 'Status', 'Requested', 'Approved']} data={dealerOrders} renderRow={(item) => {
                const totalReq = item.items.reduce((sum, i) => sum + i.quantity, 0);
                const totalApp = item.approvedItems?.reduce((sum, i) => sum + i.approvedQuantity, 0) ?? 'N/A';
                 return (<>
                    <td className="px-6 py-4 whitespace-nowrap">{new Date(item.requestTimestamp).toLocaleDateString()}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{getStatusChip(item.status)}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{totalReq} units</td>
                    <td className="px-6 py-4 whitespace-nowrap font-semibold">{totalApp} units</td>
                </>);
            }} />;
             case 'bookings': return <PaginatedTable columns={['Date', 'Customer', 'Product', 'Status']} data={dealerBookings} renderRow={(item) => {
                 const {product, variant} = findProductInfo(item.variantId);
                 return (<>
                    <td className="px-6 py-4 whitespace-nowrap">{new Date(item.bookingTimestamp).toLocaleDateString()}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{item.customerName}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{product?.modelName} ({variant?.name})</td>
                    <td className="px-6 py-4 whitespace-nowrap">{getStatusChip(item.status)}</td>
                </>);
             }} />;
            case 'financials':
                const financialSummary = useMemo(() => {
                    const ordersWithValues = dealerOrders
                        .filter(o => o.status !== OrderStatus.Pending && o.status !== OrderStatus.Rejected)
                        .map(order => {
                            const orderValue = order.approvedItems?.reduce((sum, item) => {
                                const variant = findProductInfo(item.variantId).variant;
                                return sum + (item.approvedQuantity * (variant?.price || 0));
                            }, 0) ?? 0;

                            const paidAmount = paymentsForDealer
                                .filter(p => p.stockOrderId === order._id)
                                .reduce((sum, p) => sum + p.amount, 0);

                            return {
                                order,
                                orderValue,
                                paidAmount,
                                balance: orderValue - paidAmount,
                            };
                        });

                    const unlinkedPayments = paymentsForDealer.filter(p => !p.stockOrderId);
                    const totalOrderValue = ordersWithValues.reduce((sum, o) => sum + o.orderValue, 0);
                    const totalPaid = paymentsForDealer.reduce((sum, p) => sum + p.amount, 0);

                    return { ordersWithValues, unlinkedPayments, totalOrderValue, totalPaid, totalBalance: totalOrderValue - totalPaid };
                }, [dealerOrders, paymentsForDealer, products]);

                return (
                    <div className="space-y-6">
                        <div className="bg-white dark:bg-slate-800 p-6 rounded-lg shadow-sm">
                            <div className="flex justify-between items-center mb-4">
                                <h3 className="font-semibold text-slate-800 dark:text-slate-100 text-lg">Financial Summary</h3>
                                <button onClick={() => setPaymentModalOpen(true)} className="py-2 px-4 text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary no-print">Record Payment</button>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 border-t border-slate-200 dark:border-slate-700 pt-4">
                                <div><p className="text-sm text-slate-500 dark:text-slate-400">Total Approved Order Value</p><p className="text-2xl font-bold text-slate-800 dark:text-slate-100">Rs. {financialSummary.totalOrderValue.toLocaleString()}</p></div>
                                <div><p className="text-sm text-slate-500 dark:text-slate-400">Total Payments Received</p><p className="text-2xl font-bold text-green-600">Rs. {financialSummary.totalPaid.toLocaleString()}</p></div>
                                <div><p className="text-sm text-slate-500 dark:text-slate-400">Overall Balance</p><p className={`text-2xl font-bold ${financialSummary.totalBalance > 0 ? 'text-red-600' : 'text-slate-800 dark:text-slate-100'}`}>Rs. {financialSummary.totalBalance.toLocaleString()}</p></div>
                            </div>
                        </div>
                        <PaginatedTable columns={['Order Date', 'Order Value', 'Amount Paid', 'Balance']} data={financialSummary.ordersWithValues} renderRow={(item) => (
                             <>
                                <td className="px-6 py-4 whitespace-nowrap">{new Date(item.order.requestTimestamp).toLocaleDateString()}</td>
                                <td className="px-6 py-4 whitespace-nowrap">Rs. {item.orderValue.toLocaleString()}</td>
                                <td className="px-6 py-4 whitespace-nowrap text-green-600">Rs. {item.paidAmount.toLocaleString()}</td>
                                <td className={`px-6 py-4 whitespace-nowrap font-semibold ${item.balance > 0 ? 'text-red-600' : 'text-slate-800 dark:text-slate-200'}`}>Rs. {item.balance.toLocaleString()}</td>
                            </>
                         )} />
                    </div>
                );
        }
    }

    if (isLoading) return <SkeletonLoader type="table" rows={8} />;

    if (!dealer) {
        return <div className="text-center p-8 bg-white dark:bg-slate-800 rounded-lg">
            <h2 className="text-xl font-bold text-red-600">Dealer Not Found</h2>
            <p className="text-slate-500 mt-2">The requested dealer could not be found.</p>
            <button onClick={() => setActivePage('Dealers')} className="mt-4 flex items-center mx-auto text-sm font-semibold text-primary hover:underline">
                <ArrowLeftIcon className="w-4 h-4 mr-1" />
                Return to Dealers List
            </button>
        </div>;
    }

    return (
        <div id="dealer-detail-content" className="space-y-6">
            <div className="flex justify-between items-center no-print">
                <button onClick={() => setActivePage('Dealers')} className="flex items-center text-sm font-semibold text-primary hover:underline">
                    <ArrowLeftIcon className="w-4 h-4 mr-2" />
                    Back to Dealers List
                </button>
                <div className="flex items-center gap-2">
                    <Tooltip content="Send a message">
                        <button onClick={handleSendMessage} className="flex items-center justify-center p-2 border border-slate-300 dark:border-slate-600 shadow-sm rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                            <MessageSquareIcon />
                        </button>
                    </Tooltip>
                    <Tooltip content="Print Current View">
                        <button onClick={() => printElementById('dealer-detail-content')} className="flex items-center justify-center p-2 border border-slate-300 dark:border-slate-600 shadow-sm rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                            <PrintIcon />
                        </button>
                    </Tooltip>
                </div>
            </div>

            <div>
                <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100">{dealer.name}</h2>
                <p className="text-slate-500 dark:text-slate-400">{dealer.city}</p>
            </div>

            <div className="hidden print-only">
                <h1 className="text-2xl font-bold mb-1">Dealer Summary: {dealer.name}</h1>
                <p className="text-sm text-slate-600 mb-4">Report for: {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} | Generated on: {new Date().toLocaleDateString()}</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 no-print">
                <StatCard title="Total Stock Value" value={`Rs. ${stats.totalStockValue.toLocaleString()}`} icon={<BoxIcon />} color="bg-blue-500" onClick={() => setActiveTab('stock')} />
                <StatCard title="Pending Orders" value={stats.pendingOrders.toString()} icon={<CheckSquareIcon />} color="bg-yellow-500" onClick={() => setActiveTab('orders')} />
                <StatCard title="Total Bookings" value={stats.totalBookings.toString()} icon={<CalendarIcon />} color="bg-green-500" onClick={() => setActiveTab('bookings')} />
                <StatCard title="Total Sales Revenue" value={`Rs. ${stats.totalRevenue.toLocaleString()}`} icon={<DollarSignIcon />} color="bg-indigo-500" onClick={() => setActiveTab('financials')} />
            </div>

            <div className="flex space-x-1 border-b border-slate-200 dark:border-slate-700 no-print">
                {(['overview', 'stock', 'orders', 'bookings', 'financials'] as DetailTab[]).map(tab => (
                    <button key={tab} onClick={() => setActiveTab(tab)} className={`px-4 py-2 text-sm font-semibold capitalize transition-colors ${activeTab === tab ? 'border-b-2 border-primary text-primary' : 'text-slate-500 dark:text-slate-400 hover:text-primary dark:hover:text-slate-200'}`}>
                        {tab}
                    </button>
                ))}
            </div>

             <div className="mt-4 animate-fade-in">
                {renderContent()}
            </div>
             <DealerPaymentModal 
                isOpen={isPaymentModalOpen} 
                onClose={() => setPaymentModalOpen(false)} 
                dealerId={dealerId} 
                showToast={showToast}
            />
        </div>
    );
};

const PaginatedTable: React.FC<{
    columns: string[];
    data: any[];
    renderRow: (item: any) => React.ReactNode;
}> = ({ columns, data, renderRow }) => {
    const { paginatedData, currentPage, totalPages, nextPage, prevPage } = usePagination(data, 5);

    return (
        <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm overflow-hidden">
            <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                    <thead className="bg-slate-100/80 dark:bg-slate-700/50">
                        <tr>
                            {columns.map(col => <th key={col} className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">{col}</th>)}
                        </tr>
                    </thead>
                    <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
                        {paginatedData.length > 0 ? paginatedData.map((item, index) => <tr key={item._id || index} className="hover:bg-slate-50 dark:hover:bg-slate-700/50">{renderRow(item)}</tr>) : (
                             <tr><td colSpan={columns.length}><EmptyState icon={<BoxIcon/>} title="No Data Available" message="There are no records to display for this section." /></td></tr>
                        )}
                    </tbody>
                </table>
            </div>
            <Pagination currentPage={currentPage} totalPages={totalPages} onNext={nextPage} onPrev={prevPage} />
        </div>
    );
};

export default DealerDetail;

import React, { useState, useMemo } from 'react';
import { useData } from '../../hooks/useData.ts';
import type { StockOrder, StockOrderItem, DealerPayment } from '../../types.ts';
import { OrderStatus } from '../../types.ts';
import OrderReviewModal from '../modals/OrderReviewModal.tsx';
import Tooltip from '../shared/Tooltip.tsx';
import { ChevronDownIcon, ChevronUpIcon, ClipboardListIcon, TruckIcon, PrintIcon, WhatsAppIcon } from '../icons/Icons.tsx';
import SkeletonLoader from '../shared/SkeletonLoader.tsx';
import usePagination from '../../hooks/usePagination.ts';
import Pagination from '../shared/Pagination.tsx';
import EmptyState from '../shared/EmptyState.tsx';
import { usePermissions } from '../../hooks/usePermissions.ts';
import { printElementById, createWhatsAppLink } from '../../utils/print.ts';
import ConfirmModal from '../modals/ConfirmModal.tsx';

const StockOrders: React.FC<{ showToast: (message: string, type: 'success' | 'error' | 'info') => void; }> = ({ showToast }) => {
    const { stockOrders, dealers, products, isLoading, dispatchStockOrder, dealerPayments } = useData();
    const { canApproveStockOrder, canDispatchOrders } = usePermissions();
    const [isModalOpen, setModalOpen] = useState(false);
    const [selectedOrder, setSelectedOrder] = useState<StockOrder | null>(null);
    const [orderToDispatch, setOrderToDispatch] = useState<StockOrder | null>(null);
    const [isConfirmDispatchOpen, setConfirmDispatchOpen] = useState(false);
    const [filterStatus, setFilterStatus] = useState<OrderStatus | 'all'>('all');
    const [dealerFilter, setDealerFilter] = useState('all');
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [searchQuery, setSearchQuery] = useState('');
    const [expandedOrderId, setExpandedOrderId] = useState<string | null>(null);

    const findVariant = (variantId: string) => {
        for (const product of products) {
            const variant = product.variants.find(v => v._id === variantId);
            if (variant) return { product, variant }; // Return full structure
        }
        return null;
    };

    const getOrderPaymentStatus = (order: StockOrder) => {
        if (order.status === OrderStatus.Rejected || order.status === OrderStatus.Pending) {
            return { status: 'N/A', color: 'bg-slate-100 text-slate-800 dark:bg-slate-700 dark:text-slate-300' };
        }

        const orderValue = order.approvedItems?.reduce((sum, item) => {
            const found = findVariant(item.variantId);
            const variant = found?.variant;
            return sum + (item.approvedQuantity * (variant?.price || 0));
        }, 0) ?? 0;

        if (orderValue === 0) {
            return { status: 'N/A', color: 'bg-slate-100 text-slate-800 dark:bg-slate-700 dark:text-slate-300' };
        }

        const totalPaid = dealerPayments
            .filter(p => p.stockOrderId === order._id)
            .reduce((sum, p) => sum + p.amount, 0);

        if (totalPaid >= orderValue) {
            return { status: 'Paid', color: 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300' };
        }
        if (totalPaid > 0) {
            return { status: 'Partially Paid', color: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/50 dark:text-yellow-300' };
        }
        return { status: 'Unpaid', color: 'bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-300' };
    };

    const filteredOrders = useMemo(() => {
        let orders = stockOrders;

        if (filterStatus !== 'all') orders = orders.filter(o => o.status === filterStatus);
        if (dealerFilter !== 'all') orders = orders.filter(o => o.dealerId === dealerFilter);

        const orderDate = new Date(orders[0]?.requestTimestamp);
        if (startDate) orders = orders.filter(o => new Date(o.requestTimestamp) >= new Date(startDate));
        if (endDate) orders = orders.filter(o => new Date(o.requestTimestamp) <= new Date(endDate));

        if (searchQuery) {
            const lowercasedQuery = searchQuery.toLowerCase();
            orders = orders.filter(order => {
                const dealer = dealers.find(d => d._id === order.dealerId);
                if (dealer?.name.toLowerCase().includes(lowercasedQuery)) return true;

                return order.items.some(item => {
                    const product = products.find(p => p._id === item.productId);
                    if (product) {
                        if (product.modelName.toLowerCase().includes(lowercasedQuery)) return true;
                        const variant = product.variants.find(v => v._id === item.variantId);
                        if (variant?.name.toLowerCase().includes(lowercasedQuery)) return true;
                    }
                    return false;
                });
            });
        }

        return orders.sort((a, b) => new Date(b.requestTimestamp).getTime() - new Date(a.requestTimestamp).getTime());
    }, [stockOrders, filterStatus, dealerFilter, startDate, endDate, searchQuery, dealers, products]);

    const { paginatedData, currentPage, totalPages, nextPage, prevPage, setCurrentPage } = usePagination(filteredOrders, 10);

    const handleReview = (order: StockOrder) => {
        setSelectedOrder(order);
        setModalOpen(true);
    };

    const handleDispatchClick = (order: StockOrder) => {
        setOrderToDispatch(order);
        setConfirmDispatchOpen(true);
    };

    const handleDispatchConfirm = async () => {
        if (!orderToDispatch) return;
        try {
            await dispatchStockOrder(orderToDispatch._id);
            showToast('Order marked as dispatched!', 'success');
        } catch {
            showToast('Failed to dispatch order.', 'error');
        }
        setConfirmDispatchOpen(false);
        setOrderToDispatch(null);
    };

    const handlePrintOrder = (orderId: string) => {
        const elementId = `order-details-${orderId}`;
        printElementById(elementId);
    };


    const handleToggleRow = (orderId: string) => {
        setExpandedOrderId(prev => (prev === orderId ? null : orderId));
    };

    const getStatusColor = (status: OrderStatus) => {
        switch (status) {
            case OrderStatus.Pending: return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/50 dark:text-yellow-300';
            case OrderStatus.Approved: return 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300';
            case OrderStatus.PartiallyApproved: return 'bg-blue-100 text-blue-800 dark:bg-blue-900/50 dark:text-blue-300';
            case OrderStatus.Rejected: return 'bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-300';
            case OrderStatus.Dispatched: return 'bg-indigo-100 text-indigo-800 dark:bg-indigo-900/50 dark:text-indigo-300';
            case OrderStatus.InTransit: return 'bg-purple-100 text-purple-800 dark:bg-purple-900/50 dark:text-purple-300';
            case OrderStatus.Delivered: return 'bg-teal-100 text-teal-800 dark:bg-teal-900/50 dark:text-teal-300';
            default: return 'bg-slate-100 text-slate-800 dark:bg-slate-700 dark:text-slate-300';
        }
    };

    const handleClearFilters = () => {
        setSearchQuery('');
        setFilterStatus('all');
        setDealerFilter('all');
        setStartDate('');
        setEndDate('');
    };

    if (isLoading) {
        return <SkeletonLoader type="table" rows={5} />;
    }

    return (
        <div id="stock-orders-page-content" className="space-y-6">
            <div className="flex justify-between items-center no-print">
                <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100">Stock Orders</h2>
                <Tooltip content="Print Current View">
                    <button onClick={() => printElementById('stock-orders-page-content')} className="flex items-center justify-center space-x-2 py-2 px-4 border border-slate-300 dark:border-slate-600 shadow-sm text-sm font-medium rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                        <PrintIcon />
                        <span>Print</span>
                    </button>
                </Tooltip>
            </div>

            <div className="bg-white dark:bg-slate-800 p-4 rounded-lg shadow-sm flex flex-col md:flex-row justify-between items-stretch gap-4 no-print">
                <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4 flex-wrap">
                    <div className="relative">
                        <input type="text" placeholder="Search by dealer or item..." value={searchQuery} onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }} className="pl-10 pr-4 py-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm w-full sm:w-64 bg-white dark:bg-slate-700" />
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <svg className="h-5 w-5 text-slate-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg>
                        </div>
                    </div>
                    <div className="flex items-center">
                        <label className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">Status:</label>
                        <select value={filterStatus} onChange={(e) => { setFilterStatus(e.target.value as OrderStatus | 'all'); setCurrentPage(1); }} className="p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm w-full bg-white dark:bg-slate-700">
                            <option value="all">All</option>{Object.values(OrderStatus).map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                    </div>
                    <div className="flex items-center">
                        <label className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">Dealer:</label>
                        <select value={dealerFilter} onChange={(e) => { setDealerFilter(e.target.value); setCurrentPage(1); }} className="p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm w-full bg-white dark:bg-slate-700">
                            <option value="all">All</option>{dealers.map(d => <option key={d._id} value={d._id}>{d.name}</option>)}
                        </select>
                    </div>
                    <div className="flex items-center">
                        <label className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">From:</label>
                        <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm w-full bg-white dark:bg-slate-700" />
                    </div>
                    <div className="flex items-center">
                        <label className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">To:</label>
                        <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm w-full bg-white dark:bg-slate-700" />
                    </div>
                </div>
                 <button onClick={handleClearFilters} className="py-2 px-4 border border-slate-300 dark:border-slate-600 shadow-sm text-sm font-medium rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors shrink-0">
                    Clear Filters
                </button>
            </div>

            <div className="hidden print-only">
                <h1 className="text-2xl font-bold mb-1">Stock Orders Report</h1>
                <p className="text-sm text-slate-600 mb-4">
                    Filter: Status ({filterStatus}) | Generated on: {new Date().toLocaleDateString()}
                </p>
            </div>

            <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                        <thead className="bg-slate-100/80 dark:bg-slate-700/50">
                            <tr>
                                <th className="px-2 py-3 w-12 no-print"></th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Dealer</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Order Date</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Status</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Payment Status</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Items (Req/App)</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider no-print">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
                            {paginatedData.length > 0 ? paginatedData.map(order => {
                                const dealer = dealers.find(d => d._id === order.dealerId);
                                const totalQty = order.items.reduce((sum, item) => sum + item.quantity, 0);
                                const approvedQty = order.approvedItems?.reduce((sum, item) => sum + item.approvedQuantity, 0) ?? 0;
                                const isExpanded = expandedOrderId === order._id;
                                const prefilledMessage = `Hi ${dealer?.name}, regarding Stock Order #${order._id.slice(-6)}.`;
                                const canBeDispatched = (order.status === OrderStatus.Approved || order.status === OrderStatus.PartiallyApproved) && canDispatchOrders;
                                const paymentStatus = getOrderPaymentStatus(order);

                                return (
                                    <React.Fragment key={order._id}>
                                        <tr className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                                            <td className="px-2 py-4 whitespace-nowrap text-center no-print">
                                                <Tooltip content={isExpanded ? 'Hide Details' : 'Show Details'}>
                                                    <button onClick={() => handleToggleRow(order._id)} className="text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300 p-1 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700">
                                                        {isExpanded ? <ChevronUpIcon /> : <ChevronDownIcon />}
                                                    </button>
                                                </Tooltip>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <div className="text-sm font-medium text-slate-900 dark:text-slate-100">{dealer?.name}</div>
                                                <div className="text-sm text-slate-500 dark:text-slate-400">{dealer?.city}</div>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">{new Date(order.requestTimestamp).toLocaleDateString()}</td>
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full capitalize ${getStatusColor(order.status)}`}>
                                                    {order.status}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full capitalize ${paymentStatus.color}`}>
                                                    {paymentStatus.status}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <Tooltip content={order.items.map(item => `${item.quantity}x ${findVariant(item.variantId)?.variant?.name || 'Unknown'}`).join(', ')}>
                                                    <span className="text-sm text-slate-700 dark:text-slate-300">{totalQty} / {order.status !== OrderStatus.Pending ? approvedQty : 'N/A'}</span>
                                                </Tooltip>
                                                {order.status !== OrderStatus.Pending && 
                                                    <p className="text-xs text-slate-500 dark:text-slate-400">Approved: {approvedQty} units</p>
                                                }
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm font-medium no-print">
                                                <div className="flex items-center space-x-2">
                                                    {order.status === OrderStatus.Pending && canApproveStockOrder && (
                                                        <button onClick={() => handleReview(order)} className="py-2 px-4 border border-transparent shadow-sm rounded-md text-white bg-primary hover:bg-secondary text-xs font-medium">
                                                            Review
                                                        </button>
                                                    )}
                                                    {canBeDispatched && (
                                                        <button onClick={() => handleDispatchClick(order)} className="flex items-center space-x-2 py-2 px-3 border border-transparent shadow-sm rounded-md text-white bg-indigo-600 hover:bg-indigo-700 text-xs font-medium">
                                                            <TruckIcon className="w-4 h-4" />
                                                            <span>Dispatch</span>
                                                        </button>
                                                    )}
                                                     <Tooltip content={`Chat with ${dealer?.name} on WhatsApp`}>
                                                        <a 
                                                            href={createWhatsAppLink(dealer?.phone || '', prefilledMessage)}
                                                            target="_blank"
                                                            rel="noopener noreferrer"
                                                            className="text-green-600 hover:text-green-700 dark:text-green-400 dark:hover:text-green-300 transition-colors p-1 rounded-full hover:bg-green-100 dark:hover:bg-green-900/50"
                                                        >
                                                            <WhatsAppIcon />
                                                        </a>
                                                    </Tooltip>
                                                </div>
                                            </td>
                                        </tr>
                                        {isExpanded && (
                                            <tr className="bg-slate-50 dark:bg-slate-800/50">
                                                <td colSpan={7} className="p-0">
                                                     <div id={`order-details-${order._id}`} className="p-4 mx-4 my-2 border-l-4 border-accent bg-slate-100 dark:bg-slate-700 rounded-r-md">
                                                        <div className="flex justify-between items-center mb-2">
                                                            <h4 className="text-sm font-semibold text-slate-700 dark:text-slate-200 px-4">Order Details</h4>
                                                            <button onClick={() => handlePrintOrder(order._id)} className="flex items-center space-x-1 text-xs font-semibold text-primary hover:underline no-print">
                                                                <PrintIcon className="w-4 h-4" />
                                                                <span>Print</span>
                                                            </button>
                                                        </div>
                                                        <table className="min-w-full">
                                                            <thead className="bg-slate-200 dark:bg-slate-600">
                                                                <tr>
                                                                    <th className="px-4 py-2 text-left text-xs font-medium text-slate-600 dark:text-slate-300 uppercase">Product</th>
                                                                    <th className="px-4 py-2 text-center text-xs font-medium text-slate-600 dark:text-slate-300 uppercase">Requested</th>
                                                                    <th className="px-4 py-2 text-center text-xs font-medium text-slate-600 dark:text-slate-300 uppercase">Approved</th>
                                                                    <th className="px-4 py-2 text-right text-xs font-medium text-slate-600 dark:text-slate-300 uppercase">Unit Price</th>
                                                                    <th className="px-4 py-2 text-right text-xs font-medium text-slate-600 dark:text-slate-300 uppercase">Subtotal</th>
                                                                </tr>
                                                            </thead>
                                                            <tbody className="bg-white dark:bg-slate-700/50">
                                                                {order.items.map((item: StockOrderItem) => {
                                                                    const found = findVariant(item.variantId);
                                                                    const variant = found?.variant;
                                                                    const approvedItem = order.approvedItems?.find(ai => ai.variantId === item.variantId);
                                                                    const approvedQuantity = approvedItem?.approvedQuantity;
                                                                    const subtotal = (variant?.price ?? 0) * (approvedQuantity ?? 0);
                                                                    return (
                                                                        <tr key={item.variantId}>
                                                                            <td className="px-4 py-2 text-sm text-slate-800 dark:text-slate-200">{variant?.name || 'Unknown Variant'}</td>
                                                                            <td className="px-4 py-2 text-sm text-slate-500 dark:text-slate-400 text-center">{item.quantity}</td>
                                                                            <td className={`px-4 py-2 text-sm font-bold text-center`}>
                                                                                {approvedQuantity !== undefined ? approvedQuantity : 'N/A'}
                                                                            </td>
                                                                            <td className="px-4 py-2 text-sm text-slate-600 dark:text-slate-300 text-right">
                                                                                {variant ? `Rs. ${variant.price.toLocaleString()}` : 'N/A'}
                                                                            </td>
                                                                            <td className="px-4 py-2 text-sm text-slate-800 dark:text-slate-200 font-semibold text-right">
                                                                                {approvedQuantity !== undefined ? `Rs. ${subtotal.toLocaleString()}` : 'N/A'}
                                                                            </td>
                                                                        </tr>
                                                                    );
                                                                })}
                                                            </tbody>
                                                        </table>
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </React.Fragment>
                                );
                            }) : (
                                <tr>
                                    <td colSpan={7}>
                                        <EmptyState
                                            icon={<ClipboardListIcon className="w-10 h-10" />}
                                            title="No Orders Found"
                                            message={
                                                searchQuery || filterStatus !== 'all' || dealerFilter !== 'all'
                                                ? "Your filters didn't match any orders. Try a different query." 
                                                : "There are no stock orders in the system yet."
                                            }
                                        />
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
                <Pagination currentPage={currentPage} totalPages={totalPages} onNext={nextPage} onPrev={prevPage} />
            </div>

            <OrderReviewModal
                isOpen={isModalOpen}
                onClose={() => setModalOpen(false)}
                order={selectedOrder}
                showToast={showToast}
            />

            <ConfirmModal
                isOpen={isConfirmDispatchOpen}
                onClose={() => setConfirmDispatchOpen(false)}
                onConfirm={handleDispatchConfirm}
                title="Confirm Dispatch"
                message={`Are you sure you want to mark order #${orderToDispatch?._id.slice(-6)} as dispatched? This action will notify the dealer.`}
            />
        </div>
    );
};

