import React, { useState, useEffect } from 'react';
import { useAppContext } from '../../hooks/useAppContext.ts';
import { useAuth } from '../../hooks/useAuth.ts';
import type { StockOrderItem } from '../../types.ts';
import { StockStatus } from '../../types.ts';
import { PlusIcon, XCircleIcon } from '../icons/Icons.tsx';
import Spinner from '../shared/Spinner.tsx';
import { useData } from '../../hooks/useData.ts';

interface NewOrderModalProps {
    isOpen: boolean;
    onClose: () => void;
    showToast: (message: string, type: 'success' | 'error' | 'info') => void;
}

const NewOrderModal: React.FC<NewOrderModalProps> = ({ isOpen, onClose, showToast }) => {
    const { products, createStockOrder, stock } = useData();
    const { isOnline, addToQueue } = useAppContext();
    const { user } = useAuth();
    const [orderItems, setOrderItems] = useState<(Partial<StockOrderItem> & { error?: string })[]>([{}]);
    const [isVisible, setIsVisible] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);

    useEffect(() => {
        if (isOpen) {
            setIsVisible(true);
            setOrderItems([{}]); // Reset form on open
        } else {
            setTimeout(() => setIsVisible(false), 200);
        }
    }, [isOpen]);

    const validateItem = (item: Partial<StockOrderItem> & { error?: string }): string | undefined => {
        if (item.quantity === undefined || item.quantity === null) return undefined;

        if (!Number.isInteger(item.quantity) || item.quantity <= 0) {
            return "Must be a positive number.";
        }

        if (!item.variantId) return undefined;

        const centralStockCount = stock.filter(
            s => s.variantId === item.variantId && s.dealerId === null && s.status === StockStatus.Available
        ).length;

        if (item.quantity > centralStockCount) {
            return `Exceeds stock (${centralStockCount} available).`;
        }

        return undefined;
    };


    const handleItemChange = (index: number, field: 'variantId' | 'quantity', value: string) => {
        const newItems = [...orderItems];
        const updatedItem = { ...newItems[index] };

        if (field === 'variantId') {
            const [productId, variantId] = value.split(',');
            updatedItem.productId = productId;
            updatedItem.variantId = variantId;
        } else {
            if (value === '') {
                updatedItem.quantity = undefined;
            } else {
                const num = parseInt(value, 10);
                if (!isNaN(num)) {
                    updatedItem.quantity = num;
                }
            }
        }

        updatedItem.error = validateItem(updatedItem);
        newItems[index] = updatedItem;
        setOrderItems(newItems);
    };

    const addItem = () => {
        setOrderItems(prev => [...prev, {}]);
    };

    const removeItem = (index: number) => {
        if (orderItems.length <= 1) return;
        setOrderItems(prev => prev.filter((_, i) => i !== index));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        const validatedItems = orderItems.map(item => ({...item, error: validateItem(item)}));
        const hasErrors = validatedItems.some(item => item.quantity && item.quantity > 0 && item.error);

        if (hasErrors) {
            setOrderItems(validatedItems);
            showToast("Please fix the errors in your order.", "error");
            return;
        }

        const finalItems = validatedItems.filter(
            item => item.productId && item.variantId && item.quantity && item.quantity > 0
        ) as StockOrderItem[];

        if (finalItems.length === 0) {
            showToast("Please add at least one valid item to the order.", "error");
            return;
        }

        setIsSubmitting(true);

        try {
            const orderData = {
                dealerId: user!.dealerId!,
                items: finalItems,
            };

            if (isOnline) {
                await createStockOrder(orderData);
                showToast("Stock order submitted successfully!", "success");
            } else {
                addToQueue({ type: 'ADD_STOCK_ORDER', payload: orderData, timestamp: Date.now() });
                showToast("You are offline. Order added to sync queue.", "info");
            }
        } catch (error) {
            showToast("Failed to submit order.", "error");
        } finally {
            setIsSubmitting(false);
            onClose();
        }
    };

    if (!isVisible) return null;

    return (
        <div className={`fixed inset-0 bg-black bg-opacity-60 z-50 flex justify-center items-start sm:items-center p-0 sm:p-4 transition-opacity duration-200 ${isOpen ? 'opacity-100' : 'opacity-0'}`} onClick={onClose}>
            <div className={`bg-white dark:bg-slate-800 rounded-none sm:rounded-lg shadow-xl w-full h-full sm:h-auto sm:max-w-4xl flex flex-col transform transition-transform duration-200 ${isOpen ? 'scale-100' : 'scale-95'}`} onClick={e => e.stopPropagation()}>
                <form onSubmit={handleSubmit} className="flex flex-col h-full">
                    <div className="p-6 border-b border-slate-200 dark:border-slate-700 flex-shrink-0">
                        <h3 className="text-xl font-semibold text-slate-800 dark:text-slate-100">Create New Stock Order</h3>
                        <p className="text-sm text-slate-500 dark:text-slate-400">Select products and quantities to request from New Asia central stock.</p>
                    </div>
                    <div className="p-6 space-y-4 flex-grow overflow-y-auto bg-slate-50/50 dark:bg-slate-900/50">
                        {orderItems.map((item, index) => {
                             const selectedVariant = item.variantId ? products.flatMap(p => p.variants).find(v => v._id === item.variantId) : null;
                             const centralStockCount = item.variantId ? stock.filter(s => s.variantId === item.variantId && s.dealerId === null && s.status === StockStatus.Available).length : 0;
                            return (
                                <div key={index} className="grid grid-cols-1 md:grid-cols-12 gap-3 items-start border-b md:border-b-0 border-slate-200 dark:border-slate-700 pb-4 md:pb-0">
                                    <div className="md:col-span-6">
                                        <label className="block text-xs font-medium text-slate-600 dark:text-slate-400">Product Variant</label>
                                        <select
                                            value={item.productId ? `${item.productId},${item.variantId}` : ''}
                                            onChange={e => handleItemChange(index, 'variantId', e.target.value)}
                                            className="mt-1 block w-full shadow-sm sm:text-sm border-slate-300 dark:border-slate-600 rounded-md p-2 focus:ring-2 focus:ring-primary/50 focus:border-primary bg-white dark:bg-slate-700 text-slate-900 dark:text-slate-100"
                                        >
                                            <option value="" disabled>Select a product...</option>
                                            {products.map(p => (
                                                <optgroup label={`${p.brand} ${p.modelName}`} key={p._id}>
                                                    {p.variants.map(v => (
                                                        <option key={v._id} value={`${p._id},${v._id}`}>{v.name}</option>
                                                    ))}
                                                </optgroup>
                                            ))}
                                        </select>
                                    </div>
                                    <div className="md:col-span-3">
                                        <label className="block text-xs font-medium text-slate-600 dark:text-slate-400">Unit Price</label>
                                        <div className="mt-1 flex items-center h-10 px-2 bg-slate-100 dark:bg-slate-600 rounded-md border border-slate-200 dark:border-slate-500">
                                            <span className="text-sm text-slate-800 dark:text-slate-200 font-semibold">
                                                {selectedVariant ? `Rs. ${selectedVariant.price.toLocaleString()}` : '—'}
                                            </span>
                                        </div>
                                    </div>
                                    <div className="md:col-span-2">
                                        <div className="flex justify-between items-baseline">
                                            <label className="block text-xs font-medium text-slate-600 dark:text-slate-400">Quantity</label>
                                            {item.variantId && <span className="text-xs text-slate-500 dark:text-slate-400">Available: {centralStockCount}</span>}
                                        </div>
                                        <input
                                            type="number"
                                            min="1"
                                            value={item.quantity ?? ''}
                                            onChange={e => handleItemChange(index, 'quantity', e.target.value)}
                                            className={`mt-1 block w-full shadow-sm sm:text-sm rounded-md p-2 focus:ring-2 focus:ring-primary/50 bg-white dark:bg-slate-700 text-slate-900 dark:text-slate-100 ${item.error ? 'border-red-500 text-red-600 focus:border-red-500' : 'border-slate-300 dark:border-slate-600 focus:border-primary'}`}
                                        />
                                         {item.error && <p className="mt-1 text-xs text-red-600">{item.error}</p>}
                                    </div>
                                    <div className="md:col-span-1 pt-6 text-right flex justify-end">
                                        {orderItems.length > 1 && (
                                            <button type="button" onClick={() => removeItem(index)} className="text-red-500 hover:text-red-700 p-2 rounded-full hover:bg-red-100 dark:hover:bg-slate-600">
                                                <XCircleIcon />
                                            </button>
                                        )}
                                    </div>
                                </div>
                            )
                        })}
                        <button type="button" onClick={addItem} className="mt-4 flex items-center space-x-1 text-sm font-medium text-primary hover:underline">
                            <PlusIcon className="w-4 h-4" />
                            <span>Add Another Item</span>
                        </button>
                    </div>
                    <div className="px-6 py-4 bg-slate-50 dark:bg-slate-700/50 text-right space-x-2 rounded-b-lg flex-shrink-0 border-t border-slate-200 dark:border-slate-700">
                        <button type="button" onClick={onClose} disabled={isSubmitting} className="py-2 px-4 border border-slate-300 dark:border-slate-600 shadow-sm text-sm font-medium rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-700 hover:bg-slate-50 dark:hover:bg-slate-600 disabled:opacity-50">Cancel</button>
                        <button type="submit" disabled={isSubmitting} className="w-36 flex justify-center py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary disabled:bg-slate-400">
                            {isSubmitting ? <Spinner /> : 'Submit Order'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default NewOrderModal;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import type { Dealer, Page } from '../../types.ts';
import { PlusIcon, EditIcon, UsersIcon, StarIcon, PrintIcon, ChevronDownIcon, ChevronUpIcon, ChevronsUpDownIcon, CheckCircleIcon, XCircleIcon, WhatsAppIcon } from '../icons/Icons.tsx';
import DealerModal from '../modals/DealerModal.tsx';
import { useData } from '../../hooks/useData.ts';
import Tooltip from '../shared/Tooltip.tsx';
import SkeletonLoader from '../shared/SkeletonLoader.tsx';
import usePagination from '../../hooks/usePagination.ts';
import Pagination from '../shared/Pagination.tsx';
import EmptyState from '../shared/EmptyState.tsx';
import { usePermissions } from '../../hooks/usePermissions.ts';
import { printElementById, createWhatsAppLink } from '../../utils/print.ts';
import ConfirmModal from '../modals/ConfirmModal.tsx';

type SortableKey = 'name' | 'reputationScore' | 'createdAt';
type SortDirection = 'ascending' | 'descending';

const Dealers: React.FC<{
    showToast: (message: string, type: 'success' | 'error' | 'info') => void;
    setActivePage: (page: Page, state?: any) => void;
    initialState?: any;
    onInitialStateConsumed: () => void;
}> = ({ showToast, setActivePage, initialState, onInitialStateConsumed }) => {
    const { dealers, addDealer, updateDealer, approveDealer, revokeDealer, updateDealerStatusBulk, isLoading } = useData();
    const { canCreateDealer, canUpdateDealer, canApproveDealer } = usePermissions();

    const [isSaving, setIsSaving] = useState(false);
    const [isModalOpen, setModalOpen] = useState(false);
    const [selectedDealer, setSelectedDealer] = useState<Dealer | null>(null);
    const [selectedDealers, setSelectedDealers] = useState<string[]>([]);
    const [searchQuery, setSearchQuery] = useState('');
    const [debouncedSearchQuery, setDebouncedSearchQuery] = useState('');
    const [sortConfig, setSortConfig] = useState<{ key: SortableKey; direction: SortDirection } | null>({ key: 'name', direction: 'ascending' });
    const selectAllCheckboxRef = useRef<HTMLInputElement>(null);
    const [isConfirmOpen, setConfirmOpen] = useState(false);
    const [dealerToRevoke, setDealerToRevoke] = useState<Dealer | null>(null);
    const [isBulkConfirmOpen, setBulkConfirmOpen] = useState(false);
    const [bulkAction, setBulkAction] = useState<'approve' | 'revoke' | null>(null);
    const [cityFilter, setCityFilter] = useState<string>('all');
    const [statusFilter, setStatusFilter] = useState<'all' | 'approved' | 'pending'>('all');
    const [reputationFilter, setReputationFilter] = useState<'all' | 'excellent' | 'good' | 'poor'>('all');

    useEffect(() => {
        if (initialState?.status) {
            setStatusFilter(initialState.status);
            onInitialStateConsumed();
        }
    }, [initialState, onInitialStateConsumed]);

    useEffect(() => {
        const timerId = setTimeout(() => {
            setDebouncedSearchQuery(searchQuery);
        }, 300);
        return () => clearTimeout(timerId);
    }, [searchQuery]);

    const uniqueCities = useMemo(() => [...new Set(dealers.map(d => d.city))], [dealers]);

    const filteredDealers = useMemo(() => {
        let tempDealers = [...dealers];

        if (statusFilter !== 'all') {
            const isApproved = statusFilter === 'approved';
            tempDealers = tempDealers.filter(d => d.registrationApproved === isApproved);
        }

        if (cityFilter !== 'all') {
            tempDealers = tempDealers.filter(d => d.city === cityFilter);
        }

        if (reputationFilter !== 'all') {
            tempDealers = tempDealers.filter(d => {
                if (reputationFilter === 'excellent') return d.reputationScore >= 8;
                if (reputationFilter === 'good') return d.reputationScore >= 5 && d.reputationScore < 8;
                if (reputationFilter === 'poor') return d.reputationScore < 5;
                return true;
            });
        }

        if (debouncedSearchQuery) {
            const lowercasedQuery = debouncedSearchQuery.toLowerCase();
            tempDealers = tempDealers.filter(dealer =>
                dealer.name.toLowerCase().includes(lowercasedQuery) ||
                dealer.ownerName.toLowerCase().includes(lowercasedQuery) ||
                dealer.city.toLowerCase().includes(lowercasedQuery)
            );
        }
        return tempDealers;
    }, [dealers, debouncedSearchQuery, cityFilter, statusFilter, reputationFilter]);

    const sortedDealers = useMemo(() => {
        let sortableItems = [...filteredDealers];
        if (sortConfig !== null) {
            sortableItems.sort((a, b) => {
                let aValue = a[sortConfig.key];
                let bValue = b[sortConfig.key];

                if (aValue < bValue) {
                    return sortConfig.direction === 'ascending' ? -1 : 1;
                }
                if (aValue > bValue) {
                    return sortConfig.direction === 'ascending' ? 1 : -1;
                }
                return 0;
            });
        }
        return sortableItems;
    }, [filteredDealers, sortConfig]);

    const { paginatedData, currentPage, totalPages, nextPage, prevPage, setCurrentPage } = usePagination(sortedDealers, 10);

    useEffect(() => {
        setSelectedDealers([]);
    }, [currentPage, searchQuery, sortConfig, cityFilter, statusFilter, reputationFilter]);

    useEffect(() => {
        if (selectAllCheckboxRef.current) {
            const isIndeterminate = selectedDealers.length > 0 && selectedDealers.length < paginatedData.length;
            selectAllCheckboxRef.current.indeterminate = isIndeterminate;
        }
    }, [selectedDealers, paginatedData]);

    const handleEdit = (dealer: Dealer) => {
        setSelectedDealer(dealer);
        setModalOpen(true);
    };

    const handleAddNew = () => {
        setSelectedDealer(null);
        setModalOpen(true);
    };

    const handleSave = async (dealerData: Omit<Dealer, '_id' | 'createdAt' | 'registrationApproved'>, isEditing: boolean) => {
        setIsSaving(true);
        try {
            if (isEditing && selectedDealer) {
                await updateDealer({ ...selectedDealer, ...dealerData });
                showToast('Dealer updated successfully!', 'success');
            } else {
                await addDealer(dealerData);
                showToast('New dealer created!', 'success');
            }
        } catch (error) {
            showToast('Failed to save dealer.', 'error');
        } finally {
            setModalOpen(false);
            setIsSaving(false);
        }
    };

    const handleApprove = async (dealerId: string) => {
        try {
            await approveDealer(dealerId);
            showToast('Dealer registration approved!', 'success');
        } catch (error) {
            showToast('Failed to approve dealer.', 'error');
        }
    };

    const handleRevokeClick = (dealer: Dealer) => {
        setDealerToRevoke(dealer);
        setConfirmOpen(true);
    };

    const handleRevokeConfirm = async () => {
        if (!dealerToRevoke) return;
        try {
            await revokeDealer(dealerToRevoke._id); 
            showToast('Dealer approval revoked!', 'info');
        } catch (error) {
            showToast('Failed to revoke dealer approval.', 'error');
        }
        setDealerToRevoke(null);
        setConfirmOpen(false);
    };

    const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.checked) {
            setSelectedDealers(paginatedData.map(d => d._id));
        } else {
            setSelectedDealers([]);
        }
    };

    const handleSelectDealer = (dealerId: string, isSelected: boolean) => {
        if (isSelected) {
            setSelectedDealers(prev => [...prev, dealerId]);
        } else {
            setSelectedDealers(prev => prev.filter(id => id !== dealerId));
        }
    };

    const handleBulkActionTrigger = (action: 'approve' | 'revoke') => {
        if (!canApproveDealer || selectedDealers.length === 0) return;
        setBulkAction(action);
        setBulkConfirmOpen(true);
    };

    const handleBulkActionConfirm = async () => {
        if (!bulkAction) return;

        const isApproving = bulkAction === 'approve';
        try {
            await updateDealerStatusBulk(selectedDealers, isApproving);
            showToast(
                `${selectedDealers.length} dealer(s) ${isApproving ? 'approved' : 'approval revoked'}.`,
                isApproving ? 'success' : 'info'
            );
        } catch (error) {
            showToast('Failed to perform bulk action.', 'error');
        }

        setSelectedDealers([]);
        setBulkConfirmOpen(false);
        setBulkAction(null);
    };

    const SortIndicator = ({ columnKey }: { columnKey: SortableKey }) => {
        if (!sortConfig || sortConfig.key !== columnKey) {
            return <ChevronsUpDownIcon className="w-4 h-4 text-slate-400" />;
        }
        if (sortConfig.direction === 'ascending') {
            return <ChevronUpIcon className="w-4 h-4" />;
        }
        return <ChevronDownIcon className="w-4 h-4" />;
    };

    const requestSort = (key: SortableKey) => {
        let direction: SortDirection = 'ascending';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setSortConfig({ key, direction });
    };

    const viewDealerDetails = (dealerId: string) => {
        setActivePage('DealerDetail', { dealerId });
    };

    const handleClearFilters = () => {
        setSearchQuery('');
        setCityFilter('all');
        setStatusFilter('all');
        setReputationFilter('all');
        setCurrentPage(1);
    };

    if (isLoading) {
        return <SkeletonLoader type="table" rows={6} />;
    }

    const showActionsColumn = canUpdateDealer || canApproveDealer;

    return (
        <div id="dealers-page-content" className="space-y-6">
            <div className="flex justify-between items-center no-print">
                <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100">Manage Dealers</h2>
                <div className="flex items-center space-x-2">
                     <div className="relative hidden md:block">
                        <input 
                            type="text" 
                            placeholder="Search dealer, owner..."
                            value={searchQuery}
                            onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
                            className="pl-10 pr-4 py-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm focus:ring-primary focus:border-primary bg-white dark:bg-slate-800"
                        />
                         <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <svg className="h-5 w-5 text-slate-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg>
                        </div>
                    </div>
                     <Tooltip content="Print Current View">
                        <button onClick={() => printElementById('dealers-page-content')} className="flex items-center justify-center py-2 px-4 border border-slate-300 dark:border-slate-600 shadow-sm text-sm font-medium rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                            <PrintIcon />
                        </button>
                    </Tooltip>
                    {canCreateDealer && (
                        <button onClick={handleAddNew} className="flex items-center space-x-2 py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition-colors">
                            <PlusIcon />
                            <span className="hidden sm:inline">Add New Dealer</span>
                        </button>
                    )}
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-4 rounded-lg shadow-sm flex flex-col xl:flex-row justify-between items-stretch gap-4 no-print">
                <div className="flex flex-col md:flex-row items-stretch md:items-center gap-4 flex-wrap w-full xl:w-auto">
                    {/* Mobile Search */}
                    <div className="relative md:hidden w-full">
                        <input 
                            type="text" 
                            placeholder="Search dealer, owner..."
                            value={searchQuery}
                            onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
                            className="w-full pl-10 pr-4 py-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm focus:ring-primary focus:border-primary bg-white dark:bg-slate-800"
                        />
                         <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <svg className="h-5 w-5 text-slate-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg>
                        </div>
                    </div>

                    <div className="flex items-center w-full md:w-auto">
                        <label htmlFor="city-filter" className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">City:</label>
                        <select
                            id="city-filter"
                            value={cityFilter}
                            onChange={(e) => { setCityFilter(e.target.value); setCurrentPage(1); }}
                            className="w-full md:w-40 p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-800"
                        >
                            <option value="all">All Cities</option>
                            {uniqueCities.map(city => <option key={city} value={city}>{city}</option>)}
                        </select>
                    </div>
                    <div className="flex items-center w-full md:w-auto">
                        <label htmlFor="status-filter" className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">Status:</label>
                        <select
                            id="status-filter"
                            value={statusFilter}
                            onChange={(e) => { setStatusFilter(e.target.value as 'all' | 'approved' | 'pending'); setCurrentPage(1); }}
                            className="w-full md:w-32 p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-800"
                        >
                            <option value="all">All Statuses</option>
                            <option value="approved">Approved</option>
                            <option value="pending">Pending</option>
                        </select>
                    </div>
                     <div className="flex items-center w-full md:w-auto">
                        <label htmlFor="reputation-filter" className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">Reputation:</label>
                        <select
                            id="reputation-filter"
                            value={reputationFilter}
                            onChange={(e) => { setReputationFilter(e.target.value as any); setCurrentPage(1); }}
                            className="w-full md:w-40 p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-800"
                        >
                            <option value="all">All Scores</option>
                            <option value="excellent">Excellent (8+)</option>
                            <option value="good">Good (5-8)</option>
                            <option value="poor">Poor (&lt;5)</option>
                        </select>
                    </div>
                </div>
                <button 
                    onClick={handleClearFilters}
                    className="w-full xl:w-auto py-2 px-4 border border-slate-300 dark:border-slate-600 shadow-sm text-sm font-medium rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors shrink-0"
                >
                    Clear Filters
                </button>
            </div>

            {selectedDealers.length > 0 && canApproveDealer && (
                <div className="bg-slate-100 dark:bg-slate-800 p-3 rounded-lg shadow-sm flex items-center justify-between animate-fade-in no-print">
                    <span className="text-sm font-semibold text-slate-700 dark:text-slate-300">{selectedDealers.length} dealer(s) selected</span>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => handleBulkActionTrigger('approve')} className="px-3 py-1.5 text-xs font-medium rounded-md text-white bg-green-600 hover:bg-green-700">Approve</button>
                        <button onClick={() => handleBulkActionTrigger('revoke')} className="px-3 py-1.5 text-xs font-medium rounded-md text-white bg-red-600 hover:bg-red-700">Revoke</button>
                    </div>
                </div>
            )}

            <div className="hidden print-only">
                <h1 className="text-2xl font-bold mb-1">Dealers List</h1>
                <p className="text-sm text-slate-600 mb-4">Generated on: {new Date().toLocaleDateString()}</p>
            </div>


            <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                        <thead className="bg-slate-100/80 dark:bg-slate-700/50">
                            <tr>
                                <th className="px-4 py-3 w-12 no-print">
                                    <input
                                        ref={selectAllCheckboxRef}
                                        type="checkbox"
                                        className="h-4 w-4 rounded border-slate-300 dark:border-slate-500 text-primary focus:ring-primary bg-transparent"
                                        onChange={handleSelectAll}
                                        checked={paginatedData.length > 0 && selectedDealers.length === paginatedData.length}
                                    />
                                </th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
                                     <button onClick={() => requestSort('name')} className="flex items-center space-x-1 group">
                                        <span>Dealer</span> <SortIndicator columnKey="name" />
                                    </button>
                                </th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Contact</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Status</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
                                     <button onClick={() => requestSort('reputationScore')} className="flex items-center space-x-1 group">
                                        <span>Reputation</span> <SortIndicator columnKey="reputationScore" />
                                    </button>
                                </th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
                                    <button onClick={() => requestSort('createdAt')} className="flex items-center space-x-1 group">
                                        <span>Joined</span> <SortIndicator columnKey="createdAt" />
                                    </button>
                                </th>
                                {showActionsColumn && <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider no-print">Actions</th>}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                           {paginatedData.length > 0 ? paginatedData.map(dealer => (
                               <tr
                                   key={dealer._id}
                                   onClick={() => viewDealerDetails(dealer._id)}
                                   className={`cursor-pointer transition-colors odd:bg-slate-50 dark:odd:bg-slate-800/50 ${selectedDealers.includes(dealer._id) ? 'bg-blue-100 dark:bg-blue-900/50' : 'hover:bg-slate-100 dark:hover:bg-slate-700/50'}`}
                                >
                                    <td className="px-4 py-4 whitespace-nowrap no-print" onClick={(e) => e.stopPropagation()}>
                                        <input
                                            type="checkbox"
                                            className="h-4 w-4 rounded border-slate-300 dark:border-slate-500 text-primary focus:ring-primary bg-transparent"
                                            checked={selectedDealers.includes(dealer._id)}
                                            onChange={(e) => handleSelectDealer(dealer._id, e.target.checked)}
                                        />
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <div className="text-sm font-medium text-slate-900 dark:text-slate-100">{dealer.name}</div>
                                        <div className="text-sm text-slate-500 dark:text-slate-400">{dealer.city}</div>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <div className="text-sm font-medium text-slate-900 dark:text-slate-100">{dealer.ownerName}</div>
                                        <div className="text-sm text-slate-500 dark:text-slate-400 flex items-center gap-2">
                                            <span>{dealer.phone}</span>
                                            <a
                                                href={createWhatsAppLink(dealer.phone)}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                onClick={(e) => e.stopPropagation()}
                                                className="text-green-600 hover:text-green-700 dark:text-green-400 dark:hover:text-green-300 transition-colors"
                                                aria-label="Chat on WhatsApp"
                                            >
                                                <Tooltip content="Chat on WhatsApp">
                                                    <WhatsAppIcon className="w-5 h-5" />
                                                </Tooltip>
                                            </a>
                                        </div>
                                    </td>
                                     <td className="px-6 py-4 whitespace-nowrap">
                                        {dealer.registrationApproved
                                            ? <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300">Approved</span>
                                            : <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-yellow-100 text-yellow-800 dark:bg-yellow-900/50 dark:text-yellow-300">Pending</span>
                                        }
                                    </td>
                                     <td className="px-6 py-4 whitespace-nowrap font-semibold text-sm">
                                        <span className={dealer.reputationScore > 8 ? 'text-green-600 dark:text-green-400' : dealer.reputationScore < 5 ? 'text-red-600 dark:text-red-400' : 'text-slate-700 dark:text-slate-300'}>
                                            {dealer.reputationScore.toFixed(1)}
                                        </span>
                                    </td>
                                     <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">{new Date(dealer.createdAt).toLocaleDateString()}</td>
                                    {showActionsColumn && (
                                         <td className="px-6 py-4 whitespace-nowrap text-sm font-medium space-x-2 no-print" onClick={(e) => e.stopPropagation()}>
                                            {!dealer.registrationApproved && canApproveDealer && (
                                                <Tooltip content="Approve Registration">
                                                    <button onClick={(e) => { e.stopPropagation(); handleApprove(dealer._id); }} className="text-green-600 hover:text-green-900 dark:text-green-400 dark:hover:text-green-300 transition-colors p-1 rounded-full hover:bg-green-100 dark:hover:bg-green-900/50"><CheckCircleIcon /></button>
                                                </Tooltip>
                                            )}
                                            {dealer.registrationApproved && canApproveDealer && (
                                                <Tooltip content="Revoke Approval">
                                                    <button onClick={(e) => { e.stopPropagation(); handleRevokeClick(dealer); }} className="text-red-600 hover:text-red-900 dark:text-red-400 dark:hover:text-red-300 transition-colors p-1 rounded-full hover:bg-red-100 dark:hover:bg-red-900/50"><XCircleIcon /></button>
                                                </Tooltip>
                                            )}
                                            {canUpdateDealer && (
                                                <Tooltip content="Edit Dealer Details">
                                                    <button onClick={(e) => { e.stopPropagation(); handleEdit(dealer); }} className="text-indigo-600 hover:text-indigo-900 dark:text-indigo-400 dark:hover:text-indigo-300 transition-colors p-1 rounded-full hover:bg-indigo-100 dark:hover:bg-indigo-900/50"><EditIcon /></button>
                                                </Tooltip>
                                            )}
                                        </td>
                                    )}
                               </tr>
                           )) : (
                               <tr>
                                   <td colSpan={showActionsColumn ? 8 : 7}>
                                       <EmptyState
                                            icon={<UsersIcon className="w-10 h-10" />}
                                            title="No Dealers Found"
                                            message={searchQuery || cityFilter !== 'all' || statusFilter !== 'all' || reputationFilter !== 'all' ? "Your filters didn't match any dealers." : "Get started by adding your first dealer to the system."}
                                            action={canCreateDealer && !searchQuery ? (
                                                 <button onClick={handleAddNew} className="flex items-center space-x-2 mx-auto py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary no-print">
                                                    <PlusIcon />
                                                    <span>Create First Dealer</span>
                                                </button>
                                            ) : undefined}
                                        />
                                   </td>
                               </tr>
                           )}
                        </tbody>
                    </table>
                </div>
                 <Pagination currentPage={currentPage} totalPages={totalPages} onNext={nextPage} onPrev={prevPage} />
            </div>

            <DealerModal isOpen={isModalOpen} onClose={() => setModalOpen(false)} onSave={handleSave} dealer={selectedDealer} isSaving={isSaving} />

            <ConfirmModal
                isOpen={isConfirmOpen}
                onClose={() => setConfirmOpen(false)}
                onConfirm={handleRevokeConfirm}
                title="Revoke Dealer Approval"
                message={`Are you sure you want to revoke approval for "${dealerToRevoke?.name}"? They will lose access to the dealer portal.`}
            />

            <ConfirmModal
                isOpen={isBulkConfirmOpen}
                onClose={() => setBulkConfirmOpen(false)}
                onConfirm={handleBulkActionConfirm}
                title={`Confirm Bulk ${bulkAction === 'approve' ? 'Approval' : 'Revocation'}`}
                message={`Are you sure you want to ${bulkAction} the ${selectedDealers.length} selected dealers?`}
            />
        </div>
    );
};

export default Dealers;

import React, { useState, useMemo, useEffect } from 'react';
import type { Booking } from '../../types.ts';
import { BookingStatus } from '../../types.ts';
import { PlusIcon, DollarSignIcon, FileTextIcon, EditIcon, CalendarIcon, PrintIcon, ArchiveIcon, WhatsAppIcon, ChevronsUpDownIcon, ChevronUpIcon, ChevronDownIcon, XCircleIcon } from '../icons/Icons.tsx';
import InvoiceModal from '../modals/InvoiceModal.tsx';
import PaymentsModal from '../modals/PaymentsModal.tsx';
import BookingModal from '../modals/BookingModal.tsx';
import AllocateStockModal from '../modals/AllocateStockModal.tsx';
import { useAuth } from '../../hooks/useAuth.ts';
import { useAppContext } from '../../hooks/useAppContext.ts';
import { useData } from '../../hooks/useData.ts';
import Tooltip from '../shared/Tooltip.tsx';
import SkeletonLoader from '../shared/SkeletonLoader.tsx';
import usePagination from '../../hooks/usePagination.ts';
import Pagination from '../shared/Pagination.tsx';
import EmptyState from '../shared/EmptyState.tsx';
import { usePermissions } from '../../hooks/usePermissions.ts';
import { printElementById, createWhatsAppLink } from '../../utils/print.ts';
import ConfirmModal from '../modals/ConfirmModal.tsx';

type SortableKey = 'customerName' | 'productName' | 'dealerName' | 'bookingTimestamp';
type SortDirection = 'ascending' | 'descending';

const Bookings: React.FC<{ showToast: (message: string, type: 'success' | 'error' | 'info') => void; }> = ({ showToast }) => {
    const { bookings, products, dealers, addBooking, updateBooking, cancelBooking, isLoading } = useData();
    const { addToQueue, isOnline } = useAppContext();
    const { canCreateBooking, canUpdateBooking, canViewBookingActions, canViewInvoice } = usePermissions();

    const [isInvoiceOpen, setInvoiceOpen] = useState(false);
    const [isPaymentsOpen, setPaymentsOpen] = useState(false);
    const [isBookingModalOpen, setBookingModalOpen] = useState(false);
    const [isAllocateModalOpen, setAllocateModalOpen] = useState(false);
    const [isConfirmCancelOpen, setConfirmCancelOpen] = useState(false);
    const [bookingToCancel, setBookingToCancel] = useState<Booking | null>(null);
    const [selectedBooking, setSelectedBooking] = useState<Booking | null>(null);
    const [searchQuery, setSearchQuery] = useState('');
    const [debouncedSearchQuery, setDebouncedSearchQuery] = useState('');
    const [filterStatus, setFilterStatus] = useState<BookingStatus | 'all'>('all');
    const [dealerFilter, setDealerFilter] = useState('all');
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [sortConfig, setSortConfig] = useState<{ key: SortableKey; direction: SortDirection } | null>({ key: 'bookingTimestamp', direction: 'descending' });

    useEffect(() => {
        const timerId = setTimeout(() => {
            setDebouncedSearchQuery(searchQuery);
        }, 300);
        return () => clearTimeout(timerId);
    }, [searchQuery]);

    const findProductInfo = (variantId: string) => {
        for (const product of products) {
            const variant = product.variants.find(v => v._id === variantId);
            if (variant) {
                return { product, variant };
            }
        }
        return { product: null, variant: null };
    };

    const enrichedBookings = useMemo(() => {
        return bookings.map(b => {
            const { product, variant } = findProductInfo(b.variantId);
            const dealer = dealers.find(d => d._id === b.dealerId);
            return {
                ...b,
                productName: `${product?.brand} ${product?.modelName} ${variant?.name}`,
                dealerName: dealer?.name || 'N/A',
            };
        });
    }, [bookings, products, dealers]);


    const filteredBookings = useMemo(() => {
        const lowercasedQuery = debouncedSearchQuery.toLowerCase();

        return enrichedBookings.filter(b => {
            if (filterStatus !== 'all' && b.status !== filterStatus) return false;
            if (dealerFilter !== 'all' && b.dealerId !== dealerFilter) return false;

            const bookingDate = new Date(b.bookingTimestamp);
            if (startDate && bookingDate < new Date(startDate)) return false;
            if (endDate && bookingDate > new Date(endDate)) return false;

            if (debouncedSearchQuery) {
                return b.customerName.toLowerCase().includes(lowercasedQuery) || 
                       b.customerPhone.includes(lowercasedQuery) ||
                       b.productName.toLowerCase().includes(lowercasedQuery);
            }

            return true;
        });
    }, [enrichedBookings, filterStatus, dealerFilter, startDate, endDate, debouncedSearchQuery]);

    const sortedBookings = useMemo(() => {
        let sortableItems = [...filteredBookings];
        if (sortConfig !== null) {
            sortableItems.sort((a, b) => {
                const aValue = a[sortConfig.key];
                const bValue = b[sortConfig.key];
                if (aValue < bValue) return sortConfig.direction === 'ascending' ? -1 : 1;
                if (aValue > bValue) return sortConfig.direction === 'ascending' ? 1 : -1;
                return 0;
            });
        }
        return sortableItems;
    }, [filteredBookings, sortConfig]);

    const { paginatedData, currentPage, totalPages, nextPage, prevPage, setCurrentPage } = usePagination(sortedBookings, 10);

    const requestSort = (key: SortableKey) => {
        let direction: SortDirection = 'ascending';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setSortConfig({ key, direction });
    };

    const SortIndicator = ({ columnKey }: { columnKey: SortableKey }) => {
        if (!sortConfig || sortConfig.key !== columnKey) return <ChevronsUpDownIcon className="w-4 h-4 text-slate-400" />;
        if (sortConfig.direction === 'ascending') return <ChevronUpIcon className="w-4 h-4" />;
        return <ChevronDownIcon className="w-4 h-4" />;
    };

    const openModal = (booking: Booking, modal: 'invoice' | 'payments' | 'edit') => {
        setSelectedBooking(booking);
        if (modal === 'invoice') setInvoiceOpen(true);
        if (modal === 'payments') setPaymentsOpen(true);
        if (modal === 'edit') setBookingModalOpen(true);
    };

    const openAllocateModal = (booking: Booking) => {
        setSelectedBooking(booking);
        setAllocateModalOpen(true);
    };

    const handleCancelClick = (booking: Booking) => {
        setBookingToCancel(booking);
        setConfirmCancelOpen(true);
    };

    const handleCancelConfirm = async () => {
        if (!bookingToCancel) return;
        try {
            await cancelBooking(bookingToCancel._id);
            showToast('Booking has been cancelled.', 'success');
        } catch (error) {
            showToast('Failed to cancel booking.', 'error');
        }
        setConfirmCancelOpen(false);
        setBookingToCancel(null);
    };

    const handleAddNew = () => {
        setSelectedBooking(null);
        setBookingModalOpen(true);
    };

    const getStatusColor = (status: BookingStatus) => {
        switch (status) {
            case BookingStatus.Pending: return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/50 dark:text-yellow-300';
            case BookingStatus.Allocated: return 'bg-blue-100 text-blue-800 dark:bg-blue-900/50 dark:text-blue-300';
            case BookingStatus.Delivered: return 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300';
            case BookingStatus.Cancelled: return 'bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-300';
            default: return 'bg-slate-100 text-slate-800 dark:bg-slate-700 dark:text-slate-300';
        }
    };

    const getStatusTooltip = (status: BookingStatus) => {
        switch (status) {
            case BookingStatus.Pending: return 'Awaiting vehicle allocation from stock.';
            case BookingStatus.Allocated: return 'Vehicle allocated, pending delivery.';
            case BookingStatus.Delivered: return 'Vehicle has been delivered to the customer.';
            case BookingStatus.Cancelled: return 'This booking has been cancelled.';
            default: return '';
        }
    };

    const getPaymentStatusInfo = (booking: Booking): { text: string; color: string; } => {
        const { variant } = findProductInfo(booking.variantId);
        const variantPrice = variant?.price ?? 0;
        const totalPaid = booking.payments.reduce((sum, p) => sum + p.amount, 0);

        if (totalPaid <= 0) {
            return { text: 'Unpaid', color: 'bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-300' };
        } else if (totalPaid >= variantPrice) {
            return { text: 'Paid', color: 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300' };
        } else {
            return { text: 'Partial', color: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/50 dark:text-yellow-300' };
        }
    };

    const handleSaveBooking = async (bookingData: Omit<Booking, '_id' | 'bookingTimestamp' | 'payments' | 'stockItemId'>, isEditing: boolean) => {
        if (isEditing && selectedBooking) {
            const updatedBookingData = { ...selectedBooking, ...bookingData };
            if (isOnline) {
                await updateBooking(updatedBookingData);
            } else {
                 addToQueue({ type: 'UPDATE_BOOKING', payload: updatedBookingData, timestamp: Date.now() });
            }
            showToast('Booking updated successfully!', 'success');
        } else {
             if (isOnline) {
                await addBooking(bookingData);
                showToast('New booking created!', 'success');
             } else {
                addToQueue({ type: 'ADD_BOOKING', payload: bookingData, timestamp: Date.now() });
                showToast('You are offline. Booking added to sync queue.', 'info');
             }
        }
        setBookingModalOpen(false);
    };

    const handleClearFilters = () => {
        setSearchQuery('');
        setFilterStatus('all');
        setDealerFilter('all');
        setStartDate('');
        setEndDate('');
    };

    if (isLoading) {
        return <SkeletonLoader type="table" rows={6} />;
    }

    return (
        <div id="bookings-page-content" className="space-y-6">
            <div className="flex justify-between items-center no-print">
                <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100">Manage Bookings</h2>
                <div className="flex items-center space-x-2">
                    <Tooltip content="Print Current View">
                        <button onClick={() => printElementById('bookings-page-content')} className="flex items-center justify-center py-2 px-4 border border-slate-300 dark:border-slate-600 shadow-sm text-sm font-medium rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                            <PrintIcon />
                        </button>
                    </Tooltip>
                    {canCreateBooking && (
                        <button onClick={handleAddNew} className="flex items-center space-x-2 py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition-colors">
                            <PlusIcon />
                            <span>New Booking</span>
                        </button>
                    )}
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-4 rounded-lg shadow-sm flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4 no-print">
                <div className="flex flex-col md:flex-row items-stretch md:items-center gap-4 flex-wrap w-full xl:w-auto">
                    <div className="relative w-full md:w-64">
                        <input type="text" placeholder="Search customer, phone, product..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="p-2 pl-10 border border-slate-300 rounded-md shadow-sm w-full" />
                         <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <svg className="h-5 w-5 text-slate-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 md:flex md:items-center gap-4 w-full md:w-auto">
                         <div className="flex items-center">
                            <label className="text-sm font-medium text-slate-600 mr-2 shrink-0">Status:</label>
                            <select value={filterStatus} onChange={(e) => { setFilterStatus(e.target.value as BookingStatus | 'all'); setCurrentPage(1); }} className="p-2 border border-slate-300 rounded-md shadow-sm text-sm w-full md:w-32">
                                <option value="all">All</option>
                                {Object.values(BookingStatus).map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                        </div>
                         <div className="flex items-center">
                            <label className="text-sm font-medium text-slate-600 mr-2 shrink-0">Dealer:</label>
                            <select value={dealerFilter} onChange={(e) => { setDealerFilter(e.target.value); setCurrentPage(1); }} className="p-2 border border-slate-300 rounded-md shadow-sm text-sm w-full md:w-40">
                                <option value="all">All</option>
                                {dealers.map(d => <option key={d._id} value={d._id}>{d.name}</option>)}
                            </select>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 md:flex md:items-center gap-4 w-full md:w-auto">
                         <div className="flex items-center">
                            <label className="text-sm font-medium text-slate-600 mr-2 shrink-0">From:</label>
                            <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="p-2 border border-slate-300 rounded-md shadow-sm text-sm w-full" />
                        </div>
                         <div className="flex items-center">
                            <label className="text-sm font-medium text-slate-600 mr-2 shrink-0">To:</label>
                            <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="p-2 border border-slate-300 rounded-md shadow-sm text-sm w-full" />
                        </div>
                    </div>
                </div>
                 <button onClick={handleClearFilters} className="w-full xl:w-auto py-2 px-4 border border-slate-300 shadow-sm text-sm font-medium rounded-md text-slate-700 bg-white hover:bg-slate-50 transition-colors shrink-0">
                    Clear Filters
                </button>
            </div>


            <div className="hidden print-only">
                <h1 className="text-2xl font-bold mb-1">Bookings Report</h1>
                <p className="text-sm text-slate-600 mb-4">
                    Filter: Status ({filterStatus}) | Generated on: {new Date().toLocaleDateString()}
                </p>
            </div>

            <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                        <thead className="bg-slate-100/80 dark:bg-slate-700/50">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider"><button onClick={() => requestSort('customerName')} className="flex items-center space-x-1"><span>Customer</span><SortIndicator columnKey="customerName"/></button></th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider"><button onClick={() => requestSort('productName')} className="flex items-center space-x-1"><span>Product</span><SortIndicator columnKey="productName"/></button></th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider"><button onClick={() => requestSort('dealerName')} className="flex items-center space-x-1"><span>Dealer</span><SortIndicator columnKey="dealerName"/></button></th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider"><button onClick={() => requestSort('bookingTimestamp')} className="flex items-center space-x-1"><span>Date</span><SortIndicator columnKey="bookingTimestamp"/></button></th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Booking Status</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Payment Status</th>
                                {canViewBookingActions && <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider no-print">Actions</th>}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                            {paginatedData.length > 0 ? paginatedData.map(booking => {
                                const { product, variant } = findProductInfo(booking.variantId);
                                const dealer = dealers.find(d => d._id === booking.dealerId);
                                const paymentStatus = getPaymentStatusInfo(booking);
                                const prefilledMessage = `Hi ${dealer?.name}, regarding Booking ID: #${booking._id.slice(-6)} for customer ${booking.customerName}.`;
                                return (
                                    <tr key={booking._id} className="odd:bg-slate-50 dark:odd:bg-slate-800/50 hover:bg-slate-100 dark:hover:bg-slate-700/50 transition-colors">
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm font-medium text-slate-900 dark:text-slate-100">{booking.customerName}</div>
                                            <div className="text-sm text-slate-500 dark:text-slate-400">{booking.customerPhone}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm font-medium text-slate-900 dark:text-slate-100">{product?.brand} {product?.modelName}</div>
                                            <div className="text-sm text-slate-500 dark:text-slate-400">{variant?.name}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">{dealer?.name}</td>
                                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">{new Date(booking.bookingTimestamp).toLocaleDateString()}</td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <Tooltip content={getStatusTooltip(booking.status)}>
                                                <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full capitalize ${getStatusColor(booking.status)}`}>
                                                    {booking.status}
                                                </span>
                                            </Tooltip>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full capitalize ${paymentStatus.color}`}>
                                                {paymentStatus.text}
                                            </span>
                                        </td>
                                        {canViewBookingActions && (
                                            <td className="px-6 py-4 whitespace-nowrap text-sm font-medium space-x-2 no-print">
                                                {booking.status === BookingStatus.Pending && canUpdateBooking && (
                                                    <Tooltip content="Allocate Stock">
                                                        <button onClick={() => openAllocateModal(booking)} className="text-cyan-600 hover:text-cyan-900 dark:text-cyan-400 dark:hover:text-cyan-300 transition-colors p-1 rounded-full hover:bg-cyan-100 dark:hover:bg-cyan-900/50"><ArchiveIcon /></button>
                                                    </Tooltip>
                                                )}
                                                {canUpdateBooking && (
                                                    <>
                                                        <Tooltip content="Edit Booking">
                                                            <button onClick={() => openModal(booking, 'edit')} className="text-indigo-600 hover:text-indigo-900 dark:text-indigo-400 dark:hover:text-indigo-300 transition-colors p-1 rounded-full hover:bg-indigo-100 dark:hover:bg-indigo-900/50"><EditIcon /></button>
                                                        </Tooltip>
                                                        <Tooltip content="Manage Payments">
                                                            <button onClick={() => openModal(booking, 'payments')} className="text-green-600 hover:text-green-900 dark:text-green-400 dark:hover:text-green-300 transition-colors p-1 rounded-full hover:bg-green-100 dark:hover:bg-green-900/50"><DollarSignIcon /></button>
                                                        </Tooltip>
                                                    </>
                                                )}
                                                {booking.status !== BookingStatus.Cancelled && booking.status !== BookingStatus.Delivered && canUpdateBooking && (
                                                    <Tooltip content="Cancel Booking">
                                                        <button onClick={() => handleCancelClick(booking)} className="text-red-600 hover:text-red-900 dark:text-red-400 dark:hover:text-red-300 transition-colors p-1 rounded-full hover:bg-red-100 dark:hover:bg-red-900/50"><XCircleIcon /></button>
                                                    </Tooltip>
                                                )}
                                                {canViewInvoice && (
                                                    <Tooltip content="View Invoice">
                                                        <button onClick={() => openModal(booking, 'invoice')} className="text-blue-600 hover:text-blue-900 dark:text-blue-400 dark:hover:text-blue-300 transition-colors p-1 rounded-full hover:bg-blue-100 dark:hover:bg-blue-900/50"><FileTextIcon /></button>
                                                    </Tooltip>
                                                )}
                                                <Tooltip content="Contact Dealer on WhatsApp">
                                                    <a 
                                                        href={createWhatsAppLink(dealer?.phone || '', prefilledMessage)}
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="text-green-600 hover:text-green-900 dark:text-green-400 dark:hover:text-green-300 transition-colors p-1 rounded-full hover:bg-green-100 dark:hover:bg-green-900/50 inline-block"
                                                    >
                                                        <WhatsAppIcon />
                                                    </a>
                                                </Tooltip>
                                            </td>
                                        )}
                                    </tr>
                                );
                            }) : (
                                <tr>
                                    <td colSpan={canViewBookingActions ? 7 : 6}>
                                        <EmptyState
                                            icon={<CalendarIcon className="w-10 h-10" />}
                                            title="No Bookings Found"
                                            message={filterStatus !== 'all' || dealerFilter !== 'all' || searchQuery ? "Your filters didn't match any bookings." : "There are no customer bookings in the system yet."}
                                            action={canCreateBooking && filterStatus === 'all' && !searchQuery ? (
                                                 <button onClick={handleAddNew} className="flex items-center space-x-2 mx-auto py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary no-print">
                                                    <PlusIcon />
                                                    <span>Create First Booking</span>
                                                </button>
                                            ) : undefined}
                                        />
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
                 <Pagination currentPage={currentPage} totalPages={totalPages} onNext={nextPage} onPrev={prevPage} />
            </div>

            <InvoiceModal isOpen={isInvoiceOpen} onClose={() => setInvoiceOpen(false)} booking={selectedBooking} />
            <PaymentsModal isOpen={isPaymentsOpen} onClose={() => setPaymentsOpen(false)} booking={selectedBooking} showToast={showToast} />
            <BookingModal isOpen={isBookingModalOpen} onClose={() => setBookingModalOpen(false)} onSave={handleSaveBooking} booking={selectedBooking} />
            <AllocateStockModal isOpen={isAllocateModalOpen} onClose={() => setAllocateModalOpen(false)} booking={selectedBooking} showToast={showToast} />
            <ConfirmModal
                isOpen={isConfirmCancelOpen}
                onClose={() => setConfirmCancelOpen(false)}
                onConfirm={handleCancelConfirm}
                title="Cancel Booking"
                message={`Are you sure you want to cancel the booking for "${bookingToCancel?.customerName}"? Any reserved stock will be made available again.`}
            />
        </div>
    );
};

