    const handleExport = () => {
        const flattenedData = sortedProducts.flatMap(p => 
            p.variants.map(v => ({
                brand: p.brand,
                modelName: p.modelName,
                variantName: v.name,
                color: v.color,
                sku: v.sku,
                price: v.price,
                engine: p.specifications.engine,
                mileage: p.specifications.mileage,
            }))
