                            <select value={userFilter} onChange={(e) => { setUserFilter(e.target.value); setCurrentPage(1); }} className="w-full sm:w-40 p-2 border border-slate-300 rounded-md shadow-sm text-sm">
                                <option value="all">All</option>
                                {users.map(u => <option key={u._id} value={u._id}>{u.name}</option>)}
                            </select>
                        </div>
                        <div className="flex items-center w-full sm:w-auto">
                            <label className="text-sm font-medium text-slate-600 mr-2 shrink-0">Action:</label>
                            <select value={actionFilter} onChange={(e) => { setActionFilter(e.target.value); setCurrentPage(1); }} className="w-full sm:w-32 p-2 border border-slate-300 rounded-md shadow-sm text-sm">
                                <option value="all">All</option>
                                {Object.values(ActionType).map(a => <option key={a} value={a}>{a}</option>)}
                            </select>
                        </div>
                    </div>
                    <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
                         <div className="flex items-center w-full sm:w-auto">
                            <label className="text-sm font-medium text-slate-600 mr-2 shrink-0">From:</label>
                            <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full sm:w-auto p-2 border border-slate-300 rounded-md shadow-sm text-sm" />
                        </div>
                         <div className="flex items-center w-full sm:w-auto">
                            <label className="text-sm font-medium text-slate-600 mr-2 shrink-0">To:</label>
                            <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="w-full sm:w-auto p-2 border border-slate-300 rounded-md shadow-sm text-sm" />
                        </div>
                    </div>
                 </div>
                <div className="flex items-center gap-2 w-full xl:w-auto justify-end">
                    <button onClick={handleClearFilters} className="py-2 px-4 border border-slate-300 shadow-sm text-sm font-medium rounded-md text-slate-700 bg-white hover:bg-slate-50 transition-colors">
                        Clear Filters
                    </button>
                    <Tooltip content="Print Current View">
                        <button onClick={() => printElementById('audit-logs-page-content')} className="flex items-center justify-center py-2 px-4 border border-slate-300 shadow-sm text-sm font-medium rounded-md text-slate-700 bg-white hover:bg-slate-50 transition-colors">
                            <PrintIcon />
                        </button>
                    </Tooltip>
                </div>
            </div>

             <div className="hidden print-only">
                <h1 className="text-2xl font-bold mb-1">Audit Log Report</h1>
                <p className="text-sm text-slate-600 mb-4">
                    Filters: User ({userFilter === 'all' ? 'All' : users.find(u => u._id === userFilter)?.name}), Action ({actionFilter})
                    | Generated on: {new Date().toLocaleDateString()}
                </p>
            </div>

            <div className="bg-white rounded-lg shadow-md overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">User</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Action</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Details</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Timestamp</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {paginatedData.length > 0 ? paginatedData.map(log => (
                                <tr key={log._id}>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <div className="text-sm font-medium text-gray-900">{usersById[log.userId]?.name || log.userId}</div>
                                        <div className="text-sm">
                                            <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full capitalize ${getRoleColor(log.userRole)}`}>
                                                {log.userRole}
                                            </span>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <span className={`text-sm font-semibold capitalize ${getActionColor(log.action)}`}>{log.action}</span>
                                    </td>
                                    <td className="px-6 py-4 whitespace-normal text-sm text-gray-600 max-w-md">
                                        {log.changes || `Performed action on ${log.targetCollection || 'system'}${log.targetId ? ` (${log.targetId})` : ''}`}
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{new Date(log.timestamp).toLocaleString()}</td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan={4}>
                                        <EmptyState
                                            icon={<FileSearchIcon className="w-10 h-10" />}
                                            title="No Logs Found"
                                            message="There are no audit logs matching your current filter criteria."
                                        />
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
                <Pagination currentPage={currentPage} totalPages={totalPages} onNext={nextPage} onPrev={prevPage} />
            </div>
        </div>
    );
};

export default AuditLogs;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { StockStatus, StockItem, Product } from '../../types.ts';
import { useData } from '../../hooks/useData.ts';
import usePagination from '../../hooks/usePagination.ts';
import Pagination from '../shared/Pagination.tsx';
import EmptyState from '../shared/EmptyState.tsx';
import { ArchiveIcon, PrintIcon, FileSearchIcon, ChevronDownIcon, ChevronUpIcon, ChevronsUpDownIcon, PlusIcon, ListIcon, GridIcon, XCircleIcon } from '../icons/Icons.tsx';
import Tooltip from '../shared/Tooltip.tsx';
import { printElementById } from '../../utils/print.ts';
import StockItemDetailModal from '../modals/StockItemDetailModal.tsx';
import StockModal from '../modals/StockModal.tsx';

interface StockProps {
    stockView: 'central' | 'dealer';
    showToast: (message: string, type: 'success' | 'error' | 'info') => void;
    initialState?: any;
    onInitialStateConsumed: () => void;
}

type SortableKey = 'vin' | 'productName' | 'holderName' | 'status' | 'assignedAt' | 'price';
type SortDirection = 'ascending' | 'descending';
type ViewMode = 'list' | 'grid';

const StockCard: React.FC<{ item: any; onSelect: (id: string, checked: boolean) => void; isSelected: boolean; onViewDetails: (item: StockItem) => void; }> = ({ item, onSelect, isSelected, onViewDetails }) => {
    const getStatusColor = (status: StockStatus) => {
        switch (status) {
            case StockStatus.Available: return 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300 border-green-200';
            case StockStatus.Reserved: return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/50 dark:text-yellow-300 border-yellow-200';
            case StockStatus.Sold: return 'bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-300 border-red-200';
            default: return 'bg-slate-100 text-slate-800 dark:bg-slate-700 dark:text-slate-300 border-slate-200';
        }
    };

    return (
        <div className={`bg-white dark:bg-slate-800 rounded-lg shadow-sm border dark:border-slate-700 transition-all relative ${isSelected ? 'border-primary shadow-lg' : 'border-slate-200 hover:shadow-md'}`}>
            <div className="absolute top-2 right-2 no-print">
                 <input
                    type="checkbox"
                    className="h-5 w-5 rounded border-slate-300 dark:border-slate-500 text-primary focus:ring-primary bg-transparent"
                    checked={isSelected}
                    onChange={(e) => onSelect(item._id, e.target.checked)}
                />
            </div>
            <div className="p-4 cursor-pointer" onClick={() => onViewDetails(item)}>
                <p className="font-mono text-sm font-bold text-primary truncate">{item.vin}</p>
                <p className="text-base font-semibold text-slate-800 dark:text-slate-100 mt-1 truncate">{item.productName}</p>
                <p className="text-xs text-slate-500 dark:text-slate-400">{item.holderName}</p>
                <div className="flex justify-between items-end mt-3">
                    <span className={`px-2 py-0.5 inline-flex text-xs leading-5 font-semibold rounded-full capitalize border ${getStatusColor(item.status)}`}>
                        {item.status}
                    </span>
                    <p className="text-lg font-bold text-slate-800 dark:text-slate-200">
                        <span className="text-xs font-normal text-slate-500 dark:text-slate-400">Rs. </span>
                        {item.price.toLocaleString()}
                    </p>
                </div>
            </div>
        </div>
    )
}


const Stock: React.FC<StockProps> = ({ stockView, showToast, initialState, onInitialStateConsumed }) => {
    const { stock, products, dealers, updateStockStatusBulk, addStock } = useData();

    const [categoryFilter, setCategoryFilter] = useState<string>('All'); // This will be modelName
    const [variantFilter, setVariantFilter] = useState<string>('all'); // This will be variant name like NA-70cc

    const [filterStatus, setFilterStatus] = useState<StockStatus | 'all'>('all');
    const [filterDealer, setFilterDealer] = useState<string>('all');
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [searchQuery, setSearchQuery] = useState('');
    const [debouncedSearchQuery, setDebouncedSearchQuery] = useState('');
    const [selectedStock, setSelectedStock] = useState<string[]>([]);
    const [isDetailModalOpen, setDetailModalOpen] = useState(false);
    const [isAddModalOpen, setAddModalOpen] = useState(false);
    const [selectedStockItem, setSelectedStockItem] = useState<StockItem | null>(null);
    const [sortConfig, setSortConfig] = useState<{ key: SortableKey; direction: SortDirection } | null>({ key: 'assignedAt', direction: 'descending' });
    const [viewMode, setViewMode] = useState<ViewMode>('grid');

    useEffect(() => {
        if (initialState?.status) {
            setFilterStatus(initialState.status);
            onInitialStateConsumed();
        }
    }, [initialState, onInitialStateConsumed]);

    useEffect(() => {
        const timerId = setTimeout(() => {
            setDebouncedSearchQuery(searchQuery);
        }, 300);
        return () => clearTimeout(timerId);
    }, [searchQuery]);

    const findProductInfo = (variantId: string) => {
        for (const product of products) {
            const variant = product.variants.find(v => v._id === variantId);
            if (variant) return { product, variant };
        }
        return { product: null, variant: null };
    };

    const enrichedStock = useMemo(() => {
        return stock.map(item => {
             const { product, variant } = findProductInfo(item.variantId);
             const holderName = dealers.find(d => d._id === item.dealerId)?.name || 'Company Stock';
             return { 
                ...item, 
                productName: `${product?.modelName || ''} (${variant?.name || ''} - ${variant?.color || ''})`,
                productId: product?._id,
                productModelName: product?.modelName,
                variantName: variant?.name,
                holderName: holderName,
                price: variant?.price || 0,
            };
        });
    }, [stock, products, dealers]);

    const productCategories = useMemo(() => ['All', ...new Set(products.map(p => p.modelName))], [products]);

    const variantsForCategory = useMemo(() => {
        if (categoryFilter === 'all' || categoryFilter === 'All') return [];
        const product = products.find(p => p.modelName === categoryFilter);
        return product ? [...new Set(product.variants.map(v => v.name))] : [];
    }, [categoryFilter, products]);

    useEffect(() => {
        setVariantFilter('all');
    }, [categoryFilter]);

    const filteredStock = useMemo(() => {
        const lowercasedQuery = debouncedSearchQuery.toLowerCase();

        return enrichedStock.filter(item => {
            const viewMatch = stockView === 'central' ? item.dealerId === null : item.dealerId !== null;
            if (!viewMatch) return false;

            const categoryMatch = categoryFilter === 'All' || item.productModelName === categoryFilter;
            if (!categoryMatch) return false;

            const variantMatch = variantFilter === 'all' || item.variantName === variantFilter;
            if (!variantMatch) return false;

            const statusMatch = filterStatus === 'all' || item.status === filterStatus;
            const dealerMatch = stockView === 'central' || filterDealer === 'all' || item.dealerId === filterDealer;

            const itemDate = new Date(item.assignedAt);
            const startMatch = !startDate || itemDate >= new Date(startDate);
            const endMatch = !endDate || itemDate <= new Date(endDate);

            if (!statusMatch || !dealerMatch || !startMatch || !endMatch) return false;

            if (lowercasedQuery) {
                const vinMatch = item.vin.toLowerCase().includes(lowercasedQuery);
                const productMatchQuery = item.productName.toLowerCase().includes(lowercasedQuery);
                const holderMatch = item.holderName.toLowerCase().includes(lowercasedQuery);
                return vinMatch || productMatchQuery || holderMatch;
            }
            return true;
        });
    }, [enrichedStock, stockView, categoryFilter, variantFilter, filterStatus, filterDealer, startDate, endDate, debouncedSearchQuery, products]);

    const sortedStock = useMemo(() => {
        let sortableItems = [...filteredStock];
        if (sortConfig !== null && viewMode === 'list') {
            sortableItems.sort((a, b) => {
                let aValue = a[sortConfig.key];
                let bValue = b[sortConfig.key];
                if (aValue < bValue) return sortConfig.direction === 'ascending' ? -1 : 1;
                if (aValue > bValue) return sortConfig.direction === 'ascending' ? 1 : -1;
                return 0;
            });
        }
        return sortableItems;
    }, [filteredStock, sortConfig, viewMode]);

    const { paginatedData, currentPage, totalPages, nextPage, prevPage, setCurrentPage } = usePagination(sortedStock, viewMode === 'grid' ? 12 : 10);

    const summaryStats = useMemo(() => ({
        count: filteredStock.length,
        value: filteredStock.reduce((sum, item) => sum + item.price, 0)
    }), [filteredStock]);

    useEffect(() => {
        setSelectedStock([]);
        setCurrentPage(1);
    }, [stockView, categoryFilter, variantFilter, filterStatus, filterDealer, startDate, endDate, debouncedSearchQuery, sortConfig, viewMode, setCurrentPage]);

    const handleViewDetails = (item: StockItem) => {
        setSelectedStockItem(item);
        setDetailModalOpen(true);
    };

    const handleSaveStockItem = async (stockData: Omit<StockItem, '_id' | 'assignedAt'>) => {
        try {
            await addStock(stockData);
            showToast('New stock item added!', 'success');
            setAddModalOpen(false);
        } catch {
            showToast('Failed to add stock item.', 'error');
        }
    };

    const handleClearFilters = () => {
        setFilterStatus('all');
        setFilterDealer('all');
        setCategoryFilter('All');
        setVariantFilter('all');
        setStartDate('');
        setEndDate('');
        setSearchQuery('');
    };

    const requestSort = (key: SortableKey) => {
        let direction: SortDirection = 'ascending';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setSortConfig({ key, direction });
    };

    const SortIndicator = ({ columnKey }: { columnKey: SortableKey }) => {
        if (!sortConfig || sortConfig.key !== columnKey) return <ChevronsUpDownIcon className="w-4 h-4 text-slate-400" />;
        if (sortConfig.direction === 'ascending') return <ChevronUpIcon className="w-4 h-4" />;
        return <ChevronDownIcon className="w-4 h-4" />;
    };

    const handleSelectStock = (stockId: string, isSelected: boolean) => {
        if (isSelected) setSelectedStock(prev => [...prev, stockId]);
        else setSelectedStock(prev => prev.filter(id => id !== stockId));
    };

    const handleBulkStatusChange = async (status: StockStatus) => {
        if (selectedStock.length === 0) return;
        await updateStockStatusBulk(selectedStock, status);
        showToast(`${selectedStock.length} items updated to '${status}'.`, 'success');
        setSelectedStock([]);
    };

    return (
        <div id="stock-page-content" className="space-y-6">
            <div className="flex justify-between items-center">
                    <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100">
                        {stockView === 'central' ? 'Company Stock' : 'Dealer Stock'}
                    </h2>
                    <div className="flex items-center space-x-2 no-print">
                         <div className="flex items-center space-x-1 p-1 bg-slate-200 dark:bg-slate-700 rounded-lg">
                            <Tooltip content="List View"><button onClick={() => setViewMode('list')} className={`p-1.5 rounded-md ${viewMode === 'list' ? 'bg-white dark:bg-slate-600 text-primary shadow' : 'text-slate-500'}`}><ListIcon/></button></Tooltip>
                            <Tooltip content="Grid View"><button onClick={() => setViewMode('grid')} className={`p-1.5 rounded-md ${viewMode === 'grid' ? 'bg-white dark:bg-slate-600 text-primary shadow' : 'text-slate-500'}`}><GridIcon/></button></Tooltip>
                        </div>
                        {stockView === 'central' && (
                            <button onClick={() => setAddModalOpen(true)} className="flex items-center space-x-2 py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary">
                                <PlusIcon /><span>Add Stock</span>
                            </button>
                        )}
                    </div>
                </div>

                <div className="space-y-4 no-print">
                    <div className="flex space-x-1 p-1 bg-slate-100 dark:bg-slate-700 rounded-lg overflow-x-auto">
                        {productCategories.map(cat => <button key={cat} onClick={() => setCategoryFilter(cat)} className={`w-full text-center px-3 py-1.5 text-sm font-semibold rounded-md transition-colors ${categoryFilter === cat ? 'bg-white dark:bg-slate-600 shadow-sm text-primary' : 'text-slate-500 dark:text-slate-300 hover:bg-white/50'}`}>{cat}</button>)}
                    </div>
                    {variantsForCategory.length > 0 && (
                        <div className="flex items-center gap-2 overflow-x-auto animate-fade-in pb-2">
                            <span className="text-xs font-semibold text-slate-500 dark:text-slate-400 shrink-0">Models:</span>
                            <button 
                                onClick={() => setVariantFilter('all')} 
                                className={`px-3 py-1 text-xs font-medium rounded-md transition-colors ${variantFilter === 'all' 
                                    ? 'bg-primary text-white shadow' 
                                    : 'bg-white dark:bg-slate-700 text-slate-600 dark:text-slate-200 border border-slate-300 dark:border-slate-600 hover:bg-slate-50'
                                }`}
                            >
                                All
                            </button>
                            {variantsForCategory.map(variantName => (
                                <button 
                                    key={variantName} 
                                    onClick={() => setVariantFilter(variantName)} 
                                    className={`px-3 py-1 text-xs font-medium rounded-md transition-colors whitespace-nowrap ${variantFilter === variantName 
                                        ? 'bg-primary text-white shadow' 
                                        : 'bg-white dark:bg-slate-700 text-slate-600 dark:text-slate-200 border border-slate-300 dark:border-slate-600 hover:bg-slate-50'
                                    }`}
                                >
                                    {variantName}
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                <div className="bg-white dark:bg-slate-800 p-4 rounded-lg shadow-sm flex flex-col xl:flex-row items-stretch xl:items-center justify-between gap-4 no-print">
                    <div className="flex flex-col md:flex-row items-stretch md:items-center gap-4 flex-wrap w-full xl:w-auto">
                        <div className="relative w-full md:w-auto">
                            <input id="stock-search" type="text" placeholder="Search VIN, product..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full md:w-64 p-2 pl-10 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-700" />
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none"><svg className="h-5 w-5 text-slate-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg></div>
                        </div>
                        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
                             <div className="w-full sm:w-auto">
                                 <label htmlFor="status-filter" className="sr-only">Status</label>
                                 <select id="status-filter" value={filterStatus} onChange={(e) => setFilterStatus(e.target.value as any)} className="w-full p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-700">
                                     <option value="all">All Statuses</option>
                                     {Object.values(StockStatus).map(s => <option key={s} value={s}>{s}</option>)}
                                 </select>
                            </div>
                            {stockView === 'dealer' && (
                                 <div className="w-full sm:w-auto">
                                    <label htmlFor="dealer-filter" className="sr-only">Dealer</label>
                                    <select id="dealer-filter" value={filterDealer} onChange={(e) => setFilterDealer(e.target.value)} className="w-full p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-700">
                                        <option value="all">All Dealers</option>
                                        {dealers.map(d => <option key={d._id} value={d._id}>{d.name}</option>)}
                                    </select>
                                </div>
                            )}
                        </div>
                        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
                            <div className="w-full sm:w-auto">
                                <label htmlFor="start-date" className="sr-only">Start Date</label>
                                <input id="start-date" type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full p-2 border border-slate-300 dark:border-slate-600 rounded-md text-sm bg-white dark:bg-slate-700" placeholder="From" />
                            </div>
                             <div className="w-full sm:w-auto">
                                <label htmlFor="end-date" className="sr-only">End Date</label>
                                <input id="end-date" type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="w-full p-2 border border-slate-300 dark:border-slate-600 rounded-md text-sm bg-white dark:bg-slate-700" placeholder="To" />
                            </div>
                        </div>
                    </div>
                     <button onClick={handleClearFilters} className="w-full xl:w-auto py-2 px-4 border border-slate-300 dark:border-slate-600 shadow-sm text-sm font-medium rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors shrink-0">Clear Filters</button>
                </div>

                 {selectedStock.length > 0 && (
                    <div className="bg-slate-100 dark:bg-slate-800 p-3 rounded-lg shadow-sm flex items-center justify-between animate-fade-in no-print sticky top-6 z-10">
                        <span className="text-sm font-semibold text-slate-700 dark:text-slate-300">{selectedStock.length} item(s) selected</span>
                        <div className="flex items-center space-x-2">
                            <span className="text-sm font-medium text-slate-600 dark:text-slate-400">Set status to:</span>
                            <button onClick={() => handleBulkStatusChange(StockStatus.Available)} className="px-3 py-1.5 text-xs font-medium rounded-md text-white bg-green-600 hover:bg-green-700">Available</button>
                            <button onClick={() => handleBulkStatusChange(StockStatus.Reserved)} className="px-3 py-1.5 text-xs font-medium rounded-md text-white bg-yellow-600 hover:bg-yellow-700">Reserved</button>
                            <button onClick={() => handleBulkStatusChange(StockStatus.Sold)} className="px-3 py-1.5 text-xs font-medium rounded-md text-white bg-red-600 hover:bg-red-700">Sold</button>
                        </div>
                    </div>
                )}
                {paginatedData.length > 0 ? (
                    viewMode === 'list' ? (
                    <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm overflow-hidden">
                        <div className="overflow-x-auto">
                            <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                                <thead className="bg-slate-100/80 dark:bg-slate-700/50">
                                    <tr>
                                        <th className="px-4 py-3 w-12 no-print"><input type="checkbox" onChange={(e) => setSelectedStock(e.target.checked ? paginatedData.map(i => i._id) : [])} className="h-4 w-4 rounded border-slate-300 dark:border-slate-500 text-primary" /></th>
                                        {(['vin', 'productName', 'price', 'holderName', 'status', 'assignedAt'] as SortableKey[]).map(key => (<th key={key} className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider"><button onClick={() => requestSort(key)} className="flex items-center space-x-1 group"><span>{key.replace('Name', ' ').replace('At', '')}</span> <SortIndicator columnKey={key} /></button></th>))}
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                                    {paginatedData.map(item => (<tr key={item._id} className={`transition-colors ${selectedStock.includes(item._id) ? 'bg-blue-50 dark:bg-blue-900/20' : 'hover:bg-slate-50 dark:hover:bg-slate-700/50'}`}>
                                        <td className="px-4 py-4 no-print"><input type="checkbox" checked={selectedStock.includes(item._id)} onChange={(e) => handleSelectStock(item._id, e.target.checked)} className="h-4 w-4 rounded" /></td>
                                        <td className="px-6 py-4 cursor-pointer" onClick={() => handleViewDetails(item)}><span className="font-mono text-slate-600 dark:text-slate-400">{item.vin}</span></td>
                                        <td className="px-6 py-4 font-medium text-slate-800 dark:text-slate-200">{item.productName}</td>
                                        <td className="px-6 py-4">Rs. {item.price.toLocaleString()}</td>
                                        <td className="px-6 py-4">{item.holderName}</td>
                                        <td className="px-6 py-4"><span className={`px-2 py-0.5 inline-flex text-xs font-semibold rounded-full capitalize ${getStatusColor(item.status)}`}>{item.status}</span></td>
                                        <td className="px-6 py-4 text-slate-500 dark:text-slate-400">{new Date(item.assignedAt).toLocaleDateString()}</td>
                                    </tr>))}
                                </tbody>
                            </table>
                        </div>
                    </div>) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                        {paginatedData.map(item => (<StockCard key={item._id} item={item} onSelect={handleSelectStock} isSelected={selectedStock.includes(item._id)} onViewDetails={handleViewDetails} />))}
                    </div>)) : (
                    <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm"><EmptyState icon={<ArchiveIcon className="w-10 h-10" />} title="No Stock Items Found" message="Your search or filter criteria did not match any stock items." /></div>
                )}
                <Pagination currentPage={currentPage} totalPages={totalPages} onNext={nextPage} onPrev={prevPage} />

            <StockItemDetailModal isOpen={isDetailModalOpen} onClose={() => setDetailModalOpen(false)} item={selectedStockItem} />
            <StockModal isOpen={isAddModalOpen} onClose={() => setAddModalOpen(false)} onSave={handleSaveStockItem} showToast={showToast} />
        </div>
    );
};

export default Stock;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { StockStatus, StockItem, Product } from '../../types.ts';
import { useData } from '../../hooks/useData.ts';
import usePagination from '../../hooks/usePagination.ts';
import Pagination from '../shared/Pagination.tsx';
import EmptyState from '../shared/EmptyState.tsx';
import { ArchiveIcon, PrintIcon, FileSearchIcon, ChevronDownIcon, ChevronUpIcon, ChevronsUpDownIcon, PlusIcon, ListIcon, GridIcon, XCircleIcon } from '../icons/Icons.tsx';
import Tooltip from '../shared/Tooltip.tsx';
import { printElementById } from '../../utils/print.ts';
import StockItemDetailModal from '../modals/StockItemDetailModal.tsx';
import StockModal from '../modals/StockModal.tsx';

interface StockProps {
    stockView: 'central' | 'dealer';
    showToast: (message: string, type: 'success' | 'error' | 'info') => void;
    initialState?: any;
    onInitialStateConsumed: () => void;
}

type SortableKey = 'vin' | 'productName' | 'holderName' | 'status' | 'assignedAt' | 'price';
type SortDirection = 'ascending' | 'descending';
type ViewMode = 'list' | 'grid';

const StockCard: React.FC<{ item: any; onSelect: (id: string, checked: boolean) => void; isSelected: boolean; onViewDetails: (item: StockItem) => void; }> = ({ item, onSelect, isSelected, onViewDetails }) => {
    const getStatusColor = (status: StockStatus) => {
        switch (status) {
            case StockStatus.Available: return 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300 border-green-200';
            case StockStatus.Reserved: return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/50 dark:text-yellow-300 border-yellow-200';
            case StockStatus.Sold: return 'bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-300 border-red-200';
            default: return 'bg-slate-100 text-slate-800 dark:bg-slate-700 dark:text-slate-300 border-slate-200';
        }
    };

    return (
        <div className={`bg-white dark:bg-slate-800 rounded-lg shadow-sm border dark:border-slate-700 transition-all relative ${isSelected ? 'border-primary shadow-lg' : 'border-slate-200 hover:shadow-md'}`}>
            <div className="absolute top-2 right-2 no-print">
                 <input
                    type="checkbox"
                    className="h-5 w-5 rounded border-slate-300 dark:border-slate-500 text-primary focus:ring-primary bg-transparent"
                    checked={isSelected}
                    onChange={(e) => onSelect(item._id, e.target.checked)}
                />
            </div>
            <div className="p-4 cursor-pointer" onClick={() => onViewDetails(item)}>
                <p className="font-mono text-sm font-bold text-primary truncate">{item.vin}</p>
                <p className="text-base font-semibold text-slate-800 dark:text-slate-100 mt-1 truncate">{item.productName}</p>
                <p className="text-xs text-slate-500 dark:text-slate-400">{item.holderName}</p>
                <div className="flex justify-between items-end mt-3">
                    <span className={`px-2 py-0.5 inline-flex text-xs leading-5 font-semibold rounded-full capitalize border ${getStatusColor(item.status)}`}>
                        {item.status}
                    </span>
                    <p className="text-lg font-bold text-slate-800 dark:text-slate-200">
                        <span className="text-xs font-normal text-slate-500 dark:text-slate-400">Rs. </span>
                        {item.price.toLocaleString()}
                    </p>
                </div>
            </div>
        </div>
    )
}


const Stock: React.FC<StockProps> = ({ stockView, showToast, initialState, onInitialStateConsumed }) => {
    const { stock, products, dealers, updateStockStatusBulk, addStock } = useData();

    const [categoryFilter, setCategoryFilter] = useState<string>('All'); // This will be modelName
    const [variantFilter, setVariantFilter] = useState<string>('all'); // This will be variant name like NA-70cc

    const [filterStatus, setFilterStatus] = useState<StockStatus | 'all'>('all');
    const [filterDealer, setFilterDealer] = useState<string>('all');
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [searchQuery, setSearchQuery] = useState('');
    const [debouncedSearchQuery, setDebouncedSearchQuery] = useState('');
    const [selectedStock, setSelectedStock] = useState<string[]>([]);
    const [isDetailModalOpen, setDetailModalOpen] = useState(false);
    const [isAddModalOpen, setAddModalOpen] = useState(false);
    const [selectedStockItem, setSelectedStockItem] = useState<StockItem | null>(null);
    const [sortConfig, setSortConfig] = useState<{ key: SortableKey; direction: SortDirection } | null>({ key: 'assignedAt', direction: 'descending' });
    const [viewMode, setViewMode] = useState<ViewMode>('grid');

    useEffect(() => {
        if (initialState?.status) {
            setFilterStatus(initialState.status);
            onInitialStateConsumed();
        }
    }, [initialState, onInitialStateConsumed]);

    useEffect(() => {
        const timerId = setTimeout(() => {
            setDebouncedSearchQuery(searchQuery);
        }, 300);
        return () => clearTimeout(timerId);
    }, [searchQuery]);

    const findProductInfo = (variantId: string) => {
        for (const product of products) {
            const variant = product.variants.find(v => v._id === variantId);
            if (variant) return { product, variant };
        }
        return { product: null, variant: null };
    };

    const enrichedStock = useMemo(() => {
        return stock.map(item => {
             const { product, variant } = findProductInfo(item.variantId);
             const holderName = dealers.find(d => d._id === item.dealerId)?.name || 'Company Stock';
             return { 
                ...item, 
                productName: `${product?.modelName || ''} (${variant?.name || ''} - ${variant?.color || ''})`,
                productId: product?._id,
                productModelName: product?.modelName,
                variantName: variant?.name,
                holderName: holderName,
                price: variant?.price || 0,
            };
        });
    }, [stock, products, dealers]);

    const productCategories = useMemo(() => ['All', ...new Set(products.map(p => p.modelName))], [products]);

    const variantsForCategory = useMemo(() => {
        if (categoryFilter === 'all' || categoryFilter === 'All') return [];
        const product = products.find(p => p.modelName === categoryFilter);
        return product ? [...new Set(product.variants.map(v => v.name))] : [];
    }, [categoryFilter, products]);

    useEffect(() => {
        setVariantFilter('all');
    }, [categoryFilter]);

    const filteredStock = useMemo(() => {
        const lowercasedQuery = debouncedSearchQuery.toLowerCase();

        return enrichedStock.filter(item => {
            const viewMatch = stockView === 'central' ? item.dealerId === null : item.dealerId !== null;
            if (!viewMatch) return false;

            const categoryMatch = categoryFilter === 'All' || item.productModelName === categoryFilter;
            if (!categoryMatch) return false;

            const variantMatch = variantFilter === 'all' || item.variantName === variantFilter;
            if (!variantMatch) return false;

            const statusMatch = filterStatus === 'all' || item.status === filterStatus;
            const dealerMatch = stockView === 'central' || filterDealer === 'all' || item.dealerId === filterDealer;

            const itemDate = new Date(item.assignedAt);
            const startMatch = !startDate || itemDate >= new Date(startDate);
            const endMatch = !endDate || itemDate <= new Date(endDate);

            if (!statusMatch || !dealerMatch || !startMatch || !endMatch) return false;

            if (lowercasedQuery) {
                const vinMatch = item.vin.toLowerCase().includes(lowercasedQuery);
                const productMatchQuery = item.productName.toLowerCase().includes(lowercasedQuery);
                const holderMatch = item.holderName.toLowerCase().includes(lowercasedQuery);
                return vinMatch || productMatchQuery || holderMatch;
            }
            return true;
        });
    }, [enrichedStock, stockView, categoryFilter, variantFilter, filterStatus, filterDealer, startDate, endDate, debouncedSearchQuery, products]);

    const sortedStock = useMemo(() => {
        let sortableItems = [...filteredStock];
        if (sortConfig !== null && viewMode === 'list') {
            sortableItems.sort((a, b) => {
                let aValue = a[sortConfig.key];
                let bValue = b[sortConfig.key];
                if (aValue < bValue) return sortConfig.direction === 'ascending' ? -1 : 1;
                if (aValue > bValue) return sortConfig.direction === 'ascending' ? 1 : -1;
                return 0;
            });
        }
        return sortableItems;
    }, [filteredStock, sortConfig, viewMode]);

    const { paginatedData, currentPage, totalPages, nextPage, prevPage, setCurrentPage } = usePagination(sortedStock, viewMode === 'grid' ? 12 : 10);

    const summaryStats = useMemo(() => ({
        count: filteredStock.length,
        value: filteredStock.reduce((sum, item) => sum + item.price, 0)
    }), [filteredStock]);

    useEffect(() => {
        setSelectedStock([]);
        setCurrentPage(1);
    }, [stockView, categoryFilter, variantFilter, filterStatus, filterDealer, startDate, endDate, debouncedSearchQuery, sortConfig, viewMode, setCurrentPage]);

    const handleViewDetails = (item: StockItem) => {
        setSelectedStockItem(item);
        setDetailModalOpen(true);
    };

    const handleSaveStockItem = async (stockData: Omit<StockItem, '_id' | 'assignedAt'>) => {
        try {
            await addStock(stockData);
            showToast('New stock item added!', 'success');
            setAddModalOpen(false);
        } catch {
            showToast('Failed to add stock item.', 'error');
        }
    };

    const handleClearFilters = () => {
        setFilterStatus('all');
        setFilterDealer('all');
        setCategoryFilter('All');
        setVariantFilter('all');
        setStartDate('');
        setEndDate('');
        setSearchQuery('');
    };

    const requestSort = (key: SortableKey) => {
        let direction: SortDirection = 'ascending';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setSortConfig({ key, direction });
    };

    const SortIndicator = ({ columnKey }: { columnKey: SortableKey }) => {
        if (!sortConfig || sortConfig.key !== columnKey) return <ChevronsUpDownIcon className="w-4 h-4 text-slate-400" />;
        if (sortConfig.direction === 'ascending') return <ChevronUpIcon className="w-4 h-4" />;
        return <ChevronDownIcon className="w-4 h-4" />;
    };

    const handleSelectStock = (stockId: string, isSelected: boolean) => {
        if (isSelected) setSelectedStock(prev => [...prev, stockId]);
        else setSelectedStock(prev => prev.filter(id => id !== stockId));
    };

    const handleBulkStatusChange = async (status: StockStatus) => {
        if (selectedStock.length === 0) return;
        await updateStockStatusBulk(selectedStock, status);
        showToast(`${selectedStock.length} items updated to '${status}'.`, 'success');
        setSelectedStock([]);
    };

    const getStatusColor = (status: StockStatus) => {
        switch (status) {
            case StockStatus.Available: return 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300';
            case StockStatus.Reserved: return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/50 dark:text-yellow-300';
            case StockStatus.Sold: return 'bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-300';
            default: return 'bg-slate-100 text-slate-800 dark:bg-slate-700 dark:text-slate-300';
        }
    };

    return (
        <div id="stock-page-content" className="space-y-6">
            <div className="flex justify-between items-center">
                    <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100">
                        {stockView === 'central' ? 'Company Stock' : 'Dealer Stock'}
                    </h2>
                    <div className="flex items-center space-x-2 no-print">
                         <div className="flex items-center space-x-1 p-1 bg-slate-200 dark:bg-slate-700 rounded-lg">
                            <Tooltip content="List View"><button onClick={() => setViewMode('list')} className={`p-1.5 rounded-md ${viewMode === 'list' ? 'bg-white dark:bg-slate-600 text-primary shadow' : 'text-slate-500'}`}><ListIcon/></button></Tooltip>
                            <Tooltip content="Grid View"><button onClick={() => setViewMode('grid')} className={`p-1.5 rounded-md ${viewMode === 'grid' ? 'bg-white dark:bg-slate-600 text-primary shadow' : 'text-slate-500'}`}><GridIcon/></button></Tooltip>
                        </div>
                        {stockView === 'central' && (
                            <button onClick={() => setAddModalOpen(true)} className="flex items-center space-x-2 py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary">
                                <PlusIcon /><span>Add Stock</span>
                            </button>
                        )}
                    </div>
                </div>

                <div className="space-y-4 no-print">
                    <div className="flex space-x-1 p-1 bg-slate-100 dark:bg-slate-700 rounded-lg overflow-x-auto">
                        {productCategories.map(cat => <button key={cat} onClick={() => setCategoryFilter(cat)} className={`w-full text-center px-3 py-1.5 text-sm font-semibold rounded-md transition-colors ${categoryFilter === cat ? 'bg-white dark:bg-slate-600 shadow-sm text-primary' : 'text-slate-500 dark:text-slate-300 hover:bg-white/50'}`}>{cat}</button>)}
                    </div>
                    {variantsForCategory.length > 0 && (
                        <div className="flex items-center gap-2 overflow-x-auto animate-fade-in pb-2">
                            <span className="text-xs font-semibold text-slate-500 dark:text-slate-400 shrink-0">Models:</span>
                            <button 
                                onClick={() => setVariantFilter('all')} 
                                className={`px-3 py-1 text-xs font-medium rounded-md transition-colors ${variantFilter === 'all' 
                                    ? 'bg-primary text-white shadow' 
                                    : 'bg-white dark:bg-slate-700 text-slate-600 dark:text-slate-200 border border-slate-300 dark:border-slate-600 hover:bg-slate-50'
                                }`}
                            >
                                All
                            </button>
                            {variantsForCategory.map(variantName => (
                                <button 
                                    key={variantName} 
                                    onClick={() => setVariantFilter(variantName)} 
                                    className={`px-3 py-1 text-xs font-medium rounded-md transition-colors whitespace-nowrap ${variantFilter === variantName 
                                        ? 'bg-primary text-white shadow' 
                                        : 'bg-white dark:bg-slate-700 text-slate-600 dark:text-slate-200 border border-slate-300 dark:border-slate-600 hover:bg-slate-50'
                                    }`}
                                >
                                    {variantName}
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                <div className="bg-white dark:bg-slate-800 p-4 rounded-lg shadow-sm flex flex-col xl:flex-row items-stretch xl:items-center justify-between gap-4 no-print">
                    <div className="flex flex-col md:flex-row items-stretch md:items-center gap-4 flex-wrap w-full xl:w-auto">
                        <div className="relative w-full md:w-auto">
                            <input id="stock-search" type="text" placeholder="Search VIN, product..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full md:w-64 p-2 pl-10 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-700" />
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none"><svg className="h-5 w-5 text-slate-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg></div>
                        </div>
                        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
                             <div className="w-full sm:w-auto">
                                 <label htmlFor="status-filter" className="sr-only">Status</label>
                                 <select id="status-filter" value={filterStatus} onChange={(e) => setFilterStatus(e.target.value as any)} className="w-full p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-700">
                                     <option value="all">All Statuses</option>
                                     {Object.values(StockStatus).map(s => <option key={s} value={s}>{s}</option>)}
                                 </select>
                            </div>
                            {stockView === 'dealer' && (
                                 <div className="w-full sm:w-auto">
                                    <label htmlFor="dealer-filter" className="sr-only">Dealer</label>
                                    <select id="dealer-filter" value={filterDealer} onChange={(e) => setFilterDealer(e.target.value)} className="w-full p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-700">
                                        <option value="all">All Dealers</option>
                                        {dealers.map(d => <option key={d._id} value={d._id}>{d.name}</option>)}
                                    </select>
                                </div>
                            )}
                        </div>
                        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
                            <div className="w-full sm:w-auto">
                                <label htmlFor="start-date" className="sr-only">Start Date</label>
                                <input id="start-date" type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full p-2 border border-slate-300 dark:border-slate-600 rounded-md text-sm bg-white dark:bg-slate-700" placeholder="From" />
                            </div>
                             <div className="w-full sm:w-auto">
                                <label htmlFor="end-date" className="sr-only">End Date</label>
                                <input id="end-date" type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="w-full p-2 border border-slate-300 dark:border-slate-600 rounded-md text-sm bg-white dark:bg-slate-700" placeholder="To" />
                            </div>
                        </div>
                    </div>
                     <button onClick={handleClearFilters} className="w-full xl:w-auto py-2 px-4 border border-slate-300 dark:border-slate-600 shadow-sm text-sm font-medium rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors shrink-0">Clear Filters</button>
                </div>

                 {selectedStock.length > 0 && (
                    <div className="bg-slate-100 dark:bg-slate-800 p-3 rounded-lg shadow-sm flex items-center justify-between animate-fade-in no-print sticky top-6 z-10">
                        <span className="text-sm font-semibold text-slate-700 dark:text-slate-300">{selectedStock.length} item(s) selected</span>
                        <div className="flex items-center space-x-2">
                            <span className="text-sm font-medium text-slate-600 dark:text-slate-400">Set status to:</span>
                            <button onClick={() => handleBulkStatusChange(StockStatus.Available)} className="px-3 py-1.5 text-xs font-medium rounded-md text-white bg-green-600 hover:bg-green-700">Available</button>
                            <button onClick={() => handleBulkStatusChange(StockStatus.Reserved)} className="px-3 py-1.5 text-xs font-medium rounded-md text-white bg-yellow-600 hover:bg-yellow-700">Reserved</button>
                            <button onClick={() => handleBulkStatusChange(StockStatus.Sold)} className="px-3 py-1.5 text-xs font-medium rounded-md text-white bg-red-600 hover:bg-red-700">Sold</button>
                        </div>
                    </div>
                )}
                {paginatedData.length > 0 ? (
                    viewMode === 'list' ? (
                    <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm overflow-hidden">
                        <div className="overflow-x-auto">
                            <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                                <thead className="bg-slate-100/80 dark:bg-slate-700/50">
                                    <tr>
                                        <th className="px-4 py-3 w-12 no-print"><input type="checkbox" onChange={(e) => setSelectedStock(e.target.checked ? paginatedData.map(i => i._id) : [])} className="h-4 w-4 rounded border-slate-300 dark:border-slate-500 text-primary" /></th>
                                        {(['vin', 'productName', 'price', 'holderName', 'status', 'assignedAt'] as SortableKey[]).map(key => (<th key={key} className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider"><button onClick={() => requestSort(key)} className="flex items-center space-x-1 group"><span>{key.replace('Name', ' ').replace('At', '')}</span> <SortIndicator columnKey={key} /></button></th>))}
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                                    {paginatedData.map(item => (<tr key={item._id} className={`transition-colors ${selectedStock.includes(item._id) ? 'bg-blue-50 dark:bg-blue-900/20' : 'hover:bg-slate-50 dark:hover:bg-slate-700/50'}`}>
                                        <td className="px-4 py-4 no-print"><input type="checkbox" checked={selectedStock.includes(item._id)} onChange={(e) => handleSelectStock(item._id, e.target.checked)} className="h-4 w-4 rounded" /></td>
                                        <td className="px-6 py-4 cursor-pointer" onClick={() => handleViewDetails(item)}><span className="font-mono text-slate-600 dark:text-slate-400">{item.vin}</span></td>
                                        <td className="px-6 py-4 font-medium text-slate-800 dark:text-slate-200">{item.productName}</td>
                                        <td className="px-6 py-4">Rs. {item.price.toLocaleString()}</td>
                                        <td className="px-6 py-4">{item.holderName}</td>
                                        <td className="px-6 py-4"><span className={`px-2 py-0.5 inline-flex text-xs font-semibold rounded-full capitalize ${getStatusColor(item.status)}`}>{item.status}</span></td>
                                        <td className="px-6 py-4 text-slate-500 dark:text-slate-400">{new Date(item.assignedAt).toLocaleDateString()}</td>
                                    </tr>))}
                                </tbody>
                            </table>
                        </div>
                    </div>) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                        {paginatedData.map(item => (<StockCard key={item._id} item={item} onSelect={handleSelectStock} isSelected={selectedStock.includes(item._id)} onViewDetails={handleViewDetails} />))}
                    </div>)) : (
                    <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm"><EmptyState icon={<ArchiveIcon className="w-10 h-10" />} title="No Stock Items Found" message="Your search or filter criteria did not match any stock items." /></div>
                )}
                <Pagination currentPage={currentPage} totalPages={totalPages} onNext={nextPage} onPrev={prevPage} />

            <StockItemDetailModal isOpen={isDetailModalOpen} onClose={() => setDetailModalOpen(false)} item={selectedStockItem} />
            <StockModal isOpen={isAddModalOpen} onClose={() => setAddModalOpen(false)} onSave={handleSaveStockItem} showToast={showToast} />
        </div>
    );
};

export default Stock;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import type { Dealer, Page } from '../../types.ts';
import { PlusIcon, EditIcon, UsersIcon, StarIcon, PrintIcon, ChevronDownIcon, ChevronUpIcon, ChevronsUpDownIcon, CheckCircleIcon, XCircleIcon, WhatsAppIcon } from '../icons/Icons.tsx';
import DealerModal from '../modals/DealerModal.tsx';
import { useData } from '../../hooks/useData.ts';
import Tooltip from '../shared/Tooltip.tsx';
import SkeletonLoader from '../shared/SkeletonLoader.tsx';
import usePagination from '../../hooks/usePagination.ts';
import Pagination from '../shared/Pagination.tsx';
import EmptyState from '../shared/EmptyState.tsx';
import { usePermissions } from '../../hooks/usePermissions.ts';
import { printElementById, createWhatsAppLink } from '../../utils/print.ts';
import ConfirmModal from '../modals/ConfirmModal.tsx';

type SortableKey = 'name' | 'reputationScore' | 'createdAt';
type SortDirection = 'ascending' | 'descending';

const Dealers: React.FC<{
    showToast: (message: string, type: 'success' | 'error' | 'info') => void;
    setActivePage: (page: Page, state?: any) => void;
    initialState?: any;
    onInitialStateConsumed: () => void;
}> = ({ showToast, setActivePage, initialState, onInitialStateConsumed }) => {
    const { dealers, addDealer, updateDealer, approveDealer, revokeDealer, updateDealerStatusBulk, isLoading } = useData();
    const { canCreateDealer, canUpdateDealer, canApproveDealer } = usePermissions();

    const [isSaving, setIsSaving] = useState(false);
    const [isModalOpen, setModalOpen] = useState(false);
    const [selectedDealer, setSelectedDealer] = useState<Dealer | null>(null);
    const [selectedDealers, setSelectedDealers] = useState<string[]>([]);
    const [searchQuery, setSearchQuery] = useState('');
    const [debouncedSearchQuery, setDebouncedSearchQuery] = useState('');
    const [sortConfig, setSortConfig] = useState<{ key: SortableKey; direction: SortDirection } | null>({ key: 'name', direction: 'ascending' });
    const selectAllCheckboxRef = useRef<HTMLInputElement>(null);
    const [isConfirmOpen, setConfirmOpen] = useState(false);
    const [dealerToRevoke, setDealerToRevoke] = useState<Dealer | null>(null);
    const [isBulkConfirmOpen, setBulkConfirmOpen] = useState(false);
    const [bulkAction, setBulkAction] = useState<'approve' | 'revoke' | null>(null);
    const [cityFilter, setCityFilter] = useState<string>('all');
    const [statusFilter, setStatusFilter] = useState<'all' | 'approved' | 'pending'>('all');
    const [reputationFilter, setReputationFilter] = useState<'all' | 'excellent' | 'good' | 'poor'>('all');
    const [itemsPerPage, setItemsPerPage] = useState(10);

    useEffect(() => {
        if (initialState?.status) {
            setStatusFilter(initialState.status);
            onInitialStateConsumed();
        }
    }, [initialState, onInitialStateConsumed]);

    useEffect(() => {
        const timerId = setTimeout(() => {
            setDebouncedSearchQuery(searchQuery);
        }, 300);
        return () => clearTimeout(timerId);
    }, [searchQuery]);

    const uniqueCities = useMemo(() => [...new Set(dealers.map(d => d.city))], [dealers]);

    const filteredDealers = useMemo(() => {
        let tempDealers = [...dealers];

        if (statusFilter !== 'all') {
            const isApproved = statusFilter === 'approved';
            tempDealers = tempDealers.filter(d => d.registrationApproved === isApproved);
        }

        if (cityFilter !== 'all') {
            tempDealers = tempDealers.filter(d => d.city === cityFilter);
        }

        if (reputationFilter !== 'all') {
            tempDealers = tempDealers.filter(d => {
                if (reputationFilter === 'excellent') return d.reputationScore >= 8;
                if (reputationFilter === 'good') return d.reputationScore >= 5 && d.reputationScore < 8;
                if (reputationFilter === 'poor') return d.reputationScore < 5;
                return true;
            });
        }

        if (debouncedSearchQuery) {
            const lowercasedQuery = debouncedSearchQuery.toLowerCase();
            tempDealers = tempDealers.filter(dealer =>
                dealer.name.toLowerCase().includes(lowercasedQuery) ||
                dealer.ownerName.toLowerCase().includes(lowercasedQuery) ||
                dealer.city.toLowerCase().includes(lowercasedQuery)
            );
        }
        return tempDealers;
    }, [dealers, debouncedSearchQuery, cityFilter, statusFilter, reputationFilter]);

    const sortedDealers = useMemo(() => {
        let sortableItems = [...filteredDealers];
        if (sortConfig !== null) {
            sortableItems.sort((a, b) => {
                let aValue = a[sortConfig.key];
                let bValue = b[sortConfig.key];

                if (aValue < bValue) {
                    return sortConfig.direction === 'ascending' ? -1 : 1;
                }
                if (aValue > bValue) {
                    return sortConfig.direction === 'ascending' ? 1 : -1;
                }
                return 0;
            });
        }
        return sortableItems;
    }, [filteredDealers, sortConfig]);

    const { paginatedData, currentPage, totalPages, nextPage, prevPage, setCurrentPage } = usePagination(sortedDealers, itemsPerPage);

    useEffect(() => {
        setSelectedDealers([]);
    }, [currentPage, searchQuery, sortConfig, cityFilter, statusFilter, reputationFilter, itemsPerPage]);

    useEffect(() => {
        if (selectAllCheckboxRef.current) {
            const isIndeterminate = selectedDealers.length > 0 && selectedDealers.length < paginatedData.length;
            selectAllCheckboxRef.current.indeterminate = isIndeterminate;
        }
    }, [selectedDealers, paginatedData]);

    const handleEdit = (dealer: Dealer) => {
        setSelectedDealer(dealer);
        setModalOpen(true);
    };

    const handleAddNew = () => {
        setSelectedDealer(null);
        setModalOpen(true);
    };

    const handleSave = async (dealerData: Omit<Dealer, '_id' | 'createdAt' | 'registrationApproved'>, isEditing: boolean) => {
        setIsSaving(true);
        try {
            if (isEditing && selectedDealer) {
                await updateDealer({ ...selectedDealer, ...dealerData });
                showToast('Dealer updated successfully!', 'success');
            } else {
                await addDealer(dealerData);
                showToast('New dealer created!', 'success');
            }
        } catch (error) {
            showToast('Failed to save dealer.', 'error');
        } finally {
            setModalOpen(false);
            setIsSaving(false);
        }
    };

    const handleApprove = async (dealerId: string) => {
        try {
            await approveDealer(dealerId);
            showToast('Dealer registration approved!', 'success');
        } catch (error) {
            showToast('Failed to approve dealer.', 'error');
        }
    };

    const handleRevokeClick = (dealer: Dealer) => {
        setDealerToRevoke(dealer);
        setConfirmOpen(true);
    };

    const handleRevokeConfirm = async () => {
        if (!dealerToRevoke) return;
        try {
            await revokeDealer(dealerToRevoke._id); 
            showToast('Dealer approval revoked!', 'info');
        } catch (error) {
            showToast('Failed to revoke dealer approval.', 'error');
        }
        setDealerToRevoke(null);
        setConfirmOpen(false);
    };

    const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.checked) {
            setSelectedDealers(paginatedData.map(d => d._id));
        } else {
            setSelectedDealers([]);
        }
    };

    const handleSelectDealer = (dealerId: string, isSelected: boolean) => {
        if (isSelected) {
            setSelectedDealers(prev => [...prev, dealerId]);
        } else {
            setSelectedDealers(prev => prev.filter(id => id !== dealerId));
        }
    };

    const handleBulkActionTrigger = (action: 'approve' | 'revoke') => {
        if (!canApproveDealer || selectedDealers.length === 0) return;
        setBulkAction(action);
        setBulkConfirmOpen(true);
    };

    const handleBulkActionConfirm = async () => {
        if (!bulkAction) return;

        const isApproving = bulkAction === 'approve';
        try {
            await updateDealerStatusBulk(selectedDealers, isApproving);
            showToast(
                `${selectedDealers.length} dealer(s) ${isApproving ? 'approved' : 'approval revoked'}.`,
                isApproving ? 'success' : 'info'
            );
        } catch (error) {
            showToast('Failed to perform bulk action.', 'error');
        }

        setSelectedDealers([]);
        setBulkConfirmOpen(false);
        setBulkAction(null);
    };

    const SortIndicator = ({ columnKey }: { columnKey: SortableKey }) => {
        if (!sortConfig || sortConfig.key !== columnKey) {
            return <ChevronsUpDownIcon className="w-4 h-4 text-slate-400" />;
        }
        if (sortConfig.direction === 'ascending') {
            return <ChevronUpIcon className="w-4 h-4" />;
        }
        return <ChevronDownIcon className="w-4 h-4" />;
    };

    const requestSort = (key: SortableKey) => {
        let direction: SortDirection = 'ascending';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setSortConfig({ key, direction });
    };

    const viewDealerDetails = (dealerId: string) => {
        setActivePage('DealerDetail', { dealerId });
    };

    const handleClearFilters = () => {
        setSearchQuery('');
        setCityFilter('all');
        setStatusFilter('all');
        setReputationFilter('all');
        setItemsPerPage(10);
        setCurrentPage(1);
    };

    if (isLoading) {
        return <SkeletonLoader type="table" rows={6} />;
    }

    const showActionsColumn = canUpdateDealer || canApproveDealer;

    return (
        <div id="dealers-page-content" className="space-y-6">
            <div className="flex justify-between items-center no-print">
                <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100">Manage Dealers</h2>
                <div className="flex items-center space-x-2">
                     <div className="relative hidden md:block">
                        <input 
                            type="text" 
                            placeholder="Search dealer, owner..."
                            value={searchQuery}
                            onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
                            className="pl-10 pr-4 py-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm focus:ring-primary focus:border-primary bg-white dark:bg-slate-800"
                        />
                         <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <svg className="h-5 w-5 text-slate-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg>
                        </div>
                    </div>
                     <Tooltip content="Print Current View">
                        <button onClick={() => printElementById('dealers-page-content')} className="flex items-center justify-center py-2 px-4 border border-slate-300 dark:border-slate-600 shadow-sm text-sm font-medium rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                            <PrintIcon />
                        </button>
                    </Tooltip>
                    {canCreateDealer && (
                        <button onClick={handleAddNew} className="flex items-center space-x-2 py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition-colors">
                            <PlusIcon />
                            <span className="hidden sm:inline">Add New Dealer</span>
                        </button>
                    )}
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-4 rounded-lg shadow-sm flex flex-col xl:flex-row justify-between items-stretch gap-4 no-print">
                <div className="flex flex-col md:flex-row items-stretch md:items-center gap-4 flex-wrap w-full xl:w-auto">
                    {/* Mobile Search */}
                    <div className="relative md:hidden w-full">
                        <input 
                            type="text" 
                            placeholder="Search dealer, owner..."
                            value={searchQuery}
                            onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
                            className="w-full pl-10 pr-4 py-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm focus:ring-primary focus:border-primary bg-white dark:bg-slate-800"
                        />
                         <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <svg className="h-5 w-5 text-slate-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg>
                        </div>
                    </div>

                    <div className="flex items-center w-full md:w-auto">
                        <label htmlFor="city-filter" className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">City:</label>
                        <select
                            id="city-filter"
                            value={cityFilter}
                            onChange={(e) => { setCityFilter(e.target.value); setCurrentPage(1); }}
                            className="w-full md:w-40 p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-800"
                        >
                            <option value="all">All Cities</option>
                            {uniqueCities.map(city => <option key={city} value={city}>{city}</option>)}
                        </select>
                    </div>
                    <div className="flex items-center w-full md:w-auto">
                        <label htmlFor="status-filter" className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">Status:</label>
                        <select
                            id="status-filter"
                            value={statusFilter}
                            onChange={(e) => { setStatusFilter(e.target.value as 'all' | 'approved' | 'pending'); setCurrentPage(1); }}
                            className="w-full md:w-32 p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-800"
                        >
                            <option value="all">All Statuses</option>
                            <option value="approved">Approved</option>
                            <option value="pending">Pending</option>
                        </select>
                    </div>
                     <div className="flex items-center w-full md:w-auto">
                        <label htmlFor="reputation-filter" className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">Reputation:</label>
                        <select
                            id="reputation-filter"
                            value={reputationFilter}
                            onChange={(e) => { setReputationFilter(e.target.value as any); setCurrentPage(1); }}
                            className="w-full md:w-40 p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-800"
                        >
                            <option value="all">All Scores</option>
                            <option value="excellent">Excellent (8+)</option>
                            <option value="good">Good (5-8)</option>
                            <option value="poor">Poor (&lt;5)</option>
                        </select>
                    </div>
                    <div className="flex items-center w-full md:w-auto">
                        <label htmlFor="rows-filter" className="text-sm font-medium text-slate-600 dark:text-slate-400 mr-2 shrink-0">Rows:</label>
                        <select
                            id="rows-filter"
                            value={itemsPerPage}
                            onChange={(e) => { setItemsPerPage(Number(e.target.value)); setCurrentPage(1); }}
                            className="w-full md:w-20 p-2 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm text-sm bg-white dark:bg-slate-800"
                        >
                            <option value={10}>10</option>
                            <option value={20}>20</option>
                            <option value={50}>50</option>
                            <option value={100}>100</option>
                        </select>
                    </div>
                </div>
                <button 
                    onClick={handleClearFilters}
                    className="w-full xl:w-auto py-2 px-4 border border-slate-300 dark:border-slate-600 shadow-sm text-sm font-medium rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors shrink-0"
                >
                    Clear Filters
                </button>
            </div>

            {selectedDealers.length > 0 && canApproveDealer && (
                <div className="bg-slate-100 dark:bg-slate-800 p-3 rounded-lg shadow-sm flex items-center justify-between animate-fade-in no-print">
                    <span className="text-sm font-semibold text-slate-700 dark:text-slate-300">{selectedDealers.length} dealer(s) selected</span>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => handleBulkActionTrigger('approve')} className="px-3 py-1.5 text-xs font-medium rounded-md text-white bg-green-600 hover:bg-green-700">Approve</button>
                        <button onClick={() => handleBulkActionTrigger('revoke')} className="px-3 py-1.5 text-xs font-medium rounded-md text-white bg-red-600 hover:bg-red-700">Revoke</button>
                    </div>
                </div>
            )}

            <div className="hidden print-only">
                <h1 className="text-2xl font-bold mb-1">Dealers List</h1>
                <p className="text-sm text-slate-600 mb-4">Generated on: {new Date().toLocaleDateString()}</p>
            </div>


            <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                        <thead className="bg-slate-100/80 dark:bg-slate-700/50">
                            <tr>
                                <th className="px-4 py-3 w-12 no-print">
                                    <input
                                        ref={selectAllCheckboxRef}
                                        type="checkbox"
                                        className="h-4 w-4 rounded border-slate-300 dark:border-slate-500 text-primary focus:ring-primary bg-transparent"
                                        onChange={handleSelectAll}
                                        checked={paginatedData.length > 0 && selectedDealers.length === paginatedData.length}
                                    />
                                </th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
                                     <button onClick={() => requestSort('name')} className="flex items-center space-x-1 group">
                                        <span>Dealer</span> <SortIndicator columnKey="name" />
                                    </button>
                                </th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Contact</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Status</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
                                     <button onClick={() => requestSort('reputationScore')} className="flex items-center space-x-1 group">
                                        <span>Reputation</span> <SortIndicator columnKey="reputationScore" />
                                    </button>
                                </th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
                                    <button onClick={() => requestSort('createdAt')} className="flex items-center space-x-1 group">
                                        <span>Joined</span> <SortIndicator columnKey="createdAt" />
                                    </button>
                                </th>
                                {showActionsColumn && <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider no-print">Actions</th>}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                           {paginatedData.length > 0 ? paginatedData.map(dealer => (
                               <tr
                                   key={dealer._id}
                                   onClick={() => viewDealerDetails(dealer._id)}
                                   className={`cursor-pointer transition-colors odd:bg-slate-50 dark:odd:bg-slate-800/50 ${selectedDealers.includes(dealer._id) ? 'bg-blue-100 dark:bg-blue-900/50' : 'hover:bg-slate-100 dark:hover:bg-slate-700/50'}`}
                                >
                                    <td className="px-4 py-4 whitespace-nowrap no-print" onClick={(e) => e.stopPropagation()}>
                                        <input
                                            type="checkbox"
                                            className="h-4 w-4 rounded border-slate-300 dark:border-slate-500 text-primary focus:ring-primary bg-transparent"
                                            checked={selectedDealers.includes(dealer._id)}
                                            onChange={(e) => handleSelectDealer(dealer._id, e.target.checked)}
                                        />
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <div className="text-sm font-medium text-slate-900 dark:text-slate-100">{dealer.name}</div>
                                        <div className="text-sm text-slate-500 dark:text-slate-400">{dealer.city}</div>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <div className="text-sm font-medium text-slate-900 dark:text-slate-100">{dealer.ownerName}</div>
                                        <div className="text-sm text-slate-500 dark:text-slate-400 flex items-center gap-2">
                                            <span>{dealer.phone}</span>
                                            <a
                                                href={createWhatsAppLink(dealer.phone)}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                onClick={(e) => e.stopPropagation()}
                                                className="text-green-600 hover:text-green-700 dark:text-green-400 dark:hover:text-green-300 transition-colors"
                                                aria-label="Chat on WhatsApp"
                                            >
                                                <Tooltip content="Chat on WhatsApp">
                                                    <WhatsAppIcon className="w-5 h-5" />
                                                </Tooltip>
                                            </a>
                                        </div>
                                    </td>
                                     <td className="px-6 py-4 whitespace-nowrap">
                                        {dealer.registrationApproved
                                            ? <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300">Approved</span>
                                            : <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-yellow-100 text-yellow-800 dark:bg-yellow-900/50 dark:text-yellow-300">Pending</span>
                                        }
                                    </td>
                                     <td className="px-6 py-4 whitespace-nowrap font-semibold text-sm">
                                        <span className={dealer.reputationScore > 8 ? 'text-green-600 dark:text-green-400' : dealer.reputationScore < 5 ? 'text-red-600 dark:text-red-400' : 'text-slate-700 dark:text-slate-300'}>
                                            {dealer.reputationScore.toFixed(1)}
                                        </span>
                                    </td>
                                     <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">{new Date(dealer.createdAt).toLocaleDateString()}</td>
                                    {showActionsColumn && (
                                         <td className="px-6 py-4 whitespace-nowrap text-sm font-medium space-x-2 no-print" onClick={(e) => e.stopPropagation()}>
                                            {!dealer.registrationApproved && canApproveDealer && (
                                                <Tooltip content="Approve Registration">
                                                    <button onClick={(e) => { e.stopPropagation(); handleApprove(dealer._id); }} className="text-green-600 hover:text-green-900 dark:text-green-400 dark:hover:text-green-300 transition-colors p-1 rounded-full hover:bg-green-100 dark:hover:bg-green-900/50"><CheckCircleIcon /></button>
                                                </Tooltip>
                                            )}
                                            {dealer.registrationApproved && canApproveDealer && (
                                                <Tooltip content="Revoke Approval">
                                                    <button onClick={(e) => { e.stopPropagation(); handleRevokeClick(dealer); }} className="text-red-600 hover:text-red-900 dark:text-red-400 dark:hover:text-red-300 transition-colors p-1 rounded-full hover:bg-red-100 dark:hover:bg-red-900/50"><XCircleIcon /></button>
                                                </Tooltip>
                                            )}
                                            {canUpdateDealer && (
                                                <Tooltip content="Edit Dealer Details">
                                                    <button onClick={(e) => { e.stopPropagation(); handleEdit(dealer); }} className="text-indigo-600 hover:text-indigo-900 dark:text-indigo-400 dark:hover:text-indigo-300 transition-colors p-1 rounded-full hover:bg-indigo-100 dark:hover:bg-indigo-900/50"><EditIcon /></button>
                                                </Tooltip>
                                            )}
                                        </td>
                                    )}
                               </tr>
                           )) : (
                               <tr>
                                   <td colSpan={showActionsColumn ? 8 : 7}>
                                       <EmptyState
                                            icon={<UsersIcon className="w-10 h-10" />}
                                            title="No Dealers Found"
                                            message={searchQuery || cityFilter !== 'all' || statusFilter !== 'all' || reputationFilter !== 'all' ? "Your filters didn't match any dealers." : "Get started by adding your first dealer to the system."}
                                            action={canCreateDealer && !searchQuery ? (
                                                 <button onClick={handleAddNew} className="flex items-center space-x-2 mx-auto py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary no-print">
                                                    <PlusIcon />
                                                    <span>Create First Dealer</span>
                                                </button>
                                            ) : undefined}
                                        />
                                   </td>
                               </tr>
                           )}
                        </tbody>
                    </table>
                </div>
                 <Pagination currentPage={currentPage} totalPages={totalPages} onNext={nextPage} onPrev={prevPage} />
            </div>

            <DealerModal isOpen={isModalOpen} onClose={() => setModalOpen(false)} onSave={handleSave} dealer={selectedDealer} isSaving={isSaving} />

            <ConfirmModal
                isOpen={isConfirmOpen}
                onClose={() => setConfirmOpen(false)}
                onConfirm={handleRevokeConfirm}
                title="Revoke Dealer Approval"
                message={`Are you sure you want to revoke approval for "${dealerToRevoke?.name}"? They will lose access to the dealer portal.`}
            />

            <ConfirmModal
                isOpen={isBulkConfirmOpen}
                onClose={() => setBulkConfirmOpen(false)}
                onConfirm={handleBulkActionConfirm}
                title={`Confirm Bulk ${bulkAction === 'approve' ? 'Approval' : 'Revocation'}`}
                message={`Are you sure you want to ${bulkAction} the ${selectedDealers.length} selected dealers?`}
            />
        </div>
    );
};

export default Dealers;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, Legend, ResponsiveContainer, LineChart, Line, PieChart, Pie, Cell, Sector } from 'recharts';
import { useData } from '../../hooks/useData.ts';
import StatCard from '../shared/StatCard.tsx';
import { DownloadIcon, DollarSignIcon, BoxIcon, UsersIcon, PrintIcon, ChevronsUpDownIcon, ChevronUpIcon, ChevronDownIcon, XCircleIcon, CalendarIcon, PackageIcon } from '../icons/Icons.tsx';
import { BookingStatus, StockStatus } from '../../types.ts';
import SkeletonLoader from '../shared/SkeletonLoader.tsx';
import { printElementById, exportToCsv } from '../../utils/print.ts';
import CustomReports from './CustomReports.tsx';
import usePagination from '../../hooks/usePagination.ts';
import Pagination from '../shared/Pagination.tsx';
import EmptyState from '../shared/EmptyState.tsx';
import ScheduleReportModal from '../modals/ScheduleReportModal.tsx';

type ReportTab = 'sales' | 'inventory' | 'dealer' | 'custom';
type DateRange = 'all' | '30d' | '90d';
type InventorySortableKey = 'VIN' | 'Product' | 'Holder' | 'Status' | 'Assigned';
type SalesSortableKey = 'Date' | 'Customer' | 'Product' | 'Dealer' | 'Price';
type DealerSortableKey = 'Dealer' | 'City' | 'Reputation' | 'UnitsSold' | 'TotalRevenue' | 'CommissionEarned';

const COLORS = ['#3B82F6', '#10B981', '#F59E0B', '#EF4444', '#6366F1'];
const PIE_COLORS = {
    [StockStatus.Available]: '#22C55E', // green-500
    [StockStatus.Reserved]: '#F59E0B', // amber-500
    [StockStatus.Sold]: '#EF4444', // red-500
};

const renderActiveShape = (props: any) => {
  const { cx, cy, innerRadius, outerRadius, startAngle, endAngle, fill, payload, percent } = props;
  return (
    <g>
      <text x={cx} y={cy - 10} textAnchor="middle" fill="#334155" className="font-bold text-lg dark:fill-slate-200">
        {payload.value}
      </text>
       <text x={cx} y={cy + 10} textAnchor="middle" fill="#64748b" className="text-sm dark:fill-slate-400">
        Units
      </text>
      <Sector cx={cx} cy={cy} innerRadius={innerRadius} outerRadius={outerRadius} startAngle={startAngle} endAngle={endAngle} fill={fill} />
      <Sector cx={cx} cy={cy} startAngle={startAngle} endAngle={endAngle} innerRadius={outerRadius + 6} outerRadius={outerRadius + 10} fill={fill} />
      <text x={cx} y={cy + outerRadius + 25} textAnchor="middle" fill={fill} className="font-semibold">
        {`${payload.name} (${(percent * 100).toFixed(0)}%)`}
      </text>
    </g>
  );
};

// FIX: Cast Pie to a component type that accepts activeIndex to resolve recharts typing issue.
const PieWithActiveIndex = Pie as React.ComponentType<React.ComponentProps<typeof Pie> & { activeIndex: number }>;

const SortIndicator = ({ active, direction }: { active: boolean; direction: 'ascending' | 'descending' }) => {
    if (!active) return <ChevronsUpDownIcon className="w-4 h-4 text-slate-400" />;
    if (direction === 'ascending') return <ChevronUpIcon className="w-4 h-4" />;
    return <ChevronDownIcon className="w-4 h-4" />;
};

const Reports: React.FC<{ showToast: (message: string, type: 'success' | 'error' | 'info') => void; }> = ({ showToast }) => {
    const { bookings, stock, products, dealers, isLoading } = useData();
    const [activeTab, setActiveTab] = useState<ReportTab>('sales');
    const [dateRange, setDateRange] = useState<DateRange>('all');
    const [isChartLoading, setIsChartLoading] = useState(true);
    const [isScheduleModalOpen, setScheduleModalOpen] = useState(false);

    // Inventory State
    const [inventoryPieIndex, setInventoryPieIndex] = useState(-1);
    const [inventoryStatusFilter, setInventoryStatusFilter] = useState<StockStatus | 'all'>('all');
    const [inventorySearch, setInventorySearch] = useState('');
    const [inventorySortConfig, setInventorySortConfig] = useState<{ key: InventorySortableKey; direction: 'ascending' | 'descending' } | null>(null);

    // Sales State
    const [categoryFilter, setCategoryFilter] = useState<string | null>(null);
    const [salesSortConfig, setSalesSortConfig] = useState<{ key: SalesSortableKey; direction: 'ascending' | 'descending' } | null>(null);

    // Dealer State
    const [dealerSortConfig, setDealerSortConfig] = useState<{ key: DealerSortableKey; direction: 'ascending' | 'descending' } | null>(null);

    useEffect(() => {
        setIsChartLoading(true);
        // Simulate chart data loading
        const timer = setTimeout(() => setIsChartLoading(false), 500);
        return () => clearTimeout(timer);
    }, [dateRange, activeTab]);

    const dateFilteredBookings = useMemo(() => {
        if (dateRange === 'all') return bookings;
        const now = Date.now();
        const days = dateRange === '30d' ? 30 : 90;
        const cutoff = now - days * 24 * 60 * 60 * 1000;
        return bookings.filter(b => new Date(b.bookingTimestamp).getTime() >= cutoff);
    }, [bookings, dateRange]);

    const findProductInfo = (variantId: string) => {
        for (const product of products) {
            const variant = product.variants.find(v => v._id === variantId);
            if (variant) return { product, variant };
        }
        return { product: null, variant: null };
    };

    const salesReportData = useMemo(() => {
        const deliveredBookings = dateFilteredBookings.filter(b => b.status === BookingStatus.Delivered);

        const totalRevenue = deliveredBookings.reduce((sum, booking) => {
            const { variant } = findProductInfo(booking.variantId);
            return sum + (variant?.price || 0);
        }, 0);

        const unitsSold = deliveredBookings.length;

        const salesByCategory = deliveredBookings.reduce((acc, booking) => {
            const { product } = findProductInfo(booking.variantId);
            if (product) {
                acc[product.modelName] = (acc[product.modelName] || 0) + 1;
            }
            return acc;
        }, {} as Record<string, number>);

        let groupingFormat: 'day' | 'week' | 'month' = 'month';
        if (dateRange === '30d') groupingFormat = 'day';
        if (dateRange === '90d') groupingFormat = 'week';

        const getGroupKey = (date: Date) => {
            if (groupingFormat === 'day') return date.toLocaleDateString('en-CA'); // YYYY-MM-DD
            if (groupingFormat === 'week') {
                const startOfWeek = new Date(date);
                startOfWeek.setDate(date.getDate() - date.getDay());
                return startOfWeek.toLocaleDateString('en-CA');
            }
            return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
        };

        const revenueOverTime = deliveredBookings.reduce((acc, booking) => {
            const groupKey = getGroupKey(new Date(booking.bookingTimestamp));
            const { variant } = findProductInfo(booking.variantId);
            const price = variant?.price || 0;
            if (!acc[groupKey]) {
                acc[groupKey] = 0;
            }
            acc[groupKey] += price;
            return acc;
        }, {} as Record<string, number>);

        const revenueTrendData = Object.entries(revenueOverTime)
            .map(([date, revenue]) => ({ date, revenue }))
            .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());


        const tableData = deliveredBookings.map(b => {
            const { product, variant } = findProductInfo(b.variantId);
            const dealer = dealers.find(d => d._id === b.dealerId);
            return {
                Date: new Date(b.bookingTimestamp).toLocaleDateString(),
                Customer: b.customerName,
                Product: `${product?.modelName} (${variant?.name})`,
                Dealer: dealer?.name,
                Price: variant?.price || 0,
                // Hidden raw fields for sorting
                _rawDate: new Date(b.bookingTimestamp).getTime(),
                _rawPrice: variant?.price || 0
            };
        });

        const averageRevenuePerUnit = unitsSold > 0 ? totalRevenue / unitsSold : 0;

        const now = Date.now();
        const allDeliveredBookings = bookings.filter(b => b.status === BookingStatus.Delivered);

        // 30-day stats
        const thirtyDaysAgo = now - 30 * 24 * 60 * 60 * 1000;
        const last30DaysBookings = allDeliveredBookings.filter(b => new Date(b.bookingTimestamp).getTime() >= thirtyDaysAgo);
        const last30DaysRevenue = last30DaysBookings.reduce((sum, b) => sum + (findProductInfo(b.variantId).variant?.price || 0), 0);
        const last30DaysUnitsSold = last30DaysBookings.length;

        // 90-day stats
        const ninetyDaysAgo = now - 90 * 24 * 60 * 60 * 1000;
        const last90DaysBookings = allDeliveredBookings.filter(b => new Date(b.bookingTimestamp).getTime() >= ninetyDaysAgo);
        const last90DaysRevenue = last90DaysBookings.reduce((sum, b) => sum + (findProductInfo(b.variantId).variant?.price || 0), 0);
        const last90DaysUnitsSold = last90DaysBookings.length;

        const newBookingsLast30d = bookings.filter(b => new Date(b.bookingTimestamp).getTime() >= thirtyDaysAgo).length;

        return {
            totalRevenue,
            unitsSold,
            salesByCategory: Object.entries(salesByCategory).map(([name, units]) => ({ name, units })),
            tableData,
            revenueTrendData,
            averageRevenuePerUnit,
            newBookingsLast30d,
            last30DaysRevenue,
            last30DaysUnitsSold,
            last90DaysRevenue,
            last90DaysUnitsSold,
        };
    }, [dateFilteredBookings, products, dealers, dateRange, bookings]);

    const displayedSalesTableData = useMemo(() => {
        let data = [...salesReportData.tableData];

        if (categoryFilter) {
            data = data.filter(row => {
                const productModelName = row.Product.split(' (')[0];
                return productModelName.includes(categoryFilter);
            });
        }

        if (salesSortConfig !== null) {
            data.sort((a, b) => {
                // Use raw values if available, otherwise use key directly
                const key = salesSortConfig.key as keyof typeof a;
                const rawKey = `_raw${key}` as keyof typeof a;
                const aValue = a[rawKey] !== undefined ? a[rawKey] : a[key];
                const bValue = b[rawKey] !== undefined ? b[rawKey] : b[key];

                if (aValue < bValue) return salesSortConfig.direction === 'ascending' ? -1 : 1;
                if (aValue > bValue) return salesSortConfig.direction === 'ascending' ? 1 : -1;
                return 0;
            });
        }

        return data;
    }, [categoryFilter, salesReportData.tableData, salesSortConfig]);

    const requestSalesSort = (key: SalesSortableKey) => {
        let direction: 'ascending' | 'descending' = 'ascending';
        if (salesSortConfig && salesSortConfig.key === key && salesSortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setSalesSortConfig({ key, direction });
    };

    const handleSalesExport = () => {
        // Strip _raw keys before export
        const cleanData = displayedSalesTableData.map(({ _rawDate, _rawPrice, ...rest }) => rest);
        exportToCsv('sales_report.csv', cleanData);
    };

    const inventoryReportData = useMemo(() => {
        const totalStockValue = stock.reduce((sum, item) => {
            const { variant } = findProductInfo(item.variantId);
            return sum + (variant?.price || 0);
        }, 0);

        const stockByStatus = stock.reduce((acc, item) => {
            acc[item.status] = (acc[item.status] || 0) + 1;
            return acc;
        }, {} as Record<StockStatus, number>);

        const tableData = stock.map(item => {
            const { product, variant } = findProductInfo(item.variantId);
            const holder = dealers.find(d => d._id === item.dealerId)?.name || 'Central Stock';
            return {
                VIN: item.vin,
                Product: `${product?.modelName} (${variant?.name})`,
                Holder: holder,
                Status: item.status,
                Assigned: new Date(item.assignedAt).toLocaleDateString(),
            };
        });

        const now = Date.now();
        const inventoryAgeBuckets = {
            '0-30 Days': 0,
            '31-60 Days': 0,
            '61-90 Days': 0,
            '91+ Days': 0,
        };
        stock.forEach(item => {
            if (item.status === StockStatus.Available || item.status === StockStatus.Reserved) {
                const ageInDays = (now - new Date(item.assignedAt).getTime()) / (1000 * 60 * 60 * 24);
                if (ageInDays <= 30) inventoryAgeBuckets['0-30 Days']++;
                else if (ageInDays <= 60) inventoryAgeBuckets['31-60 Days']++;
                else if (ageInDays <= 90) inventoryAgeBuckets['61-90 Days']++;
                else inventoryAgeBuckets['91+ Days']++;
            }
        });
        const inventoryAgeData = Object.entries(inventoryAgeBuckets).map(([name, value]) => ({ name, value }));

        return {
            totalUnits: stock.length,
            totalStockValue,
            stockByStatus: Object.entries(stockByStatus).map(([name, value]) => ({ name, value })),
            tableData,
            inventoryAgeData,
        };
    }, [stock, products, dealers]);

    const processedInventoryTableData = useMemo(() => {
        let filtered = inventoryReportData.tableData;

        if (inventoryStatusFilter !== 'all') {
            filtered = filtered.filter(item => item.Status === inventoryStatusFilter);
        }

        if (inventorySearch) {
            const lowercasedQuery = inventorySearch.toLowerCase();
            filtered = filtered.filter(item => 
                item.VIN.toLowerCase().includes(lowercasedQuery) ||
                item.Product.toLowerCase().includes(lowercasedQuery) ||
                item.Holder.toLowerCase().includes(lowercasedQuery)
            );
        }

        if (inventorySortConfig !== null) {
            filtered.sort((a, b) => {
                const aValue = a[inventorySortConfig.key as keyof typeof a];
                const bValue = b[inventorySortConfig.key as keyof typeof b];
                if (aValue < bValue) {
                    return inventorySortConfig.direction === 'ascending' ? -1 : 1;
                }
                if (aValue > bValue) {
                    return inventorySortConfig.direction === 'ascending' ? 1 : -1;
                }
                return 0;
            });
        }

        return filtered;
    }, [inventoryReportData.tableData, inventoryStatusFilter, inventorySearch, inventorySortConfig]);

    const { paginatedData: paginatedInventory, currentPage: inventoryCurrentPage, totalPages: inventoryTotalPages, nextPage: inventoryNextPage, prevPage: inventoryPrevPage, setCurrentPage: setInventoryCurrentPage } = usePagination(processedInventoryTableData, 10);

    const requestInventorySort = (key: InventorySortableKey) => {
        let direction: 'ascending' | 'descending' = 'ascending';
        if (inventorySortConfig && inventorySortConfig.key === key && inventorySortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setInventorySortConfig({ key, direction });
    };

    const handlePieClick = useCallback((data: any, index: number) => {
        const clickedStatus = data.name as StockStatus;
        // If clicking the active slice, reset the filter
        if (index === inventoryPieIndex) {
            setInventoryPieIndex(-1);
            setInventoryStatusFilter('all');
        } else {
            setInventoryPieIndex(index);
            setInventoryStatusFilter(clickedStatus);
        }
        setInventoryCurrentPage(1);
    }, [inventoryPieIndex, setInventoryCurrentPage]);

    const handleCategoryClick = (data: any) => {
        if (data && data.activePayload && data.activePayload.length > 0) {
            const clickedCategory = data.activePayload[0].payload.name;
            setCategoryFilter(prev => (prev === clickedCategory ? null : clickedCategory));
        }
    };

    const dealerReportData = useMemo(() => {
        const deliveredBookings = dateFilteredBookings.filter(b => b.status === BookingStatus.Delivered);

        const salesByDealer = deliveredBookings.reduce((acc, booking) => {
            const dealerId = booking.dealerId;
            const { variant } = findProductInfo(booking.variantId);
            const price = variant?.price || 0;

            if (!acc[dealerId]) {
                acc[dealerId] = { revenue: 0, units: 0 };
            }
            acc[dealerId].revenue += price;
            acc[dealerId].units += 1;
            return acc;
        }, {} as Record<string, { revenue: number, units: number }>);

        const COMMISSION_RATE = 0.01;

        const tableData = dealers.map(dealer => ({
            Dealer: dealer.name,
            City: dealer.city,
            Reputation: dealer.reputationScore, // Keep as number for sorting
            UnitsSold: salesByDealer[dealer._id]?.units || 0,
            TotalRevenue: salesByDealer[dealer._id]?.revenue || 0,
            CommissionEarned: (salesByDealer[dealer._id]?.revenue || 0) * COMMISSION_RATE,
        }));

        const chartData = tableData.filter(d => d.TotalRevenue > 0)
            .sort((a, b) => b.TotalRevenue - a.TotalRevenue)
            .slice(0, 10);

        return { tableData, chartData };
    }, [dateFilteredBookings, dealers, products]);

    const processedDealerTableData = useMemo(() => {
        let data = [...dealerReportData.tableData];
        if (dealerSortConfig !== null) {
            data.sort((a, b) => {
                const aValue = a[dealerSortConfig.key];
                const bValue = b[dealerSortConfig.key];
                if (aValue < bValue) return dealerSortConfig.direction === 'ascending' ? -1 : 1;
                if (aValue > bValue) return dealerSortConfig.direction === 'ascending' ? 1 : -1;
                return 0;
            });
        }
        return data;
    }, [dealerReportData.tableData, dealerSortConfig]);

    const requestDealerSort = (key: DealerSortableKey) => {
        let direction: 'ascending' | 'descending' = 'ascending';
        if (dealerSortConfig && dealerSortConfig.key === key && dealerSortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setDealerSortConfig({ key, direction });
    };

    const renderContent = () => {
        if (isLoading) {
            return (
                <div className="space-y-6">
                    <SkeletonLoader type="cards" cols={2} />
                    <SkeletonLoader type="table" rows={4} />
                    <SkeletonLoader type="table" rows={4} />
                </div>
            );
        }
        switch (activeTab) {
            case 'sales':
                return (
                    <div className="space-y-6 animate-fade-in">
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                            <StatCard title="Total Revenue" value={`Rs. ${salesReportData.totalRevenue.toLocaleString()}`} icon={<DollarSignIcon />} color="bg-green-500" />
                            <StatCard title="Total Units Sold" value={salesReportData.unitsSold.toLocaleString()} icon={<PackageIcon />} color="bg-blue-500" />
                            <StatCard title="Avg. Revenue / Unit" value={`Rs. ${salesReportData.averageRevenuePerUnit.toLocaleString(undefined, { maximumFractionDigits: 0 })}`} icon={<DollarSignIcon />} color="bg-teal-500" />
                            <StatCard title="New Bookings (Last 30d)" value={salesReportData.newBookingsLast30d.toLocaleString()} icon={<CalendarIcon />} color="bg-violet-500" />
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="bg-white dark:bg-slate-800 p-6 rounded-lg shadow-sm">
                                <h3 className="font-semibold text-slate-800 dark:text-slate-100 mb-3 text-lg">Summary (Last 30 Days)</h3>
                                <div className="space-y-2 border-t border-slate-200 dark:border-slate-700 pt-3">
                                    <div className="flex justify-between items-baseline">
                                        <span className="text-sm text-slate-500 dark:text-slate-400">Total Revenue:</span>
                                        <span className="text-lg font-bold text-slate-800 dark:text-slate-200">Rs. {salesReportData.last30DaysRevenue.toLocaleString()}</span>
                                    </div>
                                    <div className="flex justify-between items-baseline">
                                        <span className="text-sm text-slate-500 dark:text-slate-400">Units Sold:</span>
                                        <span className="text-lg font-bold text-slate-800 dark:text-slate-200">{salesReportData.last30DaysUnitsSold.toLocaleString()}</span>
                                    </div>
                                </div>
                            </div>
                            <div className="bg-white dark:bg-slate-800 p-6 rounded-lg shadow-sm">
                                <h3 className="font-semibold text-slate-800 dark:text-slate-100 mb-3 text-lg">Summary (Last 90 Days)</h3>
                                <div className="space-y-2 border-t border-slate-200 dark:border-slate-700 pt-3">
                                    <div className="flex justify-between items-baseline">
                                        <span className="text-sm text-slate-500 dark:text-slate-400">Total Revenue:</span>
                                        <span className="text-lg font-bold text-slate-800 dark:text-slate-200">Rs. {salesReportData.last90DaysRevenue.toLocaleString()}</span>
                                    </div>
                                    <div className="flex justify-between items-baseline">
                                        <span className="text-sm text-slate-500 dark:text-slate-400">Units Sold:</span>
                                        <span className="text-lg font-bold text-slate-800 dark:text-slate-200">{salesReportData.last90DaysUnitsSold.toLocaleString()}</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                        <div className="grid grid-cols-1 lg:grid-cols-5 gap-6">
                            <div className="lg:col-span-3 bg-white dark:bg-slate-800 p-6 rounded-lg shadow-sm">
                                <h3 className="font-semibold text-slate-800 dark:text-slate-100 mb-4">Revenue Trend</h3>
                                {isChartLoading ? (
                                    <div className="h-[300px] flex items-center justify-center"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div></div>
                                ) : salesReportData.revenueTrendData.length > 0 ? (
                                    <ResponsiveContainer width="100%" height={300}>
                                        <LineChart data={salesReportData.revenueTrendData} margin={{ top: 5, right: 20, left: -10, bottom: 5 }}>
                                            <CartesianGrid strokeDasharray="3 3" vertical={false} />
                                            <XAxis 
                                                dataKey="date" 
                                                fontSize={12} 
                                                tickFormatter={(tick) => {
                                                    const date = new Date(tick);
                                                    date.setDate(date.getDate() + 1);
                                                    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
                                                }}
                                                tickLine={false}
                                                axisLine={false}
                                            />
                                            <YAxis 
                                                fontSize={12} 
                                                tickFormatter={(value) => `Rs ${Number(value / 1000).toFixed(0)}k`}
                                                tickLine={false}
                                                axisLine={false}
                                            />
                                            <RechartsTooltip formatter={(value: number) => `Rs. ${value.toLocaleString()}`} />
                                            <Line type="monotone" dataKey="revenue" stroke="#10B981" name="Total Revenue" strokeWidth={2} dot={{ r: 4 }} activeDot={{ r: 8 }} />
                                        </LineChart>
                                    </ResponsiveContainer>
                                ) : (
                                    <div className="h-[300px] flex items-center justify-center">
                                        <p className="text-slate-500">No sales data for this period.</p>
                                    </div>
                                )}
                            </div>
                            <div className="lg:col-span-2 bg-white dark:bg-slate-800 p-6 rounded-lg shadow-sm">
                                <h3 className="font-semibold text-slate-800 dark:text-slate-100 mb-4">Sales by Category</h3>
                                {isChartLoading ? (
                                    <div className="h-[300px] flex items-center justify-center"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div></div>
                                ) : salesReportData.salesByCategory.length > 0 ? (
                                    <ResponsiveContainer width="100%" height={300}>
                                        <BarChart data={salesReportData.salesByCategory} margin={{ top: 5, right: 20, left: -10, bottom: 5 }} onClick={handleCategoryClick} className="cursor-pointer">
                                            <CartesianGrid strokeDasharray="3 3" vertical={false} />
                                            <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} />
                                            <YAxis fontSize={12} tickLine={false} axisLine={false} />
                                            <RechartsTooltip formatter={(value: number) => `${value.toLocaleString()} units`} />
                                            <Bar dataKey="units" name="Units Sold" radius={[4, 4, 0, 0]}>
                                                {salesReportData.salesByCategory.map((entry, index) => (
                                                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} opacity={!categoryFilter || categoryFilter === entry.name ? 1 : 0.4} className="transition-opacity" />
                                                ))}
                                            </Bar>
                                        </BarChart>
                                    </ResponsiveContainer>
                                ) : (
                                    <div className="h-[300px] flex items-center justify-center">
                                        <p className="text-slate-500">No sales data for this period.</p>
                                    </div>
                                )}
                            </div>
                        </div>
                         <div className="bg-white dark:bg-slate-800 p-6 rounded-lg shadow-sm">
                             <div className="flex justify-between items-center mb-4">
                                <div className="flex items-center gap-4">
                                    <h3 className="font-semibold text-slate-800 dark:text-slate-100">Sales Transactions</h3>
                                    {categoryFilter && (
                                        <div className="flex items-center space-x-2 bg-slate-100 dark:bg-slate-700 pl-3 pr-2 py-1 rounded-full text-sm no-print">
