import { Dealer, Product, StockItem, StockOrder, Booking, User, Role, DealerPayment, Announcement, AnnouncementRecipient, Conversation, Message } from '../types.ts';

const API_BASE = '/api';

// Helper to handle API requests
const request = async <T>(method: string, endpoint: string, data?: any): Promise<T> => {
    const headers: Record<string, string> = { 'Content-Type': 'application/json' };
    const userStr = localStorage.getItem('user');
    // In a real app with JWT, you'd send the token here. 
    // For now, we assume the backend handles session or we pass context headers if needed.

    const config: RequestInit = {
        method,
        headers,
        body: data ? JSON.stringify(data) : undefined,
    };

    const response = await fetch(`${API_BASE}${endpoint}`, config);

    if (!response.ok) {
        const errorBody = await response.json().catch(() => ({}));
        throw new Error(errorBody.message || `Request failed with status ${response.status}`);
    }

    return response.json();
};

export const api = {
    // --- Fetch Functions ---
    fetchUsers: () => request<User[]>('GET', '/users'),
    fetchRoles: () => request<Role[]>('GET', '/roles'),
    fetchDealers: () => request<Dealer[]>('GET', '/dealers'),
    fetchProducts: () => request<Product[]>('GET', '/products'),
    fetchStock: () => request<StockItem[]>('GET', '/stock'),
    fetchStockOrders: () => request<StockOrder[]>('GET', '/stock-orders'),
    fetchBookings: () => request<Booking[]>('GET', '/bookings'),
    fetchDealerPayments: () => request<DealerPayment[]>('GET', '/dealer-payments'),
    fetchAnnouncements: () => request<Announcement[]>('GET', '/announcements'),
    fetchAnnouncementRecipients: () => request<AnnouncementRecipient[]>('GET', '/announcement-recipients'),
    fetchConversations: () => request<Conversation[]>('GET', '/conversations'),
    fetchMessages: () => request<Message[]>('GET', '/messages'),

    // --- Mutation Functions ---
    saveUser: (user: Partial<User>) => request<User>(user._id && !user._id.startsWith('user-') ? 'PUT' : 'POST', user._id && !user._id.startsWith('user-') ? `/users/${user._id}` : '/users', user),
    deleteUser: (userId: string) => request<void>('DELETE', `/users/${userId}`),

    saveRole: (role: Partial<Role>) => request<Role>(role._id && !role._id.startsWith('role-') ? 'PUT' : 'POST', role._id && !role._id.startsWith('role-') ? `/roles/${role._id}` : '/roles', role),

    saveDealer: (dealer: Partial<Dealer>) => request<Dealer>(dealer._id && !dealer._id.startsWith('dealer-') ? 'PUT' : 'POST', dealer._id && !dealer._id.startsWith('dealer-') ? `/dealers/${dealer._id}` : '/dealers', dealer),

    saveProduct: (product: Partial<Product>) => request<Product>(product._id && !product._id.startsWith('prod-') ? 'PUT' : 'POST', product._id && !product._id.startsWith('prod-') ? `/products/${product._id}` : '/products', product),

    saveStockItem: (item: Partial<StockItem>) => request<StockItem>(item._id && !item._id.startsWith('stock-') ? 'PUT' : 'POST', item._id && !item._id.startsWith('stock-') ? `/stock/${item._id}` : '/stock', item),

    saveStockOrder: (order: Partial<StockOrder>) => request<StockOrder>(order._id && !order._id.startsWith('alloc-') ? 'PUT' : 'POST', order._id && !order._id.startsWith('alloc-') ? `/stock-orders/${order._id}` : '/stock-orders', order),

    saveBooking: (booking: Partial<Booking>) => request<Booking>(booking._id && !booking._id.startsWith('booking-') ? 'PUT' : 'POST', booking._id && !booking._id.startsWith('booking-') ? `/bookings/${booking._id}` : '/bookings', booking),

    saveDealerPayment: (payment: Partial<DealerPayment>) => request<DealerPayment>(payment._id && !payment._id.startsWith('dp-') ? 'PUT' : 'POST', payment._id && !payment._id.startsWith('dp-') ? `/dealer-payments/${payment._id}` : '/dealer-payments', payment),

    saveAnnouncement: (announcement: Partial<Announcement>) => request<Announcement>('POST', '/announcements', announcement),

    saveAnnouncementRecipient: (recipient: Partial<AnnouncementRecipient>) => request<AnnouncementRecipient>('PUT', `/announcement-recipients/${recipient._id}`, recipient),

    saveConversation: (conversation: Partial<Conversation>) => request<Conversation>(conversation._id && !conversation._id.startsWith('convo-') ? 'PUT' : 'POST', conversation._id && !conversation._id.startsWith('convo-') ? `/conversations/${conversation._id}` : '/conversations', conversation),

    saveMessage: (message: Partial<Message>) => request<Message>('POST', '/messages', message),

    // --- Complex Business Logic ---

    // Bulk update stock status
    saveBulkStockStatus: (stockIds: string[], status: any) => request<StockItem[]>('POST', '/stock/bulk-status', { stockIds, status }),

    // Process approved order: updates order status and assigns stock items
    saveApprovedOrder: (order: StockOrder, stockUpdates: StockItem[]) => request<{order: StockOrder, stock: StockItem[]}>('POST', '/stock-orders/approve', { order, stockUpdates }),

    // Dealer confirms receipt: updates order status to Delivered and stock to Available (for dealer)
    confirmOrderReceipt: (orderId: string) => request<{ order: StockOrder; stock: StockItem[] }>('POST', `/stock-orders/${orderId}/confirm-receipt`),
};

