import express from 'express';
import { User, Role, Dealer, Product, Stock, StockOrder, Booking, DealerPayment, Announcement, AnnouncementRecipient, Conversation, Message } from './models.js';

const router = express.Router();

// --- Generic CRUD Helper ---
const createCrud = (Model) => {
    return {
        getAll: async (req, res) => res.json(await Model.find().sort({ createdAt: -1 })),
        create: async (req, res) => res.json(await Model.create(req.body)),
        update: async (req, res) => res.json(await Model.findByIdAndUpdate(req.params.id, req.body, { new: true })),
        delete: async (req, res) => { await Model.findByIdAndDelete(req.params.id); res.sendStatus(204); }
    };
};

// --- Users ---
const userCtrl = createCrud(User);
router.get('/users', userCtrl.getAll);
router.post('/users', userCtrl.create);
router.put('/users/:id', userCtrl.update);
router.delete('/users/:id', userCtrl.delete);

// --- Roles ---
const roleCtrl = createCrud(Role);
router.get('/roles', roleCtrl.getAll);
router.post('/roles', roleCtrl.create);
router.put('/roles/:id', roleCtrl.update);

// --- Dealers ---
const dealerCtrl = createCrud(Dealer);
router.get('/dealers', dealerCtrl.getAll);
router.post('/dealers', dealerCtrl.create);
router.put('/dealers/:id', dealerCtrl.update);

// --- Products ---
const productCtrl = createCrud(Product);
router.get('/products', productCtrl.getAll);
router.post('/products', productCtrl.create);
router.put('/products/:id', productCtrl.update);

// --- Stock ---
const stockCtrl = createCrud(Stock);
router.get('/stock', stockCtrl.getAll);
router.post('/stock', stockCtrl.create);
router.put('/stock/:id', stockCtrl.update);

// Bulk Update Stock Status
router.post('/stock/bulk-status', async (req, res) => {
    const { stockIds, status } = req.body;
    await Stock.updateMany({ _id: { $in: stockIds } }, { status });
    const updatedItems = await Stock.find({ _id: { $in: stockIds } });
    res.json(updatedItems);
});

// --- Stock Orders ---
const orderCtrl = createCrud(StockOrder);
router.get('/stock-orders', orderCtrl.getAll);
router.post('/stock-orders', orderCtrl.create);
router.put('/stock-orders/:id', orderCtrl.update);

// Approve Order Logic
router.post('/stock-orders/approve', async (req, res) => {
    const { order, stockUpdates } = req.body;

    // Update Order
    const updatedOrder = await StockOrder.findByIdAndUpdate(order._id, order, { new: true });

    // Update Stock Items
    const updatedStockItems = [];
    for (const item of stockUpdates) {
        // When allocating, set status to Reserved until confirmed
        const updated = await Stock.findByIdAndUpdate(item._id, { ...item, status: 'Reserved' }, { new: true });
        updatedStockItems.push(updated);
    }

    res.json({ order: updatedOrder, stock: updatedStockItems });
});

// Confirm Receipt Logic
router.post('/stock-orders/:id/confirm-receipt', async (req, res) => {
    const orderId = req.params.id;
    const order = await StockOrder.findById(orderId);

    if (!order) return res.status(404).json({ message: "Order not found" });

    order.status = 'Delivered';
    await order.save();

    const updatedStockItems = [];
    if (order.allocatedStockIds && order.allocatedStockIds.length > 0) {
        // Update all allocated stock to 'Available' and ensure they are assigned to this dealer
