const createCrud = (Model) => {
    return {
        getAll: async (req, res) => res.json(await Model.find().sort({ createdAt: -1 })),
        create: async (req, res) => res.json(await Model.create(req.body)),
        // Enable upsert to allow creating records via PUT if the client provides an ID
        update: async (req, res) => res.json(await Model.findByIdAndUpdate(req.params.id, req.body, { new: true, upsert: true })),
        delete: async (req, res) => { await Model.findByIdAndDelete(req.params.id); res.sendStatus(204); }
    };
};

