// Helper for generic CRUD operations with Upsert support (Frontend generates IDs)
const createCrud = (Model) => ({
    getAll: async (req, res) => {
        try {
            const items = await Model.find().sort({ createdAt: -1 }); // Default sort by newest
            res.json(items);
        } catch (e) { res.status(500).json({ error: e.message }); }
    },
    create: async (req, res) => {
        try {
            const item = await Model.create(req.body);
            res.json(item);
        } catch (e) { res.status(500).json({ error: e.message }); }
    },
    update: async (req, res) => {
        try {
            // upsert: true allows creating if ID doesn't exist, matching frontend "save" behavior
            const item = await Model.findByIdAndUpdate(req.params.id, req.body, { new: true, upsert: true });
            res.json(item);
        } catch (e) { res.status(500).json({ error: e.message }); }
    },
    delete: async (req, res) => {
        try {
            await Model.findByIdAndDelete(req.params.id);
            res.status(200).send();
        } catch (e) { res.status(500).json({ error: e.message }); }
    }
});

