// Bulk update stock status (e.g., set multiple items to 'Sold')
router.post('/stock/bulk-status', async (req, res) => {
    try {
        const { stockIds, status } = req.body;
        await Stock.updateMany({ _id: { $in: stockIds } }, { status });
        const updatedItems = await Stock.find({ _id: { $in: stockIds } });
        res.json(updatedItems);
    } catch (e) { res.status(500).json({ error: e.message }); }
});

// Approve Order: Updates order status AND assigns specific stock items to the dealer
router.post('/stock-orders/approve', async (req, res) => {
    try {
        const { order, stockUpdates } = req.body;

        // 1. Save the order (upsert ensures creation if not exists)
        const updatedOrder = await StockOrder.findByIdAndUpdate(order._id, order, { new: true, upsert: true });

        // 2. Update all stock items involved
        // We iterate because each item might have specific updates (like dealerId assignment)
        const updatedStockItems = [];
        for (const item of stockUpdates) {
            const updated = await Stock.findByIdAndUpdate(item._id, { ...item, status: 'Reserved' }, { new: true, upsert: true });
            updatedStockItems.push(updated);
        }

        res.json({ order: updatedOrder, stock: updatedStockItems });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

// Confirm Receipt: Updates order to 'Delivered' AND sets allocated stock to 'Available'
router.post('/stock-orders/:id/confirm-receipt', async (req, res) => {
    try {
        const orderId = req.params.id;
        const order = await StockOrder.findById(orderId);

        if (!order) return res.status(404).json({ message: "Order not found" });

        order.status = 'Delivered';
        await order.save(); // Mongoose save()

        const updatedStockItems = [];
        if (order.allocatedStockIds && order.allocatedStockIds.length > 0) {
            // Bulk update status to Available
            await Stock.updateMany(
                { _id: { $in: order.allocatedStockIds } },
                { status: 'Available' }
            );
            // Fetch updated items to return to frontend
            const items = await Stock.find({ _id: { $in: order.allocatedStockIds } });
            updatedStockItems.push(...items);
        }

        res.json({ order, stock: updatedStockItems });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

