    const [settings, setSettings] = useStickyState<Settings>(initialSettings, 'dms-settings');

    useEffect(() => {
        const loadInitialData = async () => {
            try {
                const [fetchedRoles, fetchedUsers, fetchedLogs] = await Promise.all([
                    api.fetchRoles(),
                    api.fetchUsers(),
                    api.fetchAuditLogs(),
                ]);
                setRoles(fetchedRoles as Role[]);
                setUsers(fetchedUsers as User[]);
                setAuditLogs(fetchedLogs as AuditLog[]);
            } catch (err) {
                console.error("Failed to fetch app context data:", err);
            }
        };
        loadInitialData();
    }, []);

    const logAction = useCallback(async (action: ActionType, targetCollection?: string, targetId?: string, changes?: string) => {
        if (!user) return;
        const newLog: AuditLog = {
            _id: `log-${Date.now()}`,
            userId: user._id,
            userRole: user.role,
            action,
            targetCollection,
            targetId,
            changes,
            timestamp: new Date().toISOString()
        };

        // Optimistic update
        setAuditLogs(prev => [newLog, ...prev]);

        try {
            await api.saveAuditLog(newLog);
        } catch (e) {
            console.error("Failed to save audit log", e);
        }
    }, [user]);

    const addUser = async (userData: Omit<User, '_id'>): Promise<User> => {
        const newUserStub = { ...userData, _id: `user-${Date.now()}` };
        const savedUser = await api.saveUser(newUserStub);
        setUsers(prev => [...prev, savedUser]);
        logAction(ActionType.Create, 'Users', savedUser._id, `Created new user ${savedUser.name} with role ${savedUser.role}.`);
        return savedUser;
    };

    const updateUser = async (updatedUser: User) => {
        const savedUser = await api.saveUser(updatedUser);
        setUsers(prev => prev.map(u => u._id === savedUser._id ? savedUser : u));
        logAction(ActionType.Update, 'Users', savedUser._id, `Updated profile for ${savedUser.name}.`);
    };

    const deleteUser = async (userId: string) => {
        const userToDelete = users.find(u => u._id === userId);
        if (!userToDelete) return;
        await api.deleteUser(userId);
        setUsers(prev => prev.filter(u => u._id !== userId));
        logAction(ActionType.Delete, 'Users', userId, `Deleted user ${userToDelete.name}.`);
    };

     const addRole = async (roleData: Omit<Role, '_id'>): Promise<Role> => {
        const newRoleStub = { ...roleData, _id: `role-${Date.now()}` };
        const savedRole = await api.saveRole(newRoleStub);
        setRoles(prev => [...prev, savedRole]);
        logAction(ActionType.Create, 'Roles', savedRole._id, `Created new role '${savedRole.name}' with ${savedRole.permissions.length} permissions.`);
        return savedRole;
    };

    const updateRole = async (updatedRole: Role) => {
        const originalRole = roles.find(r => r._id === updatedRole._id);
        const savedRole = await api.saveRole(updatedRole);
        let changesDescription = `Updated role '${savedRole.name}'.`;

        if (originalRole) {
            const changes = [];
            if (originalRole.name !== savedRole.name) {
                changes.push(`Name changed from '${originalRole.name}' to '${savedRole.name}'.`);
            }
            const originalPerms = new Set<Permission>(originalRole.permissions);
            const updatedPerms = new Set<Permission>(savedRole.permissions);
            const added = [...updatedPerms].filter(p => !originalPerms.has(p));
            const removed = [...originalPerms].filter(p => !updatedPerms.has(p));

            if (added.length > 0) changes.push(`Added permissions: ${added.join(', ')}.`);
            if (removed.length > 0) changes.push(`Removed permissions: ${removed.join(', ')}.`);

            if (changes.length > 0) changesDescription = changes.join(' ');
        }

        setRoles(prev => prev.map(r => r._id === savedRole._id ? savedRole : r));
        logAction(ActionType.Update, 'Roles', savedRole._id, changesDescription);
    };

    const updateSettings = (newSettings: Partial<Settings>) => {
        setSettings(prev => ({...prev, ...newSettings}));
        logAction(ActionType.Update, 'Settings', undefined, `Updated system settings.`);
    };

    useEffect(() => {
        if (!isOnline) {
            setSyncStatus('offline');
        } else if (syncQueue.length > 0) {
            setSyncStatus('pending');
        } else {
            setSyncStatus('synced');
        }
    }, [isOnline, syncQueue.length]);

    const addToQueue = (item: SyncQueueItem) => {
        setSyncQueue(prev => [...prev, item]);
    };

    const markNotificationAsRead = (notificationId: string) => {
        setNotifications(prev => prev.map(n => n._id === notificationId ? { ...n, isRead: true } : n));
    };

    const toggleAutoApproval = () => {
        const newValue = !autoApprovalEnabled;
        setAutoApprovalEnabled(newValue);
        logAction(ActionType.Update, 'Settings', undefined, `Auto-approval ${newValue ? 'enabled' : 'disabled'}.`);
    };

    const processQueue = async (dataActions: any) => {
        if (syncQueue.length === 0) return;
        setSyncStatus('syncing');
        await new Promise(resolve => setTimeout(resolve, 1500));
        syncQueue.forEach(item => {
            switch (item.type) {
                case 'ADD_BOOKING': dataActions.addBooking(item.payload); break;
                case 'UPDATE_BOOKING': dataActions.updateBooking(item.payload); break;
                case 'ADD_PAYMENT': dataActions.addPayment(item.payload.bookingId, item.payload.payment); break;
                case 'ADD_STOCK_ORDER': dataActions.createStockOrder(item.payload); break;
            }
        });
        setSyncQueue([]);
        setSyncStatus('synced');
    };

    const backupState = (dataState: any) => {
        const state = { ...dataState, users, roles, auditLogs, notifications, autoApprovalEnabled, settings };
        const timestamp = new Date().toISOString();
        const fileName = `dms-backup-${timestamp.split('T')[0]}.json`;
        const blob = new Blob([JSON.stringify(state, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = fileName;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        const newBackupRecord: BackupRecord = {
            _id: `backup-${Date.now()}`,
            timestamp,
            fileName,
        };
        setBackupHistory(prev => [newBackupRecord, ...prev].slice(0, 10)); // Keep last 10
    };

    const restoreState = (newState: any, dataActions: any) => {
        dataActions.restoreDataState(newState);
        if (user?.role !== 'Dealer') {
            if (newState.users) setUsers(newState.users);
            if (newState.roles) setRoles(newState.roles);
            if (newState.auditLogs) setAuditLogs(newState.auditLogs);
            if (newState.notifications) setNotifications(newState.notifications);
            if (typeof newState.autoApprovalEnabled === 'boolean') setAutoApprovalEnabled(newState.autoApprovalEnabled);
            if (newState.settings) updateSettings(newState.settings);
        }
    };

    const removeDeviceSession = (sessionId: string) => {
        setDeviceSessions(prev => prev.filter(s => s._id !== sessionId));
        logAction(ActionType.Update, 'DeviceSessions', sessionId, `User logged out remote device session.`);
    };

    const value: AppContextType = {
        users, roles, auditLogs, notifications, setNotifications, deviceSessions, backupHistory,
        settings, isOnline, syncStatus, syncQueue, autoApprovalEnabled,
        markNotificationAsRead, removeDeviceSession,
        setIsOnline, processQueue, addToQueue, toggleAutoApproval,
        backupState, restoreState, updateSettings, logAction, addUser, updateUser, deleteUser,
        addRole, updateRole,
    };

    return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
};

import type * as React from 'react';
import { Permission } from './permissions.ts';

export interface Role {
    _id: string;
    name: string;
    permissions: Permission[];
    isEditable: boolean;
}

export interface User {
    _id: string;
    name: string;
    email: string;
    role: string; // Was Role enum, now a string to match Role.name
    dealerId?: string;
    password?: string;
    phone?: string;
    whatsapp?: string;
    address?: string;
}

export interface AuthContextType {
    isAuthenticated: boolean;
    user: User | null;
    login: (email: string, role: string) => void;
    logout: () => void;
    updateCurrentUser: (updatedUser: User) => void;
}

export interface Dealer {
    _id: string;
    name: string;
    ownerName: string;
    phone: string;
    email: string;
    city: string;
    registrationApproved: boolean;
    reputationScore: number;
    createdAt: string;
}

export interface ProductVariant {
    _id: string;
    name: string; // e.g. NA-70cc
    color: string; // e.g. Red
    sku: string;
    price: number;
}

export interface PriceHistory {
    price: number;
    timestamp: string;
}

export interface Product {
    _id: string;
    brand: string;
    modelName: string;
    variants: ProductVariant[];
    specifications: {
        engine: string;
        mileage: string;
    };
    priceHistory?: PriceHistory[];
}

export enum StockStatus {
    Available = 'Available',
    Reserved = 'Reserved',
    Sold = 'Sold',
}

export interface StockItem {
    _id: string;
    vin: string;
    variantId: string;
    dealerId: string | null; // Can be null for central stock
    status: StockStatus;
    assignedAt: string;
}

export enum ActionType {
    Create = 'CREATE',
    Update = 'UPDATE',
    Delete = 'DELETE',
    Login = 'LOGIN',
    Approve = 'APPROVE',
    Dispatch = 'DISPATCH',
}

export interface AuditLog {
    _id: string;
    userId: string;
    userRole: string; // Changed from 'role: Role'
    action: ActionType;
    targetCollection?: string;
    targetId?: string;
    changes?: string;
    timestamp: string;
}

export interface Notification {
    _id: string;
    message: string;
    timestamp: string;
    isRead: boolean;
    link?: { page: Page; state?: any };
}

export interface DeviceSession {
    _id: string;
    os: string;
    userAgent: string;
    ip: string;
    lastActive: string;
    isCurrent: boolean;
}

export enum BookingStatus {
    Pending = 'Pending',
    Allocated = 'Allocated',
    Delivered = 'Delivered',
    Cancelled = 'Cancelled',
}

export enum PaymentType {
    Cash = 'Cash',
    BankTransfer = 'Bank_Transfer',
    Card = 'Card',
}

export interface Payment {
    amount: number;
    type: PaymentType;
    timestamp: string;
    proofImage?: string;
}

export interface DealerPayment {
    _id: string;
    dealerId: string;
    stockOrderId?: string; // Optional: link payment to a specific order
    amount: number;
    type: PaymentType;
    reference?: string;
    timestamp: string;
    proofImage?: string;
}

export interface Booking {
    _id: string;
    customerName: string;
    customerPhone: string;
    dealerId: string;
    variantId: string;
    stockItemId?: string;
    bookingTimestamp: string;
    status: BookingStatus;
    payments: Payment[];
}

export interface Announcement {
    _id: string;
    subject: string;
    message: string;
    timestamp: string;
    sentByUserId: string;
}

export interface AnnouncementRecipient {
    _id: string;
    announcementId: string;
    userId: string;
    isRead: boolean;
}

export interface Conversation {
    _id: string;
    participantIds: string[];
    lastMessageTimestamp: string;
}

export interface Message {
    _id: string;
    conversationId: string;
    senderId: string;
    content: string;
    timestamp: string;
    isRead: boolean;
}


export type Page = 'Dashboard' | 'Dealers' | 'Products' | 'CompanyStock' | 'DealerStock' | 'Bookings' | 'Stock Orders' | 'Reports' | 'Audit Logs' | 'Settings' | 'DealerDetail' | 'Users' | 'Profile' | 'Approvals' | 'Announcements' | 'Messages' | 'Commission' | 'Finance';

export type DealerPage = 'Dashboard' | 'My Orders' | 'My Stock' | 'My Bookings' | 'My Backups' | 'Profile' | 'Announcements' | 'Messages';

export interface SyncQueueItem {
    type: 'ADD_STOCK_ORDER' | 'ADD_BOOKING' | 'UPDATE_BOOKING' | 'ADD_PAYMENT';
    payload: any;
    timestamp: number;
}


export interface StockOrderItem {
    productId: string;
    variantId: string;
    quantity: number;
}

export enum OrderStatus {
    Pending = 'Pending',
    Approved = 'Approved',
    PartiallyApproved = 'Partially Approved',
    Rejected = 'Rejected',
    Dispatched = 'Dispatched',
    InTransit = 'In-Transit',
    Delivered = 'Delivered',
}

export interface ApprovedOrderItem extends StockOrderItem {
    approvedQuantity: number;
}

export interface StockOrder {
    _id: string;
    dealerId: string;
    requestTimestamp: string;
    status: OrderStatus;
    items: StockOrderItem[];
    approvedItems?: ApprovedOrderItem[];
    allocatedStockIds?: string[];
}

export type RecommendationType = 'Approve' | 'Reject' | 'Review';

export interface Recommendation {
    type: RecommendationType;
    reason: string;
    mlQuantity?: number;
    mlReasoningFactors?: string[];
}

export interface BackupRecord {
    _id: string;
    timestamp: string;
    fileName: string;
}

export interface Settings {
    theme: 'light' | 'dark';
    notifications: {
        newOrder: boolean;
        orderApproved: boolean;
        orderRejected: boolean;
        lowStockWarning: boolean;
    };
}

export type SyncStatus = 'synced' | 'pending' | 'syncing' | 'error' | 'offline';

export interface AppContextType {
    users: User[];
    roles: Role[];
    auditLogs: AuditLog[];
    notifications: Notification[];
    setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
    deviceSessions: DeviceSession[];
    backupHistory: BackupRecord[];
    settings: Settings;
    isOnline: boolean;
    syncStatus: SyncStatus;
    syncQueue: SyncQueueItem[];
    autoApprovalEnabled: boolean;
    markNotificationAsRead: (notificationId: string) => void;
    removeDeviceSession: (sessionId: string) => void;
    setIsOnline: (isOnline: boolean) => void;
    processQueue: (dataActions: any) => Promise<void>;
    addToQueue: (item: SyncQueueItem) => void;
    toggleAutoApproval: () => void;
    backupState: (dataState: any) => void;
    restoreState: (newState: any, dataActions: any) => void;
    updateSettings: (newSettings: Partial<Settings>) => void;
    logAction: (action: ActionType, targetCollection?: string, targetId?: string, changes?: string) => void;
    addUser: (userData: Omit<User, '_id'>) => Promise<User>;
    updateUser: (updatedUser: User) => Promise<void>;
    deleteUser: (userId: string) => Promise<void>;
    addRole: (roleData: Omit<Role, '_id'>) => Promise<Role>;
    updateRole: (updatedRole: Role) => Promise<void>;
}


export interface DataContextType {
    isLoading: boolean;
    dealers: Dealer[];
    products: Product[];
    stock: StockItem[];
    stockOrders: StockOrder[];
    bookings: Booking[];
    dealerPayments: DealerPayment[];
    announcements: Announcement[];
    announcementRecipients: AnnouncementRecipient[];
    conversations: Conversation[];
    messages: Message[];
    addDealer: (dealerData: Omit<Dealer, '_id' | 'createdAt' | 'registrationApproved'>) => Promise<void>;
    updateDealer: (updatedDealer: Dealer) => Promise<void>;
    approveDealer: (dealerId: string) => Promise<void>;
    revokeDealer: (dealerId: string) => Promise<void>;
    updateDealerStatusBulk: (dealerIds: string[], approved: boolean) => Promise<void>;
    recalculateReputation: (dealerId: string) => Promise<void>;
    registerDealer: (dealerData: Omit<Dealer, '_id' | 'createdAt' | 'registrationApproved' | 'reputationScore'>) => Promise<Dealer>;
    addProduct: (productData: Omit<Product, '_id' | 'priceHistory'>) => Promise<void>;
    updateProduct: (updatedProduct: Product) => Promise<void>;
    addOrUpdateProductsBulk: (productsToImport: Omit<Product, '_id' | 'priceHistory'>[]) => Promise<{ created: number; updated: number; }>;
    addStock: (stockData: Omit<StockItem, '_id' | 'assignedAt'>) => Promise<void>;
    updateStockStatusBulk: (stockIds: string[], status: StockStatus) => Promise<void>;
    processAllocationRequest: (orderId: string, approvedItems: ApprovedOrderItem[], status: OrderStatus) => Promise<void>;
    dispatchStockOrder: (orderId: string) => Promise<void>;
    confirmOrderReceipt: (orderId: string) => Promise<void>;
    createStockOrder: (orderData: Omit<StockOrder, '_id' | 'requestTimestamp' | 'status' | 'approvedItems'>) => Promise<void>;
    addBooking: (bookingData: Omit<Booking, '_id' | 'bookingTimestamp' | 'payments' | 'stockItemId'>) => Promise<void>;
    updateBooking: (updatedBooking: Booking) => Promise<void>;
    cancelBooking: (bookingId: string) => Promise<void>;
    addPayment: (bookingId: string, payment: Payment) => Promise<void>;
    addDealerPayment: (paymentData: Omit<DealerPayment, '_id' | 'timestamp'>) => Promise<void>;
    allocateStockToBooking: (bookingId: string, stockItemId: string) => Promise<void>;
    addAnnouncement: (subject: string, message: string) => Promise<void>;
    markAnnouncementAsRead: (announcementId: string) => Promise<void>;
    sendMessage: (recipientId: string, content: string) => Promise<void>;
    markConversationAsRead: (conversationId: string) => Promise<void>;
    getRecommendationForItem: (item: StockOrderItem, dealerId: string) => Recommendation;
    restoreDataState: (newState: any) => void;
}

