import React, { useState, useMemo, useEffect } from 'react';
import { PaymentType, OrderStatus } from '../../types.ts';
import { useData } from '../../hooks/useData.ts';
import Spinner from '../shared/Spinner.tsx';
import { UploadCloudIcon, XCircleIcon } from '../icons/Icons.tsx';

interface DealerPaymentModalProps {
    isOpen: boolean;
    onClose: () => void;
    dealerId?: string; // Make dealerId optional
    showToast: (message: string, type: 'success' | 'error' | 'info') => void;
}

const DealerPaymentModal: React.FC<DealerPaymentModalProps> = ({ isOpen, onClose, dealerId, showToast }) => {
    const { addDealerPayment, stockOrders, dealers } = useData();
    const [selectedDealerId, setSelectedDealerId] = useState(dealerId || '');
    const [amount, setAmount] = useState('');
    const [type, setType] = useState<PaymentType>(PaymentType.BankTransfer);
    const [reference, setReference] = useState('');
    const [stockOrderId, setStockOrderId] = useState<string | undefined>(undefined);
    const [isSaving, setIsSaving] = useState(false);
    const [proofFile, setProofFile] = useState<File | null>(null);

    useEffect(() => {
        if (isOpen) {
            setSelectedDealerId(dealerId || (dealers.length > 0 ? dealers[0]._id : ''));
            setAmount('');
            setType(PaymentType.BankTransfer);
            setReference('');
            setStockOrderId(undefined);
            setProofFile(null);
        }
    }, [isOpen, dealerId, dealers]);


    const relevantOrders = useMemo(() => {
        if (!selectedDealerId) return [];
        return stockOrders.filter(order =>
            order.dealerId === selectedDealerId &&
            (order.status === OrderStatus.Approved || order.status === OrderStatus.PartiallyApproved || order.status === OrderStatus.Dispatched)
        );
    }, [stockOrders, selectedDealerId]);

    const convertToBase64 = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.readAsDataURL(file);
            reader.onload = () => resolve(reader.result as string);
            reader.onerror = error => reject(error);
        });
    };

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!amount || Number(amount) <= 0) {
            showToast("Please enter a valid payment amount.", "error");
            return;
        }
        if (!selectedDealerId) {
            showToast("Please select a dealer.", "error");
            return;
        }
        setIsSaving(true);
        try {
            let proofImage = undefined;
            if (proofFile) {
                proofImage = await convertToBase64(proofFile);
            }

            await addDealerPayment({
                dealerId: selectedDealerId,
                amount: Number(amount),
                type,
                reference,
                stockOrderId: stockOrderId || undefined,
                proofImage,
            });
            showToast("Payment recorded successfully!", "success");
            onClose();
        } catch (error) {
            showToast("Failed to record payment.", "error");
        } finally {
            setIsSaving(false);
        }
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setProofFile(e.target.files[0]);
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center p-4" onClick={onClose}>
            <div className="bg-white rounded-lg shadow-xl w-full max-w-lg" onClick={e => e.stopPropagation()}>
                <form onSubmit={handleSubmit}>
                    <div className="p-6 border-b">
                        <h3 className="text-xl font-semibold text-gray-800">Record Dealer Payment</h3>
                    </div>
                    <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                         {!dealerId && (
                             <div>
                                <label htmlFor="dealerSelect" className="block text-sm font-medium text-gray-700">Dealer</label>
                                 <select
                                    id="dealerSelect"
                                    value={selectedDealerId}
                                    onChange={(e) => setSelectedDealerId(e.target.value)}
                                    required
                                    className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                                >
                                    <option value="" disabled>Select a dealer...</option>
                                    {dealers.map(d => <option key={d._id} value={d._id}>{d.name}</option>)}
                                </select>
                            </div>
                         )}
                        <div>
                            <label htmlFor="amount" className="block text-sm font-medium text-gray-700">Amount (PKR)</label>
                            <input
                                type="number"
                                id="amount"
                                value={amount}
                                onChange={(e) => setAmount(e.target.value)}
                                required
                                min="1"
                                className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                                autoFocus
                            />
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label htmlFor="type" className="block text-sm font-medium text-gray-700">Payment Type</label>
                                <select
                                    id="type"
                                    value={type}
                                    onChange={(e) => setType(e.target.value as PaymentType)}
                                    required
                                    className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                                >
                                    {Object.values(PaymentType).map(t => <option key={t} value={t}>{String(t).replace('_', ' ')}</option>)}
                                </select>
                            </div>
                            <div>
                                <label htmlFor="stockOrderId" className="block text-sm font-medium text-gray-700">Link to Order (Optional)</label>
                                <select
                                    id="stockOrderId"
                                    value={stockOrderId || ''}
                                    onChange={(e) => setStockOrderId(e.target.value || undefined)}
                                    className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                                    disabled={!selectedDealerId}
                                >
                                    <option value="">None</option>
                                    {relevantOrders.map(order => (
                                        <option key={order._id} value={order._id}>
                                            Order #{order._id.slice(-6)} - {new Date(order.requestTimestamp).toLocaleDateString()}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <div>
                            <label htmlFor="reference" className="block text-sm font-medium text-gray-700">Reference / Notes</label>
                            <input
                                type="text"
                                id="reference"
                                value={reference}
                                onChange={(e) => setReference(e.target.value)}
                                placeholder="e.g., Invoice #, Cheque #"
                                className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Proof of Payment (Image)</label>
                            <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-gray-300 border-dashed rounded-md relative hover:border-primary transition-colors">
                                {proofFile ? (
                                    <div className="text-center">
                                        <p className="text-sm text-gray-900 font-medium truncate max-w-xs">{proofFile.name}</p>
                                        <button 
                                            type="button" 
                                            onClick={() => setProofFile(null)} 
                                            className="mt-2 inline-flex items-center text-xs text-red-600 hover:text-red-800"
                                        >
                                            <XCircleIcon className="w-4 h-4 mr-1" /> Remove
                                        </button>
                                    </div>
                                ) : (
                                    <div className="space-y-1 text-center">
                                        <UploadCloudIcon className="mx-auto h-12 w-12 text-gray-400" />
                                        <div className="flex text-sm text-gray-600 justify-center">
                                            <label htmlFor="file-upload" className="relative cursor-pointer bg-white rounded-md font-medium text-primary hover:text-secondary focus-within:outline-none focus-within:ring-2 focus-within:ring-offset-2 focus-within:ring-primary">
                                                <span>Upload a file</span>
                                                <input id="file-upload" name="file-upload" type="file" className="sr-only" accept="image/*" onChange={handleFileChange} />
                                            </label>
                                            <p className="pl-1">or drag and drop</p>
                                        </div>
                                        <p className="text-xs text-gray-500">PNG, JPG, GIF up to 5MB</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                    <div className="px-6 py-4 bg-gray-50 text-right space-x-2">
                        <button type="button" onClick={onClose} className="py-2 px-4 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50">Cancel</button>
                        <button type="submit" disabled={isSaving} className="w-36 flex justify-center py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary disabled:bg-slate-400">
                            {isSaving ? <Spinner /> : 'Save Payment'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default DealerPaymentModal;

import React, { useState, useMemo } from 'react';
import { useData } from '../../hooks/useData.ts';
import { Page, DealerPayment } from '../../types.ts';
import StatCard from '../shared/StatCard.tsx';
import { DollarSignIcon, UsersIcon, PrintIcon, ImageIcon } from '../icons/Icons.tsx';
import usePagination from '../../hooks/usePagination.ts';
import Pagination from '../shared/Pagination.tsx';
import EmptyState from '../shared/EmptyState.tsx';
import { printElementById } from '../../utils/print.ts';
import Tooltip from '../shared/Tooltip.tsx';
import DealerPaymentModal from '../modals/DealerPaymentModal.tsx';

const Finance: React.FC<{
    showToast: (message: string, type: 'success' | 'error' | 'info') => void;
}> = ({ showToast }) => {
    const { dealerPayments, dealers } = useData();
    const [dealerFilter, setDealerFilter] = useState('all');
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [isPaymentModalOpen, setPaymentModalOpen] = useState(false);
    const [selectedDealerId, setSelectedDealerId] = useState<string | undefined>(undefined);

    const paymentsWithDetails = useMemo(() => {
        return dealerPayments.map(p => ({
            ...p,
            dealerName: dealers.find(d => d._id === p.dealerId)?.name || 'Unknown Dealer',
        })).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
    }, [dealerPayments, dealers]);

    const filteredPayments = useMemo(() => {
        return paymentsWithDetails.filter(p => {
            if (dealerFilter !== 'all' && p.dealerId !== dealerFilter) return false;
            const paymentDate = new Date(p.timestamp);
            if (startDate && paymentDate < new Date(startDate)) return false;
            if (endDate && paymentDate > new Date(endDate)) return false;
            return true;
        });
    }, [paymentsWithDetails, dealerFilter, startDate, endDate]);

    const summaryStats = useMemo(() => {
        const totalReceived = filteredPayments.reduce((sum, p) => sum + p.amount, 0);
        const thirtyDaysAgo = new Date();
        thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
        const last30Days = filteredPayments.filter(p => new Date(p.timestamp) >= thirtyDaysAgo).reduce((sum, p) => sum + p.amount, 0);

        return { totalReceived, last30Days };
    }, [filteredPayments]);

    const { paginatedData, currentPage, totalPages, nextPage, prevPage } = usePagination(filteredPayments, 15);

    const handleOpenPaymentModal = (dealerId?: string) => {
        setSelectedDealerId(dealerId);
        setPaymentModalOpen(true);
    };

    const handleClearFilters = () => {
        setDealerFilter('all');
        setStartDate('');
        setEndDate('');
    };

    const openProof = (imageUrl: string) => {
        const w = window.open('about:blank');
        if (w) {
            const img = new Image();
            img.src = imageUrl;
            img.style.maxWidth = '100%';
            w.document.write(img.outerHTML);
            w.document.title = "Proof of Payment";
        }
    };

    return (
        <div id="finance-page-content" className="space-y-6">
            <div className="flex justify-between items-center no-print">
                <h2 className="text-3xl font-bold text-slate-800">Finance Ledger</h2>
                <div className="flex items-center space-x-2">
                    <Tooltip content="Print Current View">
                        <button onClick={() => printElementById('finance-page-content')} className="flex items-center justify-center p-2 border border-slate-300 shadow-sm rounded-md text-slate-700 bg-white hover:bg-slate-50 transition-colors">
                            <PrintIcon />
                        </button>
                    </Tooltip>
                    <button onClick={() => handleOpenPaymentModal()} className="py-2 px-4 text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary">
                        Record a Payment
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <StatCard title="Total Payments (Filtered)" value={`Rs. ${summaryStats.totalReceived.toLocaleString()}`} icon={<DollarSignIcon />} color="bg-green-500" />
                <StatCard title="Payments (Last 30d)" value={`Rs. ${summaryStats.last30Days.toLocaleString()}`} icon={<DollarSignIcon />} color="bg-blue-500" />
                <StatCard title="Total Dealers" value={dealers.length.toString()} icon={<UsersIcon />} color="bg-indigo-500" />
            </div>

             <div className="bg-white p-4 rounded-lg shadow-sm flex flex-col md:flex-row justify-between items-stretch gap-4 no-print">
                <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4 flex-wrap">
                    <div className="flex items-center">
                        <label className="text-sm font-medium text-slate-600 mr-2 shrink-0">Dealer:</label>
                        <select value={dealerFilter} onChange={e => setDealerFilter(e.target.value)} className="p-2 border border-slate-300 rounded-md shadow-sm text-sm w-full">
                            <option value="all">All</option>{dealers.map(d => <option key={d._id} value={d._id}>{d.name}</option>)}
                        </select>
                    </div>
                    <div className="flex items-center">
                        <label className="text-sm font-medium text-slate-600 mr-2 shrink-0">From:</label>
                        <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="p-2 border border-slate-300 rounded-md shadow-sm text-sm w-full" />
                    </div>
                    <div className="flex items-center">
                        <label className="text-sm font-medium text-slate-600 mr-2 shrink-0">To:</label>
                        <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="p-2 border border-slate-300 rounded-md shadow-sm text-sm w-full" />
                    </div>
                </div>
                 <button onClick={handleClearFilters} className="py-2 px-4 border border-slate-300 shadow-sm text-sm font-medium rounded-md text-slate-700 bg-white hover:bg-slate-50 transition-colors shrink-0">
                    Clear Filters
                </button>
            </div>


            <div className="bg-white rounded-lg shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-slate-200">
                        <thead className="bg-slate-100/80">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Date</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Dealer</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Amount (Rs)</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Type</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Reference / Linked Order</th>
                                <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase no-print">Proof</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-slate-200">
                            {paginatedData.length > 0 ? paginatedData.map(p => (
                                <tr key={p._id} className="hover:bg-slate-50">
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{new Date(p.timestamp).toLocaleString()}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-800">{p.dealerName}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm font-bold text-green-600">{p.amount.toLocaleString()}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{p.type.replace('_', ' ')}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 font-mono">
                                        {p.stockOrderId ? `Order #${p.stockOrderId.slice(-6)}` : p.reference || 'N/A'}
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 no-print">
                                        {p.proofImage ? (
                                            <Tooltip content="View Proof of Payment">
                                                <button onClick={() => openProof(p.proofImage!)} className="text-blue-600 hover:text-blue-800 p-1 hover:bg-blue-50 rounded">
                                                    <ImageIcon className="w-5 h-5"/>
                                                </button>
                                            </Tooltip>
                                        ) : <span className="text-xs text-gray-400">None</span>}
                                    </td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan={6}>
                                        <EmptyState icon={<DollarSignIcon className="w-12 h-12" />} title="No Payments Found" message="No payments match your current filter criteria." />
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
                <Pagination currentPage={currentPage} totalPages={totalPages} onNext={nextPage} onPrev={prevPage} />
            </div>
            {isPaymentModalOpen &&
                <DealerPaymentModal
                    isOpen={isPaymentModalOpen}
                    onClose={() => setPaymentModalOpen(false)}
                    dealerId={selectedDealerId || dealers[0]?._id}
                    showToast={showToast}
                />
            }
        </div>
    );
};

export default Finance;

import React, { useState, useMemo } from 'react';
import { useData } from '../../hooks/useData.ts';
import { Page, StockStatus, OrderStatus, BookingStatus, Product, ProductVariant, PaymentType, StockOrder } from '../../types.ts';
import { ArrowLeftIcon, BoxIcon, CalendarIcon, CheckSquareIcon, DollarSignIcon, StarIcon, PrintIcon, WhatsAppIcon, RefreshCwIcon, MessageSquareIcon, ImageIcon } from '../icons/Icons.tsx';
import StatCard from '../shared/StatCard.tsx';
import usePagination from '../../hooks/usePagination.ts';
import Pagination from '../shared/Pagination.tsx';
import EmptyState from '../shared/EmptyState.tsx';
import SkeletonLoader from '../shared/SkeletonLoader.tsx';
import { printElementById, createWhatsAppLink } from '../../utils/print.ts';
import Tooltip from '../shared/Tooltip.tsx';
import DealerPaymentModal from '../modals/DealerPaymentModal.tsx';
import { usePermissions } from '../../hooks/usePermissions.ts';
import { useAppContext } from '../../hooks/useAppContext.ts';

type DetailTab = 'overview' | 'stock' | 'orders' | 'bookings' | 'financials';

const DealerDetail: React.FC<{ dealerId: string; setActivePage: (page: Page, state?: any) => void; showToast: (message: string, type: 'success' | 'error' | 'info') => void; }> = ({ dealerId, setActivePage, showToast }) => {
    const { dealers, stock, stockOrders, bookings, products, isLoading, dealerPayments, recalculateReputation } = useData();
    const { users } = useAppContext();
    const { canRecalculateReputation } = usePermissions();
    const [activeTab, setActiveTab] = useState<DetailTab>('overview');
    const [isPaymentModalOpen, setPaymentModalOpen] = useState(false);
    const [isRecalculating, setIsRecalculating] = useState(false);

    const dealer = useMemo(() => dealers.find(d => d._id === dealerId), [dealers, dealerId]);

    const dealerStock = useMemo(() => stock.filter(s => s.dealerId === dealerId), [stock, dealerId]);
    const dealerOrders = useMemo(() => stockOrders.filter(o => o.dealerId === dealerId), [stockOrders, dealerId]);
    const dealerBookings = useMemo(() => bookings.filter(b => b.dealerId === dealerId), [bookings, dealerId]);
    const paymentsForDealer = useMemo(() => dealerPayments.filter(p => p.dealerId === dealerId), [dealerPayments, dealerId]);

    const findProductInfo = (variantId: string): { product: Product | null, variant: ProductVariant | null } => {
        for (const product of products) {
            const variant = product.variants.find(v => v._id === variantId);
            if (variant) return { product, variant };
        }
        return { product: null, variant: null };
    };

    const stats = useMemo(() => {
        const totalStockValue = dealerStock.reduce((sum, item) => {
            const { variant } = findProductInfo(item.variantId);
            return sum + (variant?.price || 0);
        }, 0);
        const pendingOrders = dealerOrders.filter(o => o.status === OrderStatus.Pending).length;
        const deliveredBookings = dealerBookings.filter(b => b.status === BookingStatus.Delivered);
        const totalRevenue = deliveredBookings.reduce((sum, booking) => {
            const { variant } = findProductInfo(booking.variantId);
            return sum + (variant?.price || 0);
        }, 0);

        return {
            totalStockValue,
            pendingOrders,
            totalRevenue,
            totalBookings: dealerBookings.length,
        };
    }, [dealerStock, dealerOrders, dealerBookings, products]);

    const getStatusChip = (status: StockStatus | OrderStatus | BookingStatus) => {
        let colorClasses = '';
        switch (status) {
            case StockStatus.Available:
            case OrderStatus.Approved:
            case BookingStatus.Delivered:
            case OrderStatus.Delivered:
                colorClasses = 'bg-green-100 text-green-800'; break;
            case StockStatus.Reserved:
            case OrderStatus.Pending:
            case BookingStatus.Pending:
                colorClasses = 'bg-yellow-100 text-yellow-800'; break;
            case StockStatus.Sold:
            case OrderStatus.Rejected:
            case BookingStatus.Cancelled:
                colorClasses = 'bg-red-100 text-red-800'; break;
            case OrderStatus.PartiallyApproved:
            case BookingStatus.Allocated:
                colorClasses = 'bg-blue-100 text-blue-800'; break;
            case OrderStatus.Dispatched:
            case OrderStatus.InTransit:
                colorClasses = 'bg-indigo-100 text-indigo-800'; break;
            default: colorClasses = 'bg-slate-100 text-slate-800';
        }
        return <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${colorClasses}`}>{status}</span>;
    };

    const handleRecalculate = async () => {
        if (!dealerId) return;
        setIsRecalculating(true);
        await recalculateReputation(dealerId);
        setIsRecalculating(false);
    }

    const getReputationScoreUI = (score: number) => {
        let colorClasses = '';
        if (score >= 8.0) colorClasses = 'text-green-600';
        else if (score >= 5.0) colorClasses = 'text-yellow-600';
        else colorClasses = 'text-red-600';
        return <div className={`flex items-center text-xl font-bold ${colorClasses}`}><StarIcon className="w-5 h-5 mr-1.5 fill-current" /><span>{score.toFixed(1)}</span></div>;
    };

    const handleSendMessage = () => {
        if (!dealer) return;
        const dealerUser = users.find(u => u.dealerId === dealer._id);
        if (dealerUser) {
            setActivePage('Messages', { recipientId: dealerUser._id });
        } else {
            showToast('Could not find a user associated with this dealer.', 'error');
        }
    };

    const openProof = (imageUrl: string) => {
        const w = window.open('about:blank');
        if (w) {
            const img = new Image();
            img.src = imageUrl;
            img.style.maxWidth = '100%';
            w.document.write(img.outerHTML);
            w.document.title = "Proof of Payment";
        }
    };

    const renderContent = () => {
        switch(activeTab) {
            case 'overview':
                return (
                    <div className="bg-white dark:bg-slate-800 p-6 rounded-lg shadow-sm space-y-8">
                        <div>
                            <h3 className="font-semibold text-slate-800 dark:text-slate-100 mb-4 text-lg">Dealer Information</h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div><strong>Owner:</strong> {dealer?.ownerName}</div>
                                <div><strong>Email:</strong> {dealer?.email}</div>
                                <div className="flex items-center">
                                    <strong className="mr-2">Phone:</strong>
                                    <a
                                        href={createWhatsAppLink(dealer?.phone || '')}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="flex items-center hover:text-green-600 dark:hover:text-green-400 transition-colors"
                                        aria-label="Chat on WhatsApp"
                                    >
                                        <span className="hover:underline">{dealer?.phone}</span>
                                        <Tooltip content="Chat on WhatsApp">
                                            <WhatsAppIcon className="w-5 h-5 ml-2 text-green-600 dark:text-green-400" />
                                        </Tooltip>
                                    </a>
                                </div>
                                <div><strong>City:</strong> {dealer?.city}</div>
                                <div><strong>Status:</strong> {dealer?.registrationApproved ? getStatusChip('Approved' as any) : getStatusChip('Pending' as any)}</div>
                                <div className="flex items-center gap-4">
                                    <strong>Reputation:</strong>
                                    {getReputationScoreUI(dealer?.reputationScore ?? 0)}
                                    {canRecalculateReputation &&
                                        <Tooltip content="Recalculate score based on recent performance">
                                            <button onClick={handleRecalculate} disabled={isRecalculating} className="p-1.5 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 hover:text-primary disabled:opacity-50 no-print">
                                                <RefreshCwIcon className={`w-4 h-4 ${isRecalculating ? 'animate-spin' : ''}`} />
                                            </button>
                                        </Tooltip>
                                    }
                                </div>
                            </div>
                        </div>

                        <div>
                            <h3 className="font-semibold text-slate-800 dark:text-slate-100 mb-4 text-lg border-t border-slate-200 dark:border-slate-700 pt-6">Key Performance Metrics</h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-4 gap-y-6 text-sm">
                                <div className="p-4 bg-slate-50 dark:bg-slate-700/50 rounded-lg">
                                    <p className="font-medium text-slate-500 dark:text-slate-400">Total Sales Revenue</p>
                                    <p className="text-2xl font-bold text-slate-800 dark:text-slate-100 mt-1">Rs. {stats.totalRevenue.toLocaleString()}</p>
                                </div>
                                 <div className="p-4 bg-slate-50 dark:bg-slate-700/50 rounded-lg">
                                    <p className="font-medium text-slate-500 dark:text-slate-400">Total Bookings (All Time)</p>
                                    <p className="text-2xl font-bold text-slate-800 dark:text-slate-100 mt-1">{stats.totalBookings}</p>
                                </div>
                                 <div className="p-4 bg-slate-50 dark:bg-slate-700/50 rounded-lg">
                                    <p className="font-medium text-slate-500 dark:text-slate-400">Current Stock Value</p>
                                    <p className="text-2xl font-bold text-slate-800 dark:text-slate-100 mt-1">Rs. {stats.totalStockValue.toLocaleString()}</p>
                                </div>
                                 <div className="p-4 bg-slate-50 dark:bg-slate-700/50 rounded-lg">
                                    <p className="font-medium text-slate-500 dark:text-slate-400">Pending Stock Orders</p>
                                    <p className="text-2xl font-bold text-slate-800 dark:text-slate-100 mt-1">{stats.pendingOrders}</p>
                                </div>
                            </div>
                        </div>
                    </div>
                );
            case 'stock': return <PaginatedTable columns={['VIN', 'Product', 'Status', 'Assigned']} data={dealerStock} renderRow={(item) => {
                const {product, variant} = findProductInfo(item.variantId);
                return (<>
                    <td className="px-6 py-4 whitespace-nowrap font-mono">{item.vin}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{product?.modelName} ({variant?.name})</td>
                    <td className="px-6 py-4 whitespace-nowrap">{getStatusChip(item.status)}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{new Date(item.assignedAt).toLocaleDateString()}</td>
                </>);
            }} />;
            case 'orders': return <PaginatedTable columns={['Date', 'Status', 'Requested', 'Approved']} data={dealerOrders} renderRow={(item) => {
                const totalReq = item.items.reduce((sum, i) => sum + i.quantity, 0);
                const totalApp = item.approvedItems?.reduce((sum, i) => sum + i.approvedQuantity, 0) ?? 'N/A';
                 return (<>
                    <td className="px-6 py-4 whitespace-nowrap">{new Date(item.requestTimestamp).toLocaleDateString()}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{getStatusChip(item.status)}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{totalReq} units</td>
                    <td className="px-6 py-4 whitespace-nowrap font-semibold">{totalApp} units</td>
                </>);
            }} />;
             case 'bookings': return <PaginatedTable columns={['Date', 'Customer', 'Product', 'Status']} data={dealerBookings} renderRow={(item) => {
                 const {product, variant} = findProductInfo(item.variantId);
                 return (<>
                    <td className="px-6 py-4 whitespace-nowrap">{new Date(item.bookingTimestamp).toLocaleDateString()}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{item.customerName}</td>
                    <td className="px-6 py-4 whitespace-nowrap">{product?.modelName} ({variant?.name})</td>
                    <td className="px-6 py-4 whitespace-nowrap">{getStatusChip(item.status)}</td>
                </>);
             }} />;
            case 'financials':
                const financialSummary = useMemo(() => {
                    const ordersWithValues = dealerOrders
                        .filter(o => o.status !== OrderStatus.Pending && o.status !== OrderStatus.Rejected)
                        .map(order => {
                            const orderValue = order.approvedItems?.reduce((sum, item) => {
                                const variant = findProductInfo(item.variantId).variant;
                                return sum + (item.approvedQuantity * (variant?.price || 0));
                            }, 0) ?? 0;

                            const paidAmount = paymentsForDealer
                                .filter(p => p.stockOrderId === order._id)
                                .reduce((sum, p) => sum + p.amount, 0);

                            return {
                                order,
                                orderValue,
                                paidAmount,
                                balance: orderValue - paidAmount,
                            };
                        });

                    const unlinkedPayments = paymentsForDealer.filter(p => !p.stockOrderId);
                    const totalOrderValue = ordersWithValues.reduce((sum, o) => sum + o.orderValue, 0);
                    const totalPaid = paymentsForDealer.reduce((sum, p) => sum + p.amount, 0);

                    return { ordersWithValues, unlinkedPayments, totalOrderValue, totalPaid, totalBalance: totalOrderValue - totalPaid };
                }, [dealerOrders, paymentsForDealer, products]);

                return (
                    <div className="space-y-6">
                        <div className="bg-white dark:bg-slate-800 p-6 rounded-lg shadow-sm">
                            <div className="flex justify-between items-center mb-4">
                                <h3 className="font-semibold text-slate-800 dark:text-slate-100 text-lg">Financial Summary</h3>
                                <button onClick={() => setPaymentModalOpen(true)} className="py-2 px-4 text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary no-print">Record Payment</button>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 border-t border-slate-200 dark:border-slate-700 pt-4">
                                <div><p className="text-sm text-slate-500 dark:text-slate-400">Total Approved Order Value</p><p className="text-2xl font-bold text-slate-800 dark:text-slate-100">Rs. {financialSummary.totalOrderValue.toLocaleString()}</p></div>
                                <div><p className="text-sm text-slate-500 dark:text-slate-400">Total Payments Received</p><p className="text-2xl font-bold text-green-600">Rs. {financialSummary.totalPaid.toLocaleString()}</p></div>
                                <div><p className="text-sm text-slate-500 dark:text-slate-400">Overall Balance</p><p className={`text-2xl font-bold ${financialSummary.totalBalance > 0 ? 'text-red-600' : 'text-slate-800 dark:text-slate-100'}`}>Rs. {financialSummary.totalBalance.toLocaleString()}</p></div>
                            </div>
                        </div>
                        <h4 className="font-medium text-slate-700 mt-4">Order Payment Status</h4>
                        <PaginatedTable columns={['Order Date', 'Order Value', 'Amount Paid', 'Balance']} data={financialSummary.ordersWithValues} renderRow={(item) => (
                             <>
                                <td className="px-6 py-4 whitespace-nowrap">{new Date(item.order.requestTimestamp).toLocaleDateString()}</td>
                                <td className="px-6 py-4 whitespace-nowrap">Rs. {item.orderValue.toLocaleString()}</td>
                                <td className="px-6 py-4 whitespace-nowrap text-green-600">Rs. {item.paidAmount.toLocaleString()}</td>
                                <td className={`px-6 py-4 whitespace-nowrap font-semibold ${item.balance > 0 ? 'text-red-600' : 'text-slate-800 dark:text-slate-200'}`}>Rs. {item.balance.toLocaleString()}</td>
                            </>
                         )} />

                         <h4 className="font-medium text-slate-700 mt-6">Recent Payments List</h4>
                         <PaginatedTable columns={['Date', 'Amount', 'Type', 'Reference', 'Proof']} data={paymentsForDealer} renderRow={(payment) => (
                             <>
                                <td className="px-6 py-4 whitespace-nowrap">{new Date(payment.timestamp).toLocaleDateString()}</td>
                                <td className="px-6 py-4 whitespace-nowrap font-bold text-green-600">Rs. {payment.amount.toLocaleString()}</td>
                                <td className="px-6 py-4 whitespace-nowrap capitalize">{payment.type.replace('_', ' ')}</td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{payment.reference || '-'}</td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 no-print">
                                    {payment.proofImage ? (
                                        <Tooltip content="View Proof">
                                            <button onClick={() => openProof(payment.proofImage!)} className="text-blue-600 hover:text-blue-800 p-1 hover:bg-blue-50 rounded">
                                                <ImageIcon className="w-5 h-5"/>
                                            </button>
                                        </Tooltip>
                                    ) : '-'}
                                </td>
                            </>
                         )} />
                    </div>
                );
        }
    }

    if (isLoading) return <SkeletonLoader type="table" rows={8} />;

    if (!dealer) {
        return <div className="text-center p-8 bg-white dark:bg-slate-800 rounded-lg">
            <h2 className="text-xl font-bold text-red-600">Dealer Not Found</h2>
            <p className="text-slate-500 mt-2">The requested dealer could not be found.</p>
            <button onClick={() => setActivePage('Dealers')} className="mt-4 flex items-center mx-auto text-sm font-semibold text-primary hover:underline">
                <ArrowLeftIcon className="w-4 h-4 mr-1" />
                Return to Dealers List
            </button>
        </div>;
    }

    return (
        <div id="dealer-detail-content" className="space-y-6">
            <div className="flex justify-between items-center no-print">
                <button onClick={() => setActivePage('Dealers')} className="flex items-center text-sm font-semibold text-primary hover:underline">
                    <ArrowLeftIcon className="w-4 h-4 mr-2" />
                    Back to Dealers List
                </button>
                <div className="flex items-center gap-2">
                    <Tooltip content="Send a message">
                        <button onClick={handleSendMessage} className="flex items-center justify-center p-2 border border-slate-300 dark:border-slate-600 shadow-sm rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                            <MessageSquareIcon />
                        </button>
                    </Tooltip>
                    <Tooltip content="Print Current View">
                        <button onClick={() => printElementById('dealer-detail-content')} className="flex items-center justify-center p-2 border border-slate-300 dark:border-slate-600 shadow-sm rounded-md text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                            <PrintIcon />
                        </button>
                    </Tooltip>
                </div>
            </div>

            <div>
                <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100">{dealer.name}</h2>
                <p className="text-slate-500 dark:text-slate-400">{dealer.city}</p>
            </div>

            <div className="hidden print-only">
                <h1 className="text-2xl font-bold mb-1">Dealer Summary: {dealer.name}</h1>
                <p className="text-sm text-slate-600 mb-4">Report for: {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} | Generated on: {new Date().toLocaleDateString()}</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 no-print">
                <StatCard title="Total Stock Value" value={`Rs. ${stats.totalStockValue.toLocaleString()}`} icon={<BoxIcon />} color="bg-blue-500" onClick={() => setActiveTab('stock')} />
                <StatCard title="Pending Orders" value={stats.pendingOrders.toString()} icon={<CheckSquareIcon />} color="bg-yellow-500" onClick={() => setActiveTab('orders')} />
                <StatCard title="Total Bookings" value={stats.totalBookings.toString()} icon={<CalendarIcon />} color="bg-green-500" onClick={() => setActiveTab('bookings')} />
                <StatCard title="Total Sales Revenue" value={`Rs. ${stats.totalRevenue.toLocaleString()}`} icon={<DollarSignIcon />} color="bg-indigo-500" onClick={() => setActiveTab('financials')} />
            </div>

            <div className="flex space-x-1 border-b border-slate-200 dark:border-slate-700 no-print">
                {(['overview', 'stock', 'orders', 'bookings', 'financials'] as DetailTab[]).map(tab => (
                    <button key={tab} onClick={() => setActiveTab(tab)} className={`px-4 py-2 text-sm font-semibold capitalize transition-colors ${activeTab === tab ? 'border-b-2 border-primary text-primary' : 'text-slate-500 dark:text-slate-400 hover:text-primary dark:hover:text-slate-200'}`}>
                        {tab}
                    </button>
                ))}
            </div>

             <div className="mt-4 animate-fade-in">
                {renderContent()}
            </div>
             <DealerPaymentModal 
                isOpen={isPaymentModalOpen} 
                onClose={() => setPaymentModalOpen(false)} 
                dealerId={dealerId} 
                showToast={showToast}
            />
        </div>
    );
};

const PaginatedTable: React.FC<{
    columns: string[];
    data: any[];
    renderRow: (item: any) => React.ReactNode;
}> = ({ columns, data, renderRow }) => {
    const { paginatedData, currentPage, totalPages, nextPage, prevPage } = usePagination(data, 5);

    return (
        <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm overflow-hidden">
            <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                    <thead className="bg-slate-100/80 dark:bg-slate-700/50">
                        <tr>
                            {columns.map(col => <th key={col} className="px-6 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">{col}</th>)}
                        </tr>
                    </thead>
                    <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
                        {paginatedData.length > 0 ? paginatedData.map((item, index) => <tr key={item._id || index} className="hover:bg-slate-50 dark:hover:bg-slate-700/50">{renderRow(item)}</tr>) : (
                             <tr><td colSpan={columns.length}><EmptyState icon={<BoxIcon/>} title="No Data Available" message="There are no records to display for this section." /></td></tr>
                        )}
                    </tbody>
                </table>
            </div>
            <Pagination currentPage={currentPage} totalPages={totalPages} onNext={nextPage} onPrev={prevPage} />
        </div>
    );
};

export default DealerDetail;

import React, { createContext, useState, useEffect, ReactNode, useCallback } from 'react';
import {
  Dealer, Product, StockItem, StockStatus, StockOrder, OrderStatus, ApprovedOrderItem,
  Booking, Payment, StockOrderItem, Recommendation, DataContextType, ActionType, ProductVariant, BookingStatus, DealerPayment, Announcement, AnnouncementRecipient,
  Conversation, Message, Notification
} from '../types.ts';
import { useAppContext } from '../hooks/useAppContext.ts';
import { useAuth } from '../hooks/useAuth.ts';
import { api } from '../api/index.ts';

export const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const { logAction, settings, setNotifications, users, notifications } = useAppContext();
    const { user } = useAuth();
    const [isLoading, setIsLoading] = useState(true);
    const [dealers, setDealers] = useState<Dealer[]>([]);
    const [products, setProducts] = useState<Product[]>([]);
    const [stock, setStock] = useState<StockItem[]>([]);
    const [stockOrders, setStockOrders] = useState<StockOrder[]>([]);
    const [bookings, setBookings] = useState<Booking[]>([]);
    const [dealerPayments, setDealerPayments] = useState<DealerPayment[]>([]);
    const [announcements, setAnnouncements] = useState<Announcement[]>([]);
    const [announcementRecipients, setAnnouncementRecipients] = useState<AnnouncementRecipient[]>([]);
    const [conversations, setConversations] = useState<Conversation[]>([]);
    const [messages, setMessages] = useState<Message[]>([]);


    useEffect(() => {
        const loadInitialData = async () => {
            setIsLoading(true);
            try {
                const [
                    dealersData,
                    productsData,
                    stockData,
                    stockOrdersData,
                    bookingsData,
                    dealerPaymentsData,
                    announcementsData,
                    announcementRecipientsData,
                    conversationsData,
                    messagesData,
                ] = await Promise.all([
                    api.fetchDealers(),
                    api.fetchProducts(),
                    api.fetchStock(),
                    api.fetchStockOrders(),
                    api.fetchBookings(),
                    api.fetchDealerPayments(),
                    api.fetchAnnouncements(),
                    api.fetchAnnouncementRecipients(),
                    api.fetchConversations(),
                    api.fetchMessages(),
                ]);
                setDealers(dealersData as Dealer[]);
                setProducts(productsData as Product[]);
                setStock(stockData as StockItem[]);
                setStockOrders(stockOrdersData as StockOrder[]);
                setBookings(bookingsData as Booking[]);
                setDealerPayments(dealerPaymentsData as DealerPayment[]);
                setAnnouncements(announcementsData as Announcement[]);
                setAnnouncementRecipients(announcementRecipientsData as AnnouncementRecipient[]);
                setConversations(conversationsData as Conversation[]);
                setMessages(messagesData as Message[]);
            } catch (error) {
                console.error("Failed to load initial data", error);
            } finally {
                setIsLoading(false);
            }
        };

        loadInitialData();
    }, []);

    useEffect(() => {
        if (isLoading || !user || user.role === 'Dealer') {
            return; // Don't run until data is loaded or for dealers
        }

        const now = new Date();
        const twentyFourHoursAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

        const newNotifications: Notification[] = [];

        // 1. Pending Stock Orders
        const oldPendingOrders = stockOrders.filter(
            o => o.status === OrderStatus.Pending && new Date(o.requestTimestamp) < twentyFourHoursAgo
        ).length;

        if (oldPendingOrders > 0) {
            const message = `${oldPendingOrders} stock order(s) have been pending approval for over 24 hours.`;
            if (!notifications.some(n => n.message === message && !n.isRead)) {
                newNotifications.push({
                    _id: `reminder-orders-${Date.now()}`,
                    message,
                    timestamp: now.toISOString(),
                    isRead: false,
                    link: { page: 'Approvals' } 
                });
            }
        }

        // 2. Pending Dealer Registrations
        const oldPendingDealers = dealers.filter(
            d => !d.registrationApproved && new Date(d.createdAt) < twentyFourHoursAgo
        ).length;

        if (oldPendingDealers > 0) {
            const message = `${oldPendingDealers} dealer registration(s) are awaiting approval for over 24 hours.`;
            if (!notifications.some(n => n.message === message && !n.isRead)) {
                newNotifications.push({
                    _id: `reminder-dealers-${Date.now()}`,
                    message,
                    timestamp: now.toISOString(),
                    isRead: false,
                    link: { page: 'Dealers' } 
                });
            }
        }

        // 3. Pending Bookings
        const oldPendingBookings = bookings.filter(
            b => b.status === BookingStatus.Pending && new Date(b.bookingTimestamp) < twentyFourHoursAgo
        ).length;

        if (oldPendingBookings > 0) {
            const message = `${oldPendingBookings} booking(s) are pending stock allocation for over 24 hours.`;
            if (!notifications.some(n => n.message === message && !n.isRead)) {
                newNotifications.push({
                    _id: `reminder-bookings-${Date.now()}`,
                    message,
                    timestamp: now.toISOString(),
                    isRead: false,
                    link: { page: 'Bookings' }
                });
            }
        }

        // 4. Low Stock Warning
        if (settings.notifications.lowStockWarning) {
             const centralStock = stock.filter(s => s.dealerId === null && s.status === StockStatus.Available);
             const variantCounts: Record<string, number> = {};
             centralStock.forEach(s => { variantCounts[s.variantId] = (variantCounts[s.variantId] || 0) + 1; });

             products.forEach(p => {
                 p.variants.forEach(v => {
                     const count = variantCounts[v._id] || 0;
                     if (count < 5) { // Threshold for low stock
                         const message = `Low stock warning: ${p.modelName} (${v.name}) has only ${count} units left.`;
                         // Avoid spamming: Check if notified in the last 24h
                         const recentlyNotified = notifications.some(n => 
                             n.message === message && 
                             new Date(n.timestamp) > twentyFourHoursAgo
                         );

                         if (!recentlyNotified) {
                             newNotifications.push({
                                 _id: `warn-stock-${v._id}-${Date.now()}`,
                                 message,
                                 timestamp: now.toISOString(),
                                 isRead: false,
                                 link: { page: 'CompanyStock' }
                             });
                         }
                     }
                 });
             });
        }

        if (newNotifications.length > 0) {
            setNotifications(prev => [...newNotifications, ...prev]);
        }
    }, [isLoading, stockOrders, dealers, bookings, user, setNotifications, notifications, stock, products, settings.notifications.lowStockWarning]);


    const getRecommendationForItem = useCallback((item: StockOrderItem, dealerId: string): Recommendation => {
        const centralStockCount = stock.filter(s => s.variantId === item.variantId && s.dealerId === null).length;
        const dealer = dealers.find(d => d._id === dealerId);

        if (!dealer) return { type: 'Review', reason: 'Dealer not found.' };

        const dealerStockForVariant = stock.filter(s => s.dealerId === dealer._id && s.variantId === item.variantId).length;
        const dealerDeliveredBookings = bookings.filter(b => b.dealerId === dealer._id && b.status === 'Delivered');
        const recentSalesForVariant = dealerDeliveredBookings.filter(b => 
            b.variantId === item.variantId && new Date(b.bookingTimestamp).getTime() > Date.now() - 30 * 24 * 60 * 60 * 1000
        ).length;
        const isOverstocked = dealerStockForVariant > Math.max(5, recentSalesForVariant * 2);

        const reputationFactor = 0.7 + (dealer.reputationScore / 10) * 0.3;
        const allDeliveredBookings = bookings.filter(b => b.status === 'Delivered');
        const variantSalesCount = allDeliveredBookings.filter(b => b.variantId === item.variantId).length;
        const totalSales = allDeliveredBookings.length;
        const uniqueVariantsSoldCount = new Set(allDeliveredBookings.map(b => b.variantId)).size;
        const averageSalesPerVariant = totalSales / (uniqueVariantsSoldCount || 1);
        const demandFactor = Math.max(0.9, Math.min(1.25, 1 + ((variantSalesCount - averageSalesPerVariant) / (averageSalesPerVariant * 2 || 1))));

        const now = Date.now();
        const thirtyDaysAgo = now - 30 * 24 * 60 * 60 * 1000;
        const ninetyDaysAgo = now - 90 * 24 * 60 * 60 * 1000;
        const last30DaysSales = dealerDeliveredBookings.filter(b => new Date(b.bookingTimestamp).getTime() > thirtyDaysAgo).length;
        const prev60DaysSales = dealerDeliveredBookings.filter(b => {
            const ts = new Date(b.bookingTimestamp).getTime();
            return ts <= thirtyDaysAgo && ts > ninetyDaysAgo;
        }).length;
        const normalizedPrevSales = prev60DaysSales / 2;
        let velocityFactor = 1.0;
        if (last30DaysSales > normalizedPrevSales + 1) velocityFactor = 1.1;
        else if (last30DaysSales < normalizedPrevSales) velocityFactor = 0.95;

        const combinedFactor = reputationFactor * demandFactor * velocityFactor;
        const mlOptimalQty = Math.min(item.quantity, Math.round(item.quantity * combinedFactor));

        const getMlExplanation = (): { reason: string; factors: string[] } => {
            const factors: string[] = [];
            if (demandFactor > 1.1) factors.push("high demand");
            if (velocityFactor > 1.0) factors.push("positive sales trend");
            else if (velocityFactor < 1.0) factors.push("sales slowdown");
            if (dealer.reputationScore > 8.5) factors.push("strong reputation");
            if (factors.length === 0) return { reason: 'ML predicts standard sales potential.', factors: [] };
            return { reason: `Suggestion based on ${factors.join(' & ')}.`, factors };
        };

        const mlExplanation = getMlExplanation();

        if (isOverstocked) {
            return { type: 'Reject', reason: `Overstocked: Dealer already holds ${dealerStockForVariant} units.` };
        }

        if (centralStockCount === 0) return { type: 'Reject', reason: 'Critical Stock: No units available.' };
        if (dealer.reputationScore >= 9 && centralStockCount >= item.quantity) return { type: 'Approve', reason: `Elite Dealer (${dealer.reputationScore.toFixed(1)}) with sufficient stock.` };

        const isLowReputation = dealer.reputationScore < 5;
        const isStockLimited = centralStockCount < item.quantity;

        if (isLowReputation || isStockLimited) {
            let reason = isLowReputation ? `Low dealer reputation score (${dealer.reputationScore.toFixed(1)}).` : `Limited Stock: Only ${centralStockCount} units available.`;
            if (isLowReputation && isStockLimited) reason = `Low Reputation (${dealer.reputationScore.toFixed(1)}) and Limited Stock (${centralStockCount} available).`;
            return { type: 'Review', reason: `${reason} Manual review flagged.`, mlQuantity: mlOptimalQty, mlReasoningFactors: mlExplanation.factors };
        }

        return { type: 'Review', reason: mlExplanation.reason, mlQuantity: mlOptimalQty, mlReasoningFactors: mlExplanation.factors };
    }, [dealers, stock, bookings]);

    const addDealer = async (dealerData: Omit<Dealer, '_id' | 'createdAt' | 'registrationApproved'>) => {
        const newDealerStub: Dealer = { ...dealerData, _id: `dealer-${Date.now()}`, createdAt: new Date().toISOString(), registrationApproved: true };
        const savedDealer = await api.saveDealer(newDealerStub);
        setDealers(prev => [...prev, savedDealer]);
        logAction(ActionType.Create, 'Dealers', savedDealer._id, `Created new dealer ${savedDealer.name}`);
    };

    const registerDealer = async (dealerData: Omit<Dealer, '_id' | 'createdAt' | 'registrationApproved' | 'reputationScore'>) => {
        const newDealerStub: Dealer = { ...dealerData, _id: `dealer-${Date.now()}`, createdAt: new Date().toISOString(), registrationApproved: false, reputationScore: 5.0 };
        const newDealer = await api.saveDealer(newDealerStub);
        setDealers(prev => [...prev, newDealer]);
        logAction(ActionType.Create, 'Dealers', newDealer._id, `New dealer registration: ${newDealer.name}`);
        return newDealer;
    };

    const updateDealer = async (updatedDealer: Dealer) => {
        const savedDealer = await api.saveDealer(updatedDealer);
        setDealers(prev => prev.map(d => d._id === savedDealer._id ? savedDealer : d));
        logAction(ActionType.Update, 'Dealers', savedDealer._id, `Updated details for ${savedDealer.name}`);
    };

    const approveDealer = async (dealerId: string) => {
        const dealer = dealers.find(d => d._id === dealerId);
        if (!dealer) return;
        const updatedDealer = { ...dealer, registrationApproved: true };
        const savedDealer = await api.saveDealer(updatedDealer);
        setDealers(prev => prev.map(d => d._id === savedDealer._id ? savedDealer : d));
        logAction(ActionType.Approve, 'Dealers', dealerId, `Approved registration for ${savedDealer?.name}`);
    };

    const revokeDealer = async (dealerId: string) => {
        const dealer = dealers.find(d => d._id === dealerId);
        if (!dealer) return;
        const updatedDealer = { ...dealer, registrationApproved: false };
        const savedDealer = await api.saveDealer(updatedDealer);
        setDealers(prev => prev.map(d => d._id === savedDealer._id ? savedDealer : d));
        logAction(ActionType.Update, 'Dealers', dealerId, `Revoked approval for ${savedDealer.name}.`);
    };

    const updateDealerStatusBulk = async (dealerIds: string[], approved: boolean) => {
        const dealersToUpdate = dealers.filter(d => dealerIds.includes(d._id));
        if (dealersToUpdate.length === 0) return;

        const updatedDealerObjects = dealersToUpdate.map(d => ({ ...d, registrationApproved: approved }));

        await Promise.all(updatedDealerObjects.map(api.saveDealer));

        setDealers(prevDealers => 
            prevDealers.map(d => {
                const updatedVersion = updatedDealerObjects.find(ud => ud._id === d._id);
                return updatedVersion || d;
            })
        );
        logAction(ActionType.Update, 'Dealers', undefined, `Bulk ${approved ? 'approved' : 'revoked'} ${dealerIds.length} dealers.`);
    };

    const recalculateReputation = async (dealerId: string) => {
        const dealer = dealers.find(d => d._id === dealerId);
        if (!dealer) return;
        const newScore = parseFloat((Math.random() * 5 + 5).toFixed(1)); // Score between 5.0 and 10.0
        const updatedDealer = { ...dealer, reputationScore: newScore };
        const savedDealer = await api.saveDealer(updatedDealer);
        setDealers(prev => prev.map(d => d._id === dealerId ? savedDealer : d));
        logAction(ActionType.Update, 'Dealers', dealerId, `Recalculated reputation score for ${dealer.name} to ${newScore}.`);
    };

    const addProduct = async (productData: Omit<Product, '_id' | 'priceHistory'>) => {
        const newProductStub: Product = { ...productData, _id: `prod-${Date.now()}`, priceHistory: [] };
        const newProduct = await api.saveProduct(newProductStub);
        setProducts(prev => [...prev, newProduct]);
        logAction(ActionType.Create, 'Products', newProduct._id, `Created product ${newProduct.modelName}`);
    };

    const updateProduct = async (updatedProduct: Product) => {
        const oldProduct = products.find(p => p._id === updatedProduct._id);
        const savedProduct = await api.saveProduct(updatedProduct);

        let changeDetails: string[] = [];

        if (oldProduct) {
            if (oldProduct.brand !== savedProduct.brand) changeDetails.push(`Brand: ${oldProduct.brand} -> ${savedProduct.brand}`);
            if (oldProduct.modelName !== savedProduct.modelName) changeDetails.push(`Model: ${oldProduct.modelName} -> ${savedProduct.modelName}`);

            // Compare Variants
            const oldVariantsMap = new Map(oldProduct.variants.map(v => [v._id, v]));
            const newVariantsMap = new Map(savedProduct.variants.map(v => [v._id, v]));

            // Check updates and additions
            savedProduct.variants.forEach(newVar => {
                const oldVar = oldVariantsMap.get(newVar._id);
                if (oldVar) {
                    if (oldVar.price !== newVar.price) {
                        changeDetails.push(`Price (${newVar.name} - ${newVar.color}): ${oldVar.price} -> ${newVar.price}`);
                    }
                    if (oldVar.sku !== newVar.sku) {
                        changeDetails.push(`SKU (${newVar.name} - ${newVar.color}): ${oldVar.sku} -> ${newVar.sku}`);
                    }
                } else {
                    changeDetails.push(`Added variant: ${newVar.name} (${newVar.color})`);
                }
            });

            // Check deletions
            oldProduct.variants.forEach(oldVar => {
                if (!newVariantsMap.has(oldVar._id)) {
                    changeDetails.push(`Removed variant: ${oldVar.name} (${oldVar.color})`);
                }
            });
        }

        const logMessage = changeDetails.length > 0 
            ? `Updated product ${savedProduct.modelName}: ${changeDetails.join(', ')}`
            : `Updated product ${savedProduct.modelName} (No detected changes)`;

        setProducts(prev => prev.map(p => p._id === savedProduct._id ? savedProduct : p));
        logAction(ActionType.Update, 'Products', savedProduct._id, logMessage);
    };

    const addOrUpdateProductsBulk = async (productsToImport: Omit<Product, '_id' | 'priceHistory'>[]): Promise<{ created: number; updated: number; }> => {
        let createdCount = 0;
        let updatedCount = 0;

        const newProductList: Product[] = JSON.parse(JSON.stringify(products));

        for (const productFromCsv of productsToImport) {
            const productIndex = newProductList.findIndex((p: Product) =>
                p.brand.toLowerCase() === productFromCsv.brand.toLowerCase() &&
                p.modelName.toLowerCase() === productFromCsv.modelName.toLowerCase()
            );

            if (productIndex !== -1) {
                const existingProduct = newProductList[productIndex];
                let hasChanges = false;

                const existingVariantsBySku = new Map(existingProduct.variants.map((v: ProductVariant) => [v.sku.toLowerCase(), v]));

                for (const variantFromCsv of productFromCsv.variants) {
                    const existingVariant = existingVariantsBySku.get(variantFromCsv.sku.toLowerCase());

                    if (existingVariant) {
                        if (existingVariant.name !== variantFromCsv.name || existingVariant.price !== variantFromCsv.price) {
                            existingVariant.name = variantFromCsv.name;
                            existingVariant.price = variantFromCsv.price;
                            hasChanges = true;
                        }
                    } else {
                        existingProduct.variants.push({
                            ...variantFromCsv,
                            _id: `v-new-${Date.now()}-${Math.random()}`
                        });
                        hasChanges = true;
                    }
                }

                if (hasChanges) {
                    await api.saveProduct(existingProduct); 
                    updatedCount++;
                }
            } else {
                const newProduct: Product = {
                    ...productFromCsv,
                    _id: `prod-new-${Date.now()}-${Math.random()}`,
                    priceHistory: [],
                    variants: productFromCsv.variants.map(v => ({
                        ...v,
                        _id: `v-new-${Date.now()}-${Math.random()}`
                    }))
                };
                newProductList.push(newProduct);
                await api.saveProduct(newProduct); 
                createdCount++;
            }
        }

        if (createdCount > 0 || updatedCount > 0) {
            setProducts(newProductList);
            logAction(ActionType.Update, 'Products', undefined, `Bulk import: ${createdCount} created, ${updatedCount} updated.`);
        }

        return { created: createdCount, updated: updatedCount };
    };

    const addStock = async (stockData: Omit<StockItem, '_id' | 'assignedAt'>) => {
        const newStockItem: StockItem = {
            ...stockData,
            _id: `stock-${Date.now()}`,
            assignedAt: new Date().toISOString(),
        };
        const savedItem = await api.saveStockItem(newStockItem);
        setStock(prev => [savedItem, ...prev]);
        logAction(ActionType.Create, 'Stock', savedItem._id, `Added new stock item with VIN ${savedItem.vin}`);
    };

    const updateStockStatusBulk = async (stockIds: string[], status: StockStatus) => {
        const updatedItems = await api.saveBulkStockStatus(stockIds, status);
        setStock(prev => prev.map(s => {
            const updated = updatedItems.find(i => i._id === s._id);
            return updated ? updated : s;
        }));
        logAction(ActionType.Update, 'Stock', undefined, `Bulk updated ${stockIds.length} items to ${status}`);
    };

    const processAllocationRequest = async (orderId: string, approvedItems: ApprovedOrderItem[], status: OrderStatus) => {
        const order = stockOrders.find(o => o._id === orderId);
        if (!order) return;

        const stockToUpdate: StockItem[] = [];
        const allocatedStockIds: string[] = [];
        let anyStockAssigned = false;

        for (const item of approvedItems) {
            if (item.approvedQuantity > 0) {
                const availableStock = stock.filter(s => s.variantId === item.variantId && s.dealerId === null && s.status === StockStatus.Available);
                const itemsToAssign = availableStock.slice(0, item.approvedQuantity);

                if (itemsToAssign.length > 0) anyStockAssigned = true;

                for (const stockItem of itemsToAssign) {
                    stockToUpdate.push({ ...stockItem, dealerId: order.dealerId, assignedAt: new Date().toISOString() });
                    allocatedStockIds.push(stockItem._id);
                }
            }
        }

        const updatedOrder: StockOrder = { ...order, status, approvedItems, allocatedStockIds };

        const { order: savedOrder, stock: savedStock } = await api.saveApprovedOrder(updatedOrder, stockToUpdate);

        setStockOrders(prev => prev.map(o => o._id === savedOrder._id ? savedOrder : o));

        setStock(prev => prev.map(s => {
            const updated = savedStock.find(i => i._id === s._id);
            return updated || s;
        }));

        logAction(ActionType.Approve, 'StockOrders', orderId, `Order processed with status: ${status}.`);

        // Notification Logic
        if (status === OrderStatus.Rejected && settings.notifications.orderRejected) {
             setNotifications(prev => [{
                _id: `notif-rej-${Date.now()}`,
                message: `Stock order #${orderId.slice(-4)} was rejected.`,
                timestamp: new Date().toISOString(),
                isRead: false,
                link: { page: 'Stock Orders' }
            }, ...prev]);
        }

        if (anyStockAssigned && settings.notifications.orderApproved) {
            setNotifications(prev => [{
                _id: `notif-${Date.now()}`,
                message: `Stock has been allocated for order #${orderId.slice(-4)}.`,
                timestamp: new Date().toISOString(),
                isRead: false,
                link: { page: 'Stock Orders' }
            }, ...prev]);
        }
    };

    const dispatchStockOrder = async (orderId: string) => {
        const order = stockOrders.find(o => o._id === orderId);
        if (!order) throw new Error("Order not found");

        const updatedOrder = { ...order, status: OrderStatus.Dispatched };
        const savedOrder = await api.saveStockOrder(updatedOrder);

        setStockOrders(prev => prev.map(o => o._id === savedOrder._id ? savedOrder : o));
        logAction(ActionType.Dispatch, 'StockOrders', orderId, `Order #${orderId.slice(-4)} marked as dispatched.`);
    };

    const confirmOrderReceipt = async (orderId: string) => {
        const { order: updatedOrder, stock: updatedStock } = await api.confirmOrderReceipt(orderId);

        setStockOrders(prev => prev.map(o => o._id === updatedOrder._id ? updatedOrder : o));

        setStock(prev => prev.map(s => {
            const updated = updatedStock.find(us => us._id === s._id);
            return updated || s;
        }));

        logAction(ActionType.Update, 'StockOrders', orderId, `Dealer confirmed receipt of order #${orderId.slice(-4)}.`);
    };

    const createStockOrder = async (orderData: Omit<StockOrder, '_id' | 'requestTimestamp' | 'status' | 'approvedItems'>) => {
        const newOrder: StockOrder = {
            ...orderData,
            _id: `alloc-${Date.now()}`,
            requestTimestamp: new Date().toISOString(),
            status: OrderStatus.Pending,
        };
        const savedOrder = await api.saveStockOrder(newOrder);
        setStockOrders(prev => [savedOrder, ...prev]);
        logAction(ActionType.Create, 'StockOrders', savedOrder._id, `New stock order created by dealer ${savedOrder.dealerId}`);
        if (settings.notifications.newOrder) {
            setNotifications(prev => [{
                _id: `notif-${Date.now()}`,
                message: `New stock order #${savedOrder._id.slice(-4)} is pending review.`,
                timestamp: new Date().toISOString(),
                isRead: false,
                link: { page: 'Approvals' }
            }, ...prev]);
        }
    };

    const addBooking = async (bookingData: Omit<Booking, '_id' | 'bookingTimestamp' | 'payments' | 'stockItemId'>) => {
        const newBooking: Booking = {
            ...bookingData,
            _id: `booking-${Date.now()}`,
            bookingTimestamp: new Date().toISOString(),
            payments: [],
        };
        const savedBooking = await api.saveBooking(newBooking);
        setBookings(prev => [savedBooking, ...prev]);
        logAction(ActionType.Create, 'Bookings', savedBooking._id, `New booking for ${savedBooking.customerName}`);
    };

    const updateBooking = async (updatedBooking: Booking) => {
        const savedBooking = await api.saveBooking(updatedBooking);
        setBookings(prev => prev.map(b => b._id === savedBooking._id ? savedBooking : b));
        logAction(ActionType.Update, 'Bookings', savedBooking._id, `Updated booking for ${savedBooking.customerName}`);
    };

    const cancelBooking = async (bookingId: string) => {
        const bookingToCancel = bookings.find(b => b._id === bookingId);
        if (!bookingToCancel) throw new Error("Booking not found");

        const updatedBooking: Booking = { ...bookingToCancel, status: BookingStatus.Cancelled };

        let savedStockItem: StockItem | null = null;
        if (bookingToCancel.stockItemId) {
            const stockItemToRelease = stock.find(s => s._id === bookingToCancel.stockItemId);
            if (stockItemToRelease && stockItemToRelease.status === StockStatus.Reserved) {
                const updatedStockItem: StockItem = { ...stockItemToRelease, status: StockStatus.Available, dealerId: null };
                savedStockItem = await api.saveStockItem(updatedStockItem);
            }
        }

        const savedBooking = await api.saveBooking(updatedBooking);

        setBookings(prev => prev.map(b => b._id === savedBooking._id ? savedBooking : b));
        if (savedStockItem) {
            setStock(prev => prev.map(s => s._id === savedStockItem!._id ? savedStockItem! : s));
        }

        logAction(ActionType.Update, 'Bookings', bookingId, `Cancelled booking for ${savedBooking.customerName}`);
    };

    const addPayment = async (bookingId: string, payment: Payment) => {
        const booking = bookings.find(b => b._id === bookingId);
        if (!booking) return;
        const updatedBooking = { ...booking, payments: [...booking.payments, payment] };
        const savedBooking = await api.saveBooking(updatedBooking);
        setBookings(prev => prev.map(b => b._id === savedBooking._id ? savedBooking : b));
        logAction(ActionType.Update, 'Bookings', bookingId, `Added payment of Rs. ${payment.amount} for ${booking.customerName}`);
    };

    const addDealerPayment = async (paymentData: Omit<DealerPayment, '_id' | 'timestamp'>) => {
        const newPayment: DealerPayment = {
            ...paymentData,
            _id: `dp-${Date.now()}`,
            timestamp: new Date().toISOString(),
        };
        const savedPayment = await api.saveDealerPayment(newPayment);
        setDealerPayments(prev => [savedPayment, ...prev]);
        const dealerName = dealers.find(d => d._id === savedPayment.dealerId)?.name || 'a dealer';
        logAction(ActionType.Create, 'DealerPayments', savedPayment._id, `Recorded payment of Rs. ${savedPayment.amount} from ${dealerName}`);
    };

    const allocateStockToBooking = async (bookingId: string, stockItemId: string) => {
        const booking = bookings.find(b => b._id === bookingId);
        const stockItem = stock.find(s => s._id === stockItemId);

        if (!booking || !stockItem) {
            throw new Error('Booking or Stock Item not found');
        }

        const updatedBooking: Booking = {
            ...booking,
            status: BookingStatus.Allocated,
            stockItemId: stockItemId,
        };
        const updatedStockItem: StockItem = {
            ...stockItem,
            status: StockStatus.Reserved,
            dealerId: booking.dealerId, // Ensure stock is assigned to dealer
        };

        const [savedBooking, savedStockItem] = await Promise.all([
            api.saveBooking(updatedBooking),
            api.saveStockItem(updatedStockItem),
        ]);

        setBookings(prev => prev.map(b => b._id === savedBooking._id ? savedBooking : b));
        setStock(prev => prev.map(s => s._id === savedStockItem._id ? savedStockItem : s));

        logAction(ActionType.Update, 'Bookings', bookingId, `Allocated VIN ${stockItem.vin} to booking.`);
    };

    const addAnnouncement = async (subject: string, message: string) => {
        if (!user) return;
        const newAnnouncement: Announcement = {
            _id: `anno-${Date.now()}`,
            subject,
            message,
            timestamp: new Date().toISOString(),
            sentByUserId: user._id,
        };
        const savedAnnouncement = await api.saveAnnouncement(newAnnouncement);
        setAnnouncements(prev => [savedAnnouncement, ...prev]);

        const dealerUsers = users.filter(u => u.role === 'Dealer');
        const newRecipients: AnnouncementRecipient[] = [];
        for (const dealerUser of dealerUsers) {
            const recipient: AnnouncementRecipient = {
                _id: `rec-${Date.now()}-${dealerUser._id}`,
                announcementId: savedAnnouncement._id,
                userId: dealerUser._id,
                isRead: false,
            };
            const savedRecipient = await api.saveAnnouncementRecipient(recipient);
            newRecipients.push(savedRecipient);
        }
        setAnnouncementRecipients(prev => [...prev, ...newRecipients]);

        logAction(ActionType.Create, 'Announcements', savedAnnouncement._id, `Sent announcement: "${subject}"`);
    };

    const markAnnouncementAsRead = async (announcementId: string) => {
        if (!user) return;
        const recipient = announcementRecipients.find(r => r.announcementId === announcementId && r.userId === user._id);
        if (recipient && !recipient.isRead) {
            const updatedRecipient = { ...recipient, isRead: true };
            const savedRecipient = await api.saveAnnouncementRecipient(updatedRecipient);
            setAnnouncementRecipients(prev => prev.map(r => r._id === savedRecipient._id ? savedRecipient : r));
        }
    };

    const sendMessage = async (recipientId: string, content: string) => {
        if (!user) return;
        const now = new Date().toISOString();

        // Find or create conversation
        let conversation = conversations.find(c => 
            c.participantIds.includes(user._id) && c.participantIds.includes(recipientId)
        );

        if (!conversation) {
            const newConversation: Conversation = {
                _id: `convo-${Date.now()}`,
                participantIds: [user._id, recipientId],
                lastMessageTimestamp: now,
            };
            conversation = await api.saveConversation(newConversation);
            setConversations(prev => [conversation!, ...prev]);
        } else {
            const updatedConversation = { ...conversation, lastMessageTimestamp: now };
            conversation = await api.saveConversation(updatedConversation);
            setConversations(prev => prev.map(c => c._id === conversation!._id ? conversation! : c));
        }

        // Create message
        const newMessage: Message = {
            _id: `msg-${Date.now()}`,
            conversationId: conversation._id,
            senderId: user._id,
            content,
            timestamp: now,
            isRead: false,
        };
        const savedMessage = await api.saveMessage(newMessage);
        setMessages(prev => [...prev, savedMessage]);
        logAction(ActionType.Create, 'Messages', savedMessage._id, `Sent message to user ${recipientId}`);
    };

    const markConversationAsRead = async (conversationId: string) => {
        if (!user) return;
        const unreadMessages = messages.filter(m => 
            m.conversationId === conversationId && m.senderId !== user._id && !m.isRead
        );
        if (unreadMessages.length === 0) return;

        const updatedMessages = await Promise.all(
            unreadMessages.map(m => api.saveMessage({ ...m, isRead: true }))
        );

        setMessages(prev => prev.map(m => {
            const updated = updatedMessages.find(um => um._id === m._id);
            return updated || m;
        }));
    };

    const restoreDataState = (newState: any) => {
        if (newState.dealers) setDealers(newState.dealers);
        if (newState.products) setProducts(newState.products);
        if (newState.stock) setStock(newState.stock);
        if (newState.stockOrders) setStockOrders(newState.stockOrders);
        if (newState.bookings) setBookings(newState.bookings);
        if (newState.dealerPayments) setDealerPayments(newState.dealerPayments);
        logAction(ActionType.Update, 'System', undefined, 'System state restored from backup.');
    };

    const value: DataContextType = {
        isLoading, dealers, products, stock, stockOrders, bookings, dealerPayments, announcements, announcementRecipients,
        conversations, messages,
        addDealer, updateDealer, approveDealer, revokeDealer, updateDealerStatusBulk,
        recalculateReputation,
        registerDealer,
        addProduct, updateProduct, addOrUpdateProductsBulk,
        addStock,
        updateStockStatusBulk, processAllocationRequest, dispatchStockOrder, confirmOrderReceipt, createStockOrder,
        addBooking, updateBooking, cancelBooking, addPayment, addDealerPayment, allocateStockToBooking,
        addAnnouncement, markAnnouncementAsRead,
        sendMessage, markConversationAsRead,
        getRecommendationForItem,
        restoreDataState,
    };

    return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
}

import React, { createContext, useState, useEffect, ReactNode, useCallback } from 'react';
import {
  Dealer, Product, StockItem, StockStatus, StockOrder, OrderStatus, ApprovedOrderItem,
  Booking, Payment, StockOrderItem, Recommendation, DataContextType, ActionType, ProductVariant, BookingStatus, DealerPayment, Announcement, AnnouncementRecipient,
  Conversation, Message, Notification
} from '../types.ts';
import { useAppContext } from '../hooks/useAppContext.ts';
import { useAuth } from '../hooks/useAuth.ts';
import { api } from '../api/index.ts';

export const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const { logAction, settings, setNotifications, users, notifications } = useAppContext();
    const { user } = useAuth();
    const [isLoading, setIsLoading] = useState(true);
    const [dealers, setDealers] = useState<Dealer[]>([]);
    const [products, setProducts] = useState<Product[]>([]);
    const [stock, setStock] = useState<StockItem[]>([]);
    const [stockOrders, setStockOrders] = useState<StockOrder[]>([]);
    const [bookings, setBookings] = useState<Booking[]>([]);
    const [dealerPayments, setDealerPayments] = useState<DealerPayment[]>([]);
    const [announcements, setAnnouncements] = useState<Announcement[]>([]);
    const [announcementRecipients, setAnnouncementRecipients] = useState<AnnouncementRecipient[]>([]);
    const [conversations, setConversations] = useState<Conversation[]>([]);
    const [messages, setMessages] = useState<Message[]>([]);


    useEffect(() => {
        const loadInitialData = async () => {
            setIsLoading(true);
            try {
                const [
                    dealersData,
                    productsData,
                    stockData,
                    stockOrdersData,
                    bookingsData,
                    dealerPaymentsData,
                    announcementsData,
                    announcementRecipientsData,
                    conversationsData,
                    messagesData,
                ] = await Promise.all([
                    api.fetchDealers(),
                    api.fetchProducts(),
                    api.fetchStock(),
                    api.fetchStockOrders(),
                    api.fetchBookings(),
                    api.fetchDealerPayments(),
                    api.fetchAnnouncements(),
                    api.fetchAnnouncementRecipients(),
                    api.fetchConversations(),
                    api.fetchMessages(),
                ]);
                setDealers(dealersData as Dealer[]);
                setProducts(productsData as Product[]);
                setStock(stockData as StockItem[]);
                setStockOrders(stockOrdersData as StockOrder[]);
                setBookings(bookingsData as Booking[]);
                setDealerPayments(dealerPaymentsData as DealerPayment[]);
                setAnnouncements(announcementsData as Announcement[]);
                setAnnouncementRecipients(announcementRecipientsData as AnnouncementRecipient[]);
                setConversations(conversationsData as Conversation[]);
                setMessages(messagesData as Message[]);
            } catch (error) {
                console.error("Failed to load initial data", error);
            } finally {
                setIsLoading(false);
            }
        };

        loadInitialData();
    }, []);

    useEffect(() => {
        if (isLoading || !user || user.role === 'Dealer') {
            return; // Don't run until data is loaded or for dealers
        }

        const now = new Date();
        const twentyFourHoursAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

        const newNotifications: Notification[] = [];

        // 1. Pending Stock Orders
        const oldPendingOrders = stockOrders.filter(
            o => o.status === OrderStatus.Pending && new Date(o.requestTimestamp) < twentyFourHoursAgo
        ).length;

        if (oldPendingOrders > 0) {
            const message = `${oldPendingOrders} stock order(s) have been pending approval for over 24 hours.`;
            if (!notifications.some(n => n.message === message && !n.isRead)) {
                newNotifications.push({
                    _id: `reminder-orders-${Date.now()}`,
                    message,
                    timestamp: now.toISOString(),
                    isRead: false,
                    link: { page: 'Approvals' } 
                });
            }
        }

        // 2. Pending Dealer Registrations
        const oldPendingDealers = dealers.filter(
            d => !d.registrationApproved && new Date(d.createdAt) < twentyFourHoursAgo
        ).length;

        if (oldPendingDealers > 0) {
            const message = `${oldPendingDealers} dealer registration(s) are awaiting approval for over 24 hours.`;
            if (!notifications.some(n => n.message === message && !n.isRead)) {
                newNotifications.push({
                    _id: `reminder-dealers-${Date.now()}`,
                    message,
                    timestamp: now.toISOString(),
                    isRead: false,
                    link: { page: 'Dealers' } 
                });
            }
        }

        // 3. Pending Bookings
        const oldPendingBookings = bookings.filter(
            b => b.status === BookingStatus.Pending && new Date(b.bookingTimestamp) < twentyFourHoursAgo
        ).length;

        if (oldPendingBookings > 0) {
            const message = `${oldPendingBookings} booking(s) are pending stock allocation for over 24 hours.`;
            if (!notifications.some(n => n.message === message && !n.isRead)) {
                newNotifications.push({
                    _id: `reminder-bookings-${Date.now()}`,
                    message,
                    timestamp: now.toISOString(),
                    isRead: false,
                    link: { page: 'Bookings' }
                });
            }
        }

        // 4. Low Stock Warning
        if (settings.notifications.lowStockWarning) {
             const centralStock = stock.filter(s => s.dealerId === null && s.status === StockStatus.Available);
             const variantCounts: Record<string, number> = {};
             centralStock.forEach(s => { variantCounts[s.variantId] = (variantCounts[s.variantId] || 0) + 1; });

             products.forEach(p => {
                 p.variants.forEach(v => {
                     const count = variantCounts[v._id] || 0;
                     if (count < 5) { // Threshold for low stock
                         const message = `Low stock warning: ${p.modelName} (${v.name}) has only ${count} units left.`;
                         // Avoid spamming: Check if notified in the last 24h
                         const recentlyNotified = notifications.some(n => 
                             n.message === message && 
                             new Date(n.timestamp) > twentyFourHoursAgo
                         );

                         if (!recentlyNotified) {
                             newNotifications.push({
                                 _id: `warn-stock-${v._id}-${Date.now()}`,
                                 message,
                                 timestamp: now.toISOString(),
                                 isRead: false,
                                 link: { page: 'CompanyStock' }
                             });
                         }
                     }
                 });
             });
        }

        if (newNotifications.length > 0) {
            setNotifications(prev => [...newNotifications, ...prev]);
        }
    }, [isLoading, stockOrders, dealers, bookings, user, setNotifications, notifications, stock, products, settings.notifications.lowStockWarning]);


    const getRecommendationForItem = useCallback((item: StockOrderItem, dealerId: string): Recommendation => {
        const centralStockCount = stock.filter(s => s.variantId === item.variantId && s.dealerId === null).length;
        const dealer = dealers.find(d => d._id === dealerId);

        if (!dealer) return { type: 'Review', reason: 'Dealer not found.' };

        const dealerStockForVariant = stock.filter(s => s.dealerId === dealer._id && s.variantId === item.variantId).length;
        const dealerDeliveredBookings = bookings.filter(b => b.dealerId === dealer._id && b.status === 'Delivered');
        const recentSalesForVariant = dealerDeliveredBookings.filter(b => 
            b.variantId === item.variantId && new Date(b.bookingTimestamp).getTime() > Date.now() - 30 * 24 * 60 * 60 * 1000
        ).length;
        const isOverstocked = dealerStockForVariant > Math.max(5, recentSalesForVariant * 2);

        const reputationFactor = 0.7 + (dealer.reputationScore / 10) * 0.3;
        const allDeliveredBookings = bookings.filter(b => b.status === 'Delivered');
        const variantSalesCount = allDeliveredBookings.filter(b => b.variantId === item.variantId).length;
        const totalSales = allDeliveredBookings.length;
        const uniqueVariantsSoldCount = new Set(allDeliveredBookings.map(b => b.variantId)).size;
        const averageSalesPerVariant = totalSales / (uniqueVariantsSoldCount || 1);
        const demandFactor = Math.max(0.9, Math.min(1.25, 1 + ((variantSalesCount - averageSalesPerVariant) / (averageSalesPerVariant * 2 || 1))));

        const now = Date.now();
        const thirtyDaysAgo = now - 30 * 24 * 60 * 60 * 1000;
        const ninetyDaysAgo = now - 90 * 24 * 60 * 60 * 1000;
        const last30DaysSales = dealerDeliveredBookings.filter(b => new Date(b.bookingTimestamp).getTime() > thirtyDaysAgo).length;
        const prev60DaysSales = dealerDeliveredBookings.filter(b => {
            const ts = new Date(b.bookingTimestamp).getTime();
            return ts <= thirtyDaysAgo && ts > ninetyDaysAgo;
        }).length;
        const normalizedPrevSales = prev60DaysSales / 2;
        let velocityFactor = 1.0;
        if (last30DaysSales > normalizedPrevSales + 1) velocityFactor = 1.1;
        else if (last30DaysSales < normalizedPrevSales) velocityFactor = 0.95;

        const combinedFactor = reputationFactor * demandFactor * velocityFactor;
        const mlOptimalQty = Math.min(item.quantity, Math.round(item.quantity * combinedFactor));

        const getMlExplanation = (): { reason: string; factors: string[] } => {
            const factors: string[] = [];
            if (demandFactor > 1.1) factors.push("high demand");
            if (velocityFactor > 1.0) factors.push("positive sales trend");
            else if (velocityFactor < 1.0) factors.push("sales slowdown");
            if (dealer.reputationScore > 8.5) factors.push("strong reputation");
            if (factors.length === 0) return { reason: 'ML predicts standard sales potential.', factors: [] };
            return { reason: `Suggestion based on ${factors.join(' & ')}.`, factors };
        };

        const mlExplanation = getMlExplanation();

        if (isOverstocked) {
            return { type: 'Reject', reason: `Overstocked: Dealer already holds ${dealerStockForVariant} units.` };
        }

        if (centralStockCount === 0) return { type: 'Reject', reason: 'Critical Stock: No units available.' };
        if (dealer.reputationScore >= 9 && centralStockCount >= item.quantity) return { type: 'Approve', reason: `Elite Dealer (${dealer.reputationScore.toFixed(1)}) with sufficient stock.` };

        const isLowReputation = dealer.reputationScore < 5;
        const isStockLimited = centralStockCount < item.quantity;

        if (isLowReputation || isStockLimited) {
            let reason = isLowReputation ? `Low dealer reputation score (${dealer.reputationScore.toFixed(1)}).` : `Limited Stock: Only ${centralStockCount} units available.`;
            if (isLowReputation && isStockLimited) reason = `Low Reputation (${dealer.reputationScore.toFixed(1)}) and Limited Stock (${centralStockCount} available).`;
            return { type: 'Review', reason: `${reason} Manual review flagged.`, mlQuantity: mlOptimalQty, mlReasoningFactors: mlExplanation.factors };
        }

        return { type: 'Review', reason: mlExplanation.reason, mlQuantity: mlOptimalQty, mlReasoningFactors: mlExplanation.factors };
    }, [dealers, stock, bookings]);

    const addDealer = async (dealerData: Omit<Dealer, '_id' | 'createdAt' | 'registrationApproved'>) => {
        const newDealerStub: Dealer = { ...dealerData, _id: `dealer-${Date.now()}`, createdAt: new Date().toISOString(), registrationApproved: true };
        const savedDealer = await api.saveDealer(newDealerStub);
        setDealers(prev => [...prev, savedDealer]);
        logAction(ActionType.Create, 'Dealers', savedDealer._id, `Created new dealer ${savedDealer.name}`);
    };

    const registerDealer = async (dealerData: Omit<Dealer, '_id' | 'createdAt' | 'registrationApproved' | 'reputationScore'>) => {
        const newDealerStub: Dealer = { ...dealerData, _id: `dealer-${Date.now()}`, createdAt: new Date().toISOString(), registrationApproved: false, reputationScore: 5.0 };
        const newDealer = await api.saveDealer(newDealerStub);
        setDealers(prev => [...prev, newDealer]);
        logAction(ActionType.Create, 'Dealers', newDealer._id, `New dealer registration: ${newDealer.name}`);
        return newDealer;
    };

    const updateDealer = async (updatedDealer: Dealer) => {
        const savedDealer = await api.saveDealer(updatedDealer);
        setDealers(prev => prev.map(d => d._id === savedDealer._id ? savedDealer : d));
        logAction(ActionType.Update, 'Dealers', savedDealer._id, `Updated details for ${savedDealer.name}`);
    };

    const approveDealer = async (dealerId: string) => {
        const dealer = dealers.find(d => d._id === dealerId);
        if (!dealer) return;
        const updatedDealer = { ...dealer, registrationApproved: true };
        const savedDealer = await api.saveDealer(updatedDealer);
        setDealers(prev => prev.map(d => d._id === savedDealer._id ? savedDealer : d));
        logAction(ActionType.Approve, 'Dealers', dealerId, `Approved registration for ${savedDealer?.name}`);
    };

    const revokeDealer = async (dealerId: string) => {
        const dealer = dealers.find(d => d._id === dealerId);
        if (!dealer) return;
        const updatedDealer = { ...dealer, registrationApproved: false };
        const savedDealer = await api.saveDealer(updatedDealer);
        setDealers(prev => prev.map(d => d._id === savedDealer._id ? savedDealer : d));
        logAction(ActionType.Update, 'Dealers', dealerId, `Revoked approval for ${savedDealer.name}.`);
    };

    const updateDealerStatusBulk = async (dealerIds: string[], approved: boolean) => {
        const dealersToUpdate = dealers.filter(d => dealerIds.includes(d._id));
        if (dealersToUpdate.length === 0) return;

        const updatedDealerObjects = dealersToUpdate.map(d => ({ ...d, registrationApproved: approved }));

        await Promise.all(updatedDealerObjects.map(api.saveDealer));

        setDealers(prevDealers => 
            prevDealers.map(d => {
                const updatedVersion = updatedDealerObjects.find(ud => ud._id === d._id);
                return updatedVersion || d;
            })
        );
        logAction(ActionType.Update, 'Dealers', undefined, `Bulk ${approved ? 'approved' : 'revoked'} ${dealerIds.length} dealers.`);
    };

    const recalculateReputation = async (dealerId: string) => {
        const dealer = dealers.find(d => d._id === dealerId);
        if (!dealer) return;
        const newScore = parseFloat((Math.random() * 5 + 5).toFixed(1)); // Score between 5.0 and 10.0
        const updatedDealer = { ...dealer, reputationScore: newScore };
        const savedDealer = await api.saveDealer(updatedDealer);
        setDealers(prev => prev.map(d => d._id === dealerId ? savedDealer : d));
        logAction(ActionType.Update, 'Dealers', dealerId, `Recalculated reputation score for ${dealer.name} to ${newScore}.`);
    };

    const addProduct = async (productData: Omit<Product, '_id' | 'priceHistory'>) => {
        const newProductStub: Product = { ...productData, _id: `prod-${Date.now()}`, priceHistory: [] };
        const newProduct = await api.saveProduct(newProductStub);
        setProducts(prev => [...prev, newProduct]);
        logAction(ActionType.Create, 'Products', newProduct._id, `Created product ${newProduct.modelName}`);
    };

    const updateProduct = async (updatedProduct: Product) => {
        const oldProduct = products.find(p => p._id === updatedProduct._id);
        const savedProduct = await api.saveProduct(updatedProduct);

        let changeDetails: string[] = [];

        if (oldProduct) {
            if (oldProduct.brand !== savedProduct.brand) changeDetails.push(`Brand: ${oldProduct.brand} -> ${savedProduct.brand}`);
            if (oldProduct.modelName !== savedProduct.modelName) changeDetails.push(`Model: ${oldProduct.modelName} -> ${savedProduct.modelName}`);

            // Compare Variants
            const oldVariantsMap = new Map<string, ProductVariant>(oldProduct.variants.map(v => [v._id, v]));
            const newVariantsMap = new Map<string, ProductVariant>(savedProduct.variants.map(v => [v._id, v]));

            // Check updates and additions
            savedProduct.variants.forEach(newVar => {
                const oldVar = oldVariantsMap.get(newVar._id);
                if (oldVar) {
                    if (oldVar.price !== newVar.price) {
                        changeDetails.push(`Price (${newVar.name} - ${newVar.color}): ${oldVar.price} -> ${newVar.price}`);
                    }
                    if (oldVar.sku !== newVar.sku) {
                        changeDetails.push(`SKU (${newVar.name} - ${newVar.color}): ${oldVar.sku} -> ${newVar.sku}`);
                    }
                } else {
                    changeDetails.push(`Added variant: ${newVar.name} (${newVar.color})`);
                }
            });

            // Check deletions
            oldProduct.variants.forEach(oldVar => {
                if (!newVariantsMap.has(oldVar._id)) {
                    changeDetails.push(`Removed variant: ${oldVar.name} (${oldVar.color})`);
                }
            });
        }

        const logMessage = changeDetails.length > 0 
            ? `Updated product ${savedProduct.modelName}: ${changeDetails.join(', ')}`
            : `Updated product ${savedProduct.modelName} (No detected changes)`;

        setProducts(prev => prev.map(p => p._id === savedProduct._id ? savedProduct : p));
        logAction(ActionType.Update, 'Products', savedProduct._id, logMessage);
    };

    const addOrUpdateProductsBulk = async (productsToImport: Omit<Product, '_id' | 'priceHistory'>[]): Promise<{ created: number; updated: number; }> => {
        let createdCount = 0;
        let updatedCount = 0;

        const newProductList: Product[] = JSON.parse(JSON.stringify(products));

        for (const productFromCsv of productsToImport) {
            const productIndex = newProductList.findIndex((p: Product) =>
                p.brand.toLowerCase() === productFromCsv.brand.toLowerCase() &&
                p.modelName.toLowerCase() === productFromCsv.modelName.toLowerCase()
            );

            if (productIndex !== -1) {
                const existingProduct = newProductList[productIndex];
                let hasChanges = false;

                const existingVariantsBySku = new Map(existingProduct.variants.map((v: ProductVariant) => [v.sku.toLowerCase(), v]));

                for (const variantFromCsv of productFromCsv.variants) {
                    const existingVariant = existingVariantsBySku.get(variantFromCsv.sku.toLowerCase());

                    if (existingVariant) {
                        if (existingVariant.name !== variantFromCsv.name || existingVariant.price !== variantFromCsv.price) {
                            existingVariant.name = variantFromCsv.name;
                            existingVariant.price = variantFromCsv.price;
                            hasChanges = true;
                        }
                    } else {
                        existingProduct.variants.push({
                            ...variantFromCsv,
                            _id: `v-new-${Date.now()}-${Math.random()}`
                        });
                        hasChanges = true;
                    }
                }

                if (hasChanges) {
                    await api.saveProduct(existingProduct); 
                    updatedCount++;
                }
            } else {
                const newProduct: Product = {
                    ...productFromCsv,
                    _id: `prod-new-${Date.now()}-${Math.random()}`,
                    priceHistory: [],
                    variants: productFromCsv.variants.map(v => ({
                        ...v,
                        _id: `v-new-${Date.now()}-${Math.random()}`
                    }))
                };
                newProductList.push(newProduct);
                await api.saveProduct(newProduct); 
                createdCount++;
            }
        }

        if (createdCount > 0 || updatedCount > 0) {
            setProducts(newProductList);
            logAction(ActionType.Update, 'Products', undefined, `Bulk import: ${createdCount} created, ${updatedCount} updated.`);
        }

        return { created: createdCount, updated: updatedCount };
    };

    const addStock = async (stockData: Omit<StockItem, '_id' | 'assignedAt'>) => {
        const newStockItem: StockItem = {
            ...stockData,
            _id: `stock-${Date.now()}`,
            assignedAt: new Date().toISOString(),
        };
        const savedItem = await api.saveStockItem(newStockItem);
        setStock(prev => [savedItem, ...prev]);
        logAction(ActionType.Create, 'Stock', savedItem._id, `Added new stock item with VIN ${savedItem.vin}`);
    };

    const updateStockStatusBulk = async (stockIds: string[], status: StockStatus) => {
        const updatedItems = await api.saveBulkStockStatus(stockIds, status);
        setStock(prev => prev.map(s => {
            const updated = updatedItems.find(i => i._id === s._id);
            return updated ? updated : s;
        }));
        logAction(ActionType.Update, 'Stock', undefined, `Bulk updated ${stockIds.length} items to ${status}`);
    };

    const processAllocationRequest = async (orderId: string, approvedItems: ApprovedOrderItem[], status: OrderStatus) => {
        const order = stockOrders.find(o => o._id === orderId);
        if (!order) return;

        const stockToUpdate: StockItem[] = [];
        const allocatedStockIds: string[] = [];
        let anyStockAssigned = false;

        for (const item of approvedItems) {
            if (item.approvedQuantity > 0) {
                const availableStock = stock.filter(s => s.variantId === item.variantId && s.dealerId === null && s.status === StockStatus.Available);
                const itemsToAssign = availableStock.slice(0, item.approvedQuantity);

                if (itemsToAssign.length > 0) anyStockAssigned = true;

                for (const stockItem of itemsToAssign) {
                    stockToUpdate.push({ ...stockItem, dealerId: order.dealerId, assignedAt: new Date().toISOString() });
                    allocatedStockIds.push(stockItem._id);
                }
            }
        }

        const updatedOrder: StockOrder = { ...order, status, approvedItems, allocatedStockIds };

        const { order: savedOrder, stock: savedStock } = await api.saveApprovedOrder(updatedOrder, stockToUpdate);

        setStockOrders(prev => prev.map(o => o._id === savedOrder._id ? savedOrder : o));

        setStock(prev => prev.map(s => {
            const updated = savedStock.find(i => i._id === s._id);
            return updated || s;
        }));

        logAction(ActionType.Approve, 'StockOrders', orderId, `Order processed with status: ${status}.`);

        // Notification Logic
        if (status === OrderStatus.Rejected && settings.notifications.orderRejected) {
             setNotifications(prev => [{
                _id: `notif-rej-${Date.now()}`,
                message: `Stock order #${orderId.slice(-4)} was rejected.`,
                timestamp: new Date().toISOString(),
                isRead: false,
                link: { page: 'Stock Orders' }
            }, ...prev]);
        }

        if (anyStockAssigned && settings.notifications.orderApproved) {
            setNotifications(prev => [{
                _id: `notif-${Date.now()}`,
                message: `Stock has been allocated for order #${orderId.slice(-4)}.`,
                timestamp: new Date().toISOString(),
                isRead: false,
                link: { page: 'Stock Orders' }
            }, ...prev]);
        }
    };

    const dispatchStockOrder = async (orderId: string) => {
        const order = stockOrders.find(o => o._id === orderId);
        if (!order) throw new Error("Order not found");

        const updatedOrder = { ...order, status: OrderStatus.Dispatched };
        const savedOrder = await api.saveStockOrder(updatedOrder);

        setStockOrders(prev => prev.map(o => o._id === savedOrder._id ? savedOrder : o));
        logAction(ActionType.Dispatch, 'StockOrders', orderId, `Order #${orderId.slice(-4)} marked as dispatched.`);
    };

    const confirmOrderReceipt = async (orderId: string) => {
        const { order: updatedOrder, stock: updatedStock } = await api.confirmOrderReceipt(orderId);

        setStockOrders(prev => prev.map(o => o._id === updatedOrder._id ? updatedOrder : o));

        setStock(prev => prev.map(s => {
            const updated = updatedStock.find(us => us._id === s._id);
            return updated || s;
        }));

        logAction(ActionType.Update, 'StockOrders', orderId, `Dealer confirmed receipt of order #${orderId.slice(-4)}.`);
    };

    const createStockOrder = async (orderData: Omit<StockOrder, '_id' | 'requestTimestamp' | 'status' | 'approvedItems'>) => {
        const newOrder: StockOrder = {
            ...orderData,
            _id: `alloc-${Date.now()}`,
            requestTimestamp: new Date().toISOString(),
            status: OrderStatus.Pending,
        };
        const savedOrder = await api.saveStockOrder(newOrder);
        setStockOrders(prev => [savedOrder, ...prev]);
        logAction(ActionType.Create, 'StockOrders', savedOrder._id, `New stock order created by dealer ${savedOrder.dealerId}`);
        if (settings.notifications.newOrder) {
            setNotifications(prev => [{
                _id: `notif-${Date.now()}`,
                message: `New stock order #${savedOrder._id.slice(-4)} is pending review.`,
                timestamp: new Date().toISOString(),
                isRead: false,
                link: { page: 'Approvals' }
            }, ...prev]);
        }
    };

    const addBooking = async (bookingData: Omit<Booking, '_id' | 'bookingTimestamp' | 'payments' | 'stockItemId'>) => {
        const newBooking: Booking = {
            ...bookingData,
            _id: `booking-${Date.now()}`,
            bookingTimestamp: new Date().toISOString(),
            payments: [],
        };
        const savedBooking = await api.saveBooking(newBooking);
        setBookings(prev => [savedBooking, ...prev]);
        logAction(ActionType.Create, 'Bookings', savedBooking._id, `New booking for ${savedBooking.customerName}`);
    };

    const updateBooking = async (updatedBooking: Booking) => {
        const savedBooking = await api.saveBooking(updatedBooking);
        setBookings(prev => prev.map(b => b._id === savedBooking._id ? savedBooking : b));
        logAction(ActionType.Update, 'Bookings', savedBooking._id, `Updated booking for ${savedBooking.customerName}`);
    };

    const cancelBooking = async (bookingId: string) => {
        const bookingToCancel = bookings.find(b => b._id === bookingId);
        if (!bookingToCancel) throw new Error("Booking not found");

        const updatedBooking: Booking = { ...bookingToCancel, status: BookingStatus.Cancelled };

        let savedStockItem: StockItem | null = null;
        if (bookingToCancel.stockItemId) {
            const stockItemToRelease = stock.find(s => s._id === bookingToCancel.stockItemId);
            if (stockItemToRelease && stockItemToRelease.status === StockStatus.Reserved) {
                const updatedStockItem: StockItem = { ...stockItemToRelease, status: StockStatus.Available, dealerId: null };
                savedStockItem = await api.saveStockItem(updatedStockItem);
            }
        }

        const savedBooking = await api.saveBooking(updatedBooking);

        setBookings(prev => prev.map(b => b._id === savedBooking._id ? savedBooking : b));
        if (savedStockItem) {
            setStock(prev => prev.map(s => s._id === savedStockItem!._id ? savedStockItem! : s));
        }

        logAction(ActionType.Update, 'Bookings', bookingId, `Cancelled booking for ${savedBooking.customerName}`);
    };

    const addPayment = async (bookingId: string, payment: Payment) => {
        const booking = bookings.find(b => b._id === bookingId);
        if (!booking) return;
        const updatedBooking = { ...booking, payments: [...booking.payments, payment] };
        const savedBooking = await api.saveBooking(updatedBooking);
        setBookings(prev => prev.map(b => b._id === savedBooking._id ? savedBooking : b));
        logAction(ActionType.Update, 'Bookings', bookingId, `Added payment of Rs. ${payment.amount} for ${booking.customerName}`);
    };

    const addDealerPayment = async (paymentData: Omit<DealerPayment, '_id' | 'timestamp'>) => {
        const newPayment: DealerPayment = {
            ...paymentData,
            _id: `dp-${Date.now()}`,
            timestamp: new Date().toISOString(),
        };
        const savedPayment = await api.saveDealerPayment(newPayment);
        setDealerPayments(prev => [savedPayment, ...prev]);
        const dealerName = dealers.find(d => d._id === savedPayment.dealerId)?.name || 'a dealer';
        logAction(ActionType.Create, 'DealerPayments', savedPayment._id, `Recorded payment of Rs. ${savedPayment.amount} from ${dealerName}`);
    };

    const allocateStockToBooking = async (bookingId: string, stockItemId: string) => {
        const booking = bookings.find(b => b._id === bookingId);
        const stockItem = stock.find(s => s._id === stockItemId);

        if (!booking || !stockItem) {
            throw new Error('Booking or Stock Item not found');
        }

        const updatedBooking: Booking = {
            ...booking,
            status: BookingStatus.Allocated,
            stockItemId: stockItemId,
        };
        const updatedStockItem: StockItem = {
            ...stockItem,
            status: StockStatus.Reserved,
            dealerId: booking.dealerId, // Ensure stock is assigned to dealer
        };

        const [savedBooking, savedStockItem] = await Promise.all([
            api.saveBooking(updatedBooking),
            api.saveStockItem(updatedStockItem),
        ]);

        setBookings(prev => prev.map(b => b._id === savedBooking._id ? savedBooking : b));
        setStock(prev => prev.map(s => s._id === savedStockItem._id ? savedStockItem : s));

        logAction(ActionType.Update, 'Bookings', bookingId, `Allocated VIN ${stockItem.vin} to booking.`);
    };

    const addAnnouncement = async (subject: string, message: string) => {
        if (!user) return;
        const newAnnouncement: Announcement = {
            _id: `anno-${Date.now()}`,
            subject,
            message,
            timestamp: new Date().toISOString(),
            sentByUserId: user._id,
        };
        const savedAnnouncement = await api.saveAnnouncement(newAnnouncement);
        setAnnouncements(prev => [savedAnnouncement, ...prev]);

        const dealerUsers = users.filter(u => u.role === 'Dealer');
        const newRecipients: AnnouncementRecipient[] = [];
        for (const dealerUser of dealerUsers) {
            const recipient: AnnouncementRecipient = {
                _id: `rec-${Date.now()}-${dealerUser._id}`,
                announcementId: savedAnnouncement._id,
                userId: dealerUser._id,
                isRead: false,
            };
            const savedRecipient = await api.saveAnnouncementRecipient(recipient);
            newRecipients.push(savedRecipient);
        }
        setAnnouncementRecipients(prev => [...prev, ...newRecipients]);

        logAction(ActionType.Create, 'Announcements', savedAnnouncement._id, `Sent announcement: "${subject}"`);
    };

    const markAnnouncementAsRead = async (announcementId: string) => {
        if (!user) return;
        const recipient = announcementRecipients.find(r => r.announcementId === announcementId && r.userId === user._id);
        if (recipient && !recipient.isRead) {
            const updatedRecipient = { ...recipient, isRead: true };
            const savedRecipient = await api.saveAnnouncementRecipient(updatedRecipient);
            setAnnouncementRecipients(prev => prev.map(r => r._id === savedRecipient._id ? savedRecipient : r));
        }
    };

    const sendMessage = async (recipientId: string, content: string) => {
        if (!user) return;
        const now = new Date().toISOString();

        // Find or create conversation
        let conversation = conversations.find(c => 
            c.participantIds.includes(user._id) && c.participantIds.includes(recipientId)
        );

        if (!conversation) {
            const newConversation: Conversation = {
                _id: `convo-${Date.now()}`,
                participantIds: [user._id, recipientId],
                lastMessageTimestamp: now,
            };
            conversation = await api.saveConversation(newConversation);
            setConversations(prev => [conversation!, ...prev]);
        } else {
            const updatedConversation = { ...conversation, lastMessageTimestamp: now };
            conversation = await api.saveConversation(updatedConversation);
            setConversations(prev => prev.map(c => c._id === conversation!._id ? conversation! : c));
        }

        // Create message
        const newMessage: Message = {
            _id: `msg-${Date.now()}`,
            conversationId: conversation._id,
            senderId: user._id,
            content,
            timestamp: now,
            isRead: false,
        };
        const savedMessage = await api.saveMessage(newMessage);
        setMessages(prev => [...prev, savedMessage]);
        logAction(ActionType.Create, 'Messages', savedMessage._id, `Sent message to user ${recipientId}`);
    };

    const markConversationAsRead = async (conversationId: string) => {
        if (!user) return;
        const unreadMessages = messages.filter(m => 
            m.conversationId === conversationId && m.senderId !== user._id && !m.isRead
        );
        if (unreadMessages.length === 0) return;

        const updatedMessages = await Promise.all(
            unreadMessages.map(m => api.saveMessage({ ...m, isRead: true }))
        );

        setMessages(prev => prev.map(m => {
            const updated = updatedMessages.find(um => um._id === m._id);
            return updated || m;
        }));
    };

    const restoreDataState = (newState: any) => {
        if (newState.dealers) setDealers(newState.dealers);
        if (newState.products) setProducts(newState.products);
        if (newState.stock) setStock(newState.stock);
        if (newState.stockOrders) setStockOrders(newState.stockOrders);
        if (newState.bookings) setBookings(newState.bookings);
        if (newState.dealerPayments) setDealerPayments(newState.dealerPayments);
        logAction(ActionType.Update, 'System', undefined, 'System state restored from backup.');
    };

    const value: DataContextType = {
        isLoading, dealers, products, stock, stockOrders, bookings, dealerPayments, announcements, announcementRecipients,
        conversations, messages,
        addDealer, updateDealer, approveDealer, revokeDealer, updateDealerStatusBulk,
        recalculateReputation,
        registerDealer,
        addProduct, updateProduct, addOrUpdateProductsBulk,
        addStock,
        updateStockStatusBulk, processAllocationRequest, dispatchStockOrder, confirmOrderReceipt, createStockOrder,
        addBooking, updateBooking, cancelBooking, addPayment, addDealerPayment, allocateStockToBooking,
        addAnnouncement, markAnnouncementAsRead,
        sendMessage, markConversationAsRead,
        getRecommendationForItem,
        restoreDataState,
    };

    return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
}

import React, { useState, useMemo, useEffect } from 'react';
import { PaymentType, OrderStatus } from '../../types.ts';
import { useData } from '../../hooks/useData.ts';
import Spinner from '../shared/Spinner.tsx';
import { UploadCloudIcon, XCircleIcon } from '../icons/Icons.tsx';

interface DealerPaymentModalProps {
    isOpen: boolean;
    onClose: () => void;
    dealerId?: string; // Make dealerId optional
    showToast: (message: string, type: 'success' | 'error' | 'info') => void;
}

const DealerPaymentModal: React.FC<DealerPaymentModalProps> = ({ isOpen, onClose, dealerId, showToast }) => {
    const { addDealerPayment, stockOrders, dealers } = useData();
    const [selectedDealerId, setSelectedDealerId] = useState(dealerId || '');
    const [amount, setAmount] = useState('');
    const [type, setType] = useState<PaymentType>(PaymentType.BankTransfer);
    const [reference, setReference] = useState('');
    const [stockOrderId, setStockOrderId] = useState<string | undefined>(undefined);
    const [isSaving, setIsSaving] = useState(false);
    const [proofFile, setProofFile] = useState<File | null>(null);
    const [isDragging, setIsDragging] = useState(false);

    useEffect(() => {
        if (isOpen) {
            setSelectedDealerId(dealerId || (dealers.length > 0 ? dealers[0]._id : ''));
            setAmount('');
            setType(PaymentType.BankTransfer);
            setReference('');
            setStockOrderId(undefined);
            setProofFile(null);
            setIsDragging(false);
        }
    }, [isOpen, dealerId, dealers]);


    const relevantOrders = useMemo(() => {
        if (!selectedDealerId) return [];
        return stockOrders.filter(order =>
            order.dealerId === selectedDealerId &&
            (order.status === OrderStatus.Approved || order.status === OrderStatus.PartiallyApproved || order.status === OrderStatus.Dispatched)
        );
    }, [stockOrders, selectedDealerId]);

    const convertToBase64 = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.readAsDataURL(file);
            reader.onload = () => resolve(reader.result as string);
            reader.onerror = error => reject(error);
        });
    };

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!amount || Number(amount) <= 0) {
            showToast("Please enter a valid payment amount.", "error");
            return;
        }
        if (!selectedDealerId) {
            showToast("Please select a dealer.", "error");
            return;
        }
        setIsSaving(true);
        try {
            let proofImage = undefined;
            if (proofFile) {
                proofImage = await convertToBase64(proofFile);
            }

            await addDealerPayment({
                dealerId: selectedDealerId,
                amount: Number(amount),
                type,
                reference,
                stockOrderId: stockOrderId || undefined,
                proofImage,
            });
            showToast("Payment recorded successfully!", "success");
            onClose();
        } catch (error) {
            showToast("Failed to record payment.", "error");
        } finally {
            setIsSaving(false);
        }
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setProofFile(e.target.files[0]);
        }
    };

    const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        setIsDragging(true);
    };

    const handleDragLeave = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        setIsDragging(false);
    };

    const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        setIsDragging(false);
        if (e.dataTransfer.files && e.dataTransfer.files[0]) {
            const file = e.dataTransfer.files[0];
            if (file.type.startsWith('image/')) {
                setProofFile(file);
            } else {
                showToast("Please upload an image file.", "error");
            }
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center p-4" onClick={onClose}>
            <div className="bg-white rounded-lg shadow-xl w-full max-w-lg" onClick={e => e.stopPropagation()}>
                <form onSubmit={handleSubmit}>
                    <div className="p-6 border-b">
                        <h3 className="text-xl font-semibold text-gray-800">Record Dealer Payment</h3>
                    </div>
                    <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                         {!dealerId && (
                             <div>
                                <label htmlFor="dealerSelect" className="block text-sm font-medium text-gray-700">Dealer</label>
                                 <select
                                    id="dealerSelect"
                                    value={selectedDealerId}
                                    onChange={(e) => setSelectedDealerId(e.target.value)}
                                    required
                                    className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                                >
                                    <option value="" disabled>Select a dealer...</option>
                                    {dealers.map(d => <option key={d._id} value={d._id}>{d.name}</option>)}
                                </select>
                            </div>
                         )}
                        <div>
                            <label htmlFor="amount" className="block text-sm font-medium text-gray-700">Amount (PKR)</label>
                            <input
                                type="number"
                                id="amount"
                                value={amount}
                                onChange={(e) => setAmount(e.target.value)}
                                required
                                min="1"
                                className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                                autoFocus
                            />
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label htmlFor="type" className="block text-sm font-medium text-gray-700">Payment Type</label>
                                <select
                                    id="type"
                                    value={type}
                                    onChange={(e) => setType(e.target.value as PaymentType)}
                                    required
                                    className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                                >
                                    {Object.values(PaymentType).map(t => <option key={t} value={t}>{String(t).replace('_', ' ')}</option>)}
                                </select>
                            </div>
                            <div>
                                <label htmlFor="stockOrderId" className="block text-sm font-medium text-gray-700">Link to Order (Optional)</label>
                                <select
                                    id="stockOrderId"
                                    value={stockOrderId || ''}
                                    onChange={(e) => setStockOrderId(e.target.value || undefined)}
                                    className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                                    disabled={!selectedDealerId}
                                >
                                    <option value="">None</option>
                                    {relevantOrders.map(order => (
                                        <option key={order._id} value={order._id}>
                                            Order #{order._id.slice(-6)} - {new Date(order.requestTimestamp).toLocaleDateString()}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <div>
                            <label htmlFor="reference" className="block text-sm font-medium text-gray-700">Reference / Notes</label>
                            <input
                                type="text"
                                id="reference"
                                value={reference}
                                onChange={(e) => setReference(e.target.value)}
                                placeholder="e.g., Invoice #, Cheque #"
                                className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Proof of Payment (Image)</label>
                            <div 
                                className={`mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-dashed rounded-md relative transition-colors ${isDragging ? 'border-primary bg-primary/5' : 'border-gray-300 hover:border-primary'}`}
                                onDragOver={handleDragOver}
                                onDragLeave={handleDragLeave}
                                onDrop={handleDrop}
                            >
                                {proofFile ? (
                                    <div className="text-center">
                                        <p className="text-sm text-gray-900 font-medium truncate max-w-xs">{proofFile.name}</p>
                                        <button 
                                            type="button" 
                                            onClick={() => setProofFile(null)} 
                                            className="mt-2 inline-flex items-center text-xs text-red-600 hover:text-red-800"
                                        >
                                            <XCircleIcon className="w-4 h-4 mr-1" /> Remove
                                        </button>
                                    </div>
                                ) : (
                                    <div className="space-y-1 text-center">
                                        <UploadCloudIcon className={`mx-auto h-12 w-12 ${isDragging ? 'text-primary' : 'text-gray-400'}`} />
                                        <div className="flex text-sm text-gray-600 justify-center">
                                            <label htmlFor="file-upload" className="relative cursor-pointer bg-white rounded-md font-medium text-primary hover:text-secondary focus-within:outline-none focus-within:ring-2 focus-within:ring-offset-2 focus-within:ring-primary">
                                                <span>Upload a file</span>
                                                <input id="file-upload" name="file-upload" type="file" className="sr-only" accept="image/*" onChange={handleFileChange} />
                                            </label>
                                            <p className="pl-1">or drag and drop</p>
                                        </div>
                                        <p className="text-xs text-gray-500">PNG, JPG, GIF up to 5MB</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                    <div className="px-6 py-4 bg-gray-50 text-right space-x-2">
                        <button type="button" onClick={onClose} className="py-2 px-4 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50">Cancel</button>
                        <button type="submit" disabled={isSaving} className="w-36 flex justify-center py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-primary hover:bg-secondary disabled:bg-slate-400">
                            {isSaving ? <Spinner /> : 'Save Payment'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

